// ── QUESTION BANK ──
// Structure: QBANK[chapterId] = { m:[medium×15], h:[hard×15] }
// Each question: { q, o:[A,B,C,D], a (0-based index), e (explanation), ref }

const QBANK = [

// ─────────────────────────────────────────
// CHAPTER 00 — Introduction
// ─────────────────────────────────────────
{
m:[
{q:"Which certification specification governs the EC135 P3H/T3H?",o:["CS-25 Large Aeroplanes","CS-27 Small Rotorcraft","CS-29 Large Rotorcraft","FAR Part 27"],a:1,e:"The EC135 is certified to EASA CS-27 (Certification Specification for Small Rotorcraft), which applies to rotorcraft with MTOM ≤3,175 kg.",ref:"Ch.00 §1"},
{q:"Who published the EC135 P3H/T3H Training Manual?",o:["Turbomeca France","Pratt & Whitney Canada","Airbus Helicopters Deutschland GmbH","Airbus SAS Toulouse"],a:2,e:"The manual is published by Airbus Helicopters Deutschland GmbH, Training Academy, Donauwörth, Germany.",ref:"Ch.00 §1"},
{q:"What does the abbreviation AMC stand for?",o:["Automatic Mode Controller","Aircraft Management Computer","Avionics Management Centre","Autopilot Master Controller"],a:1,e:"AMC = Aircraft Management Computer. The two AMCs host all Helionix® IMA software applications.",ref:"Ch.00 §3"},
{q:"What does AFCS stand for?",o:["Automated Flight and Control Software","Automatic Flight Control System","Airborne Flight Correction System","Advanced Flight Computer System"],a:1,e:"AFCS = Automatic Flight Control System — the full autopilot system of the EC135.",ref:"Ch.00 §3"},
{q:"What does ARIS stand for?",o:["Airframe Rigidity Isolation System","Anti Resonance Isolation System","Automatic Rotor Isolation System","Auxiliary Rotor Integration System"],a:1,e:"ARIS = Anti Resonance Isolation System. It isolates MGB vibrations from the fuselage using tuned struts.",ref:"Ch.00 §3"},
{q:"What does BMR stand for?",o:["Blade Mass Regulation","Balanced Modular Rotor","Bearingless Main Rotor","Blade Moment Rotor"],a:2,e:"BMR = Bearingless Main Rotor. The EC135 uses a 4-blade BMR with flexbeam hub, requiring no conventional blade bearings.",ref:"Ch.00 §3"},
{q:"What does MGB stand for?",o:["Main Generator Bus","Main Gear Box","Master Ground Bus","Main Gearbox Bearing"],a:1,e:"MGB = Main Gear Box (also written Main Gearbox). It is the main transmission that transfers engine power to the rotors.",ref:"Ch.00 §3"},
{q:"What does MTOM stand for?",o:["Maximum Trim Operating Mass","Maximum Take-Off Mass","Mean Technical Operating Margin","Minimum Take-Off Momentum"],a:1,e:"MTOM = Maximum Take-Off Mass. For the EC135 P3H/T3H this is 2,980 kg.",ref:"Ch.00 §3"},
{q:"What does OEI stand for?",o:["Optimal Engine Index","One Engine Inoperative","Onboard Engine Indicator","Over-Engine Intervention"],a:1,e:"OEI = One Engine Inoperative. OEI ratings define the emergency power limits when one engine fails.",ref:"Ch.00 §3"},
{q:"What does FLI stand for?",o:["Flight Level Indicator","Fuel Load Instrument","First Limitation Indicator","Flight Limit Index"],a:2,e:"FLI = First Limitation Indicator. It shows whichever engine parameter is first to approach its operational limit.",ref:"Ch.00 §3"},
{q:"What does IMA stand for?",o:["Integrated Mission Avionics","Integrated Modular Avionics","Instrument Management Architecture","Internal Module Array"],a:1,e:"IMA = Integrated Modular Avionics. The Helionix® system is an IMA platform hosting multiple applications on shared hardware.",ref:"Ch.00 §3"},
{q:"What is the revision number and date of the EC135 training manual?",o:["R02 — March 2015","R03 — June 2017","R04 — January 2019","R05 — December 2020"],a:2,e:"The training manual is Revision 04, dated January 2019. It is not subject to a revision service after issue.",ref:"Ch.00 §1"},
{q:"What does TGB stand for?",o:["Turbine Gear Box","Transfer Gear Box","Tail (Rotor) Gear Box","Tail Generator Bus"],a:2,e:"TGB = Tail (Rotor) Gear Box. The right-angle bevel gearbox at the base of the vertical fin that drives the Fenestron®.",ref:"Ch.00 §3"},
{q:"What does FND stand for in Helionix®?",o:["Flight Navigational Data","Flight and Navigation Display","Forward Navigation Display","Full Navigation Display"],a:1,e:"FND = Flight and Navigation Display — the primary flight display format shown on an MFD, equivalent to a PFD.",ref:"Ch.00 §3"},
{q:"What does SAS stand for?",o:["Speed Augmentation System","Stability Augmentation System","Sensor Actuation System","Single-Axis Stabilizer"],a:1,e:"SAS = Stability Augmentation System — the basic autopilot layer providing rate-damping and improved flying qualities.",ref:"Ch.00 §3"}
],
h:[
{q:"What is the difference between EECU and EEC in the EC135 context?",o:["Both refer to the same unit by different names","EECU is Turbomeca's engine control unit; EEC is Pratt & Whitney's","EECU is for the autopilot; EEC is for the engine","EECU is a backup unit; EEC is the primary unit"],a:1,e:"EECU (Electronic Engine Control Unit) is the Turbomeca designation for FADEC. EEC (Electronic Engine Control) is Pratt & Whitney's equivalent. Both are single-channel FADEC systems.",ref:"Ch.00 §3"},
{q:"What does DTD stand for and what is its function?",o:["Data Transfer Device — loads software and navigation databases into the IMA","Digital Terrain Display — shows terrain map on MFD","Dual Transducer Drive — controls trim actuators","Data Transfer Diagnostics — records fault codes"],a:0,e:"DTD = Data Transfer Device. It is a portable storage device used to load software updates, navigation databases, and configuration data into the Helionix® IMA system.",ref:"Ch.00 §3"},
{q:"What does AHRS stand for and what does it provide to the AFCS?",o:["Air/Height Reference System — provides altitude data only","Attitude and Heading Reference System — provides pitch, roll, and heading","Automated Hover Reference Sensor — provides hover position","Airspeed and Height Reference System — provides speed and altitude"],a:1,e:"AHRS = Attitude and Heading Reference System. It provides the AFCS with pitch, roll, and yaw/heading data — the core reference for autopilot and display systems.",ref:"Ch.00 §3"},
{q:"What does VMS stand for in the Helionix® context?",o:["Vehicle Management System — displays engine and systems data","Variable Mode Selector — switches MFD formats","Vertical Motion Sensor — measures climb rate","Vehicle Monitoring Software — records flight parameters"],a:0,e:"VMS = Vehicle Management System — an MFD display format that shows engine parameters, fuel, hydraulics, and other system data. Equivalent to a systems/EICAS page.",ref:"Ch.00 §3"},
{q:"What does DAFCS stand for?",o:["Dual Automatic Flight Control System","Digital Automatic Flight Control System","Direct AFCS engagement mode","Dynamic Autopilot and Flight Control System"],a:1,e:"DAFCS = Digital Automatic Flight Control System. This is an older designation for the full digital autopilot — in modern documentation it is simply called AFCS.",ref:"Ch.00 §3"},
{q:"What industry standard does the EC135 training course follow?",o:["ICAO Annex 6","EASA Part-FCL","ATA 104","JAA TGL 44"],a:2,e:"The EC135 P3H/T3H training is structured according to ATA 104 (Air Transport Association specification for operator training programs), which defines module content and organization.",ref:"Ch.00 §1"},
{q:"What does ADC stand for in the Helionix® system?",o:["Auto-Disconnection Controller","Autopilot Data Computer","Air Data Computer","Altitude Deviation Controller"],a:2,e:"ADC = Air Data Computer. It processes pitot-static inputs to provide IAS, altitude, and vertical speed data to Helionix® and the AFCS.",ref:"Ch.00 §3"},
{q:"What does MFD stand for, and how many are fitted to the EC135 P3H/T3H?",o:["Multi-Frequency Display — 2 fitted","Multi-Function Display — 3 fitted","Main Flight Display — 4 fitted","Modular Function Display — 2 fitted"],a:1,e:"MFD = Multi-Function Display. Three MFDs are fitted (pilot, centre, copilot), each capable of displaying FND, NAVD, VMS, and other formats.",ref:"Ch.00 §3"},
{q:"Why is the EC135 training manual stated as 'not subject to a revision service'?",o:["It is a classified document","The aircraft is out of production","It is a course-specific document issued once; operators must track actual aircraft changes via AMM revisions","It uses a digital-only update system"],a:2,e:"The training manual is a static course document. Actual airworthiness data is controlled via the official AMM and AFM, which are subject to revision services. The training manual is used as a course reference, not a regulatory document.",ref:"Ch.00 §1"},
{q:"What is the relationship between the IMA platform and the AMC?",o:["The AMC is a separate system independent of the IMA","The AMC runs as a hosted application within the IMA using ARINC 653 software partitioning","The IMA is a subset of the AMC hardware","The AMC and IMA are alternative names for the same unit"],a:1,e:"The AMC (Aircraft Management Computer) runs as hosted software on the IMA platform. ARINC 653 software partitioning ensures each application is isolated, so a failure in one does not affect others.",ref:"Ch.00 §3"},
{q:"What does HTAWS stand for?",o:["High-speed Terrain Avoidance Warning System","Helicopter Terrain Awareness and Warning System","Hover Tracking and Warning System","Horizontal Threat Assessment Warning System"],a:1,e:"HTAWS = Helicopter Terrain Awareness and Warning System. It provides FLTA (Forward-Looking Terrain Avoidance) and GPWS modes specific to helicopter operations.",ref:"Ch.00 §3"},
{q:"What does FDCR stand for?",o:["Flight Director Control Record","Flight Data Continuous Recording","Full Data Crash Recorder","Flight Dynamics Control Register"],a:1,e:"FDCR = Flight Data Continuous Recording — the EC135's flight data recording system, integrated with the Helionix® IMA and standard fit on P3H/T3H variants.",ref:"Ch.00 §3"},
{q:"What does MCP stand for in the Helionix® architecture?",o:["Main Control Panel","Multi-Control Panel","Master Cockpit Processor","Mode Control Panel"],a:1,e:"MCP = Multi-Control Panel. It is the primary panel through which crew interact with the Helionix® IMA — selecting formats, entering data, and controlling systems.",ref:"Ch.00 §3"},
{q:"The training manual states Airbus Helicopters reserves the right to make changes without notice. What practical implication does this have for operators?",o:["Operators may modify aircraft without approval","Always verify actual aircraft configuration against the current AMM, not the training manual","The training manual overrides the flight manual","Changes are only cosmetic and do not affect procedures"],a:1,e:"Because the training manual is a static document, operators must always verify system specifics against the current, approved Aircraft Maintenance Manual (AMM) and Airplane Flight Manual (AFM). The training manual is a learning tool, not an airworthiness reference.",ref:"Ch.00 §1"},
{q:"What does the abbreviation PMA stand for in the EC135 engine context?",o:["Permanent Magnet Alternator","Parts Manufacturer Approval","Pilot Manual Adjustment","Primary Mode Actuator"],a:0,e:"PMA = Permanent Magnet Alternator. It is an engine-driven AC generator on the PW206B3 that provides power to the FADEC (EEC), ensuring engine control even without the main DC supply.",ref:"Ch.00 §3"}
]
},

// ─────────────────────────────────────────
// CHAPTER 01 — First Contact with the Helicopter
// ─────────────────────────────────────────
{
m:[
{q:"What is the MTOM of the EC135 P3H and T3H?",o:["2,720 kg","2,835 kg","2,950 kg","2,980 kg"],a:3,e:"Both the EC135 P3H and T3H are certified to a MTOM of 2,980 kg.",ref:"Ch.01 §4"},
{q:"How many main rotor blades does the EC135 have?",o:["3","4","5","6"],a:1,e:"The EC135 has a 4-blade Bearingless Main Rotor (BMR).",ref:"Ch.01 §3"},
{q:"How many blades does the EC135 Fenestron® tail rotor have?",o:["8","10","12","14"],a:1,e:"The Fenestron® anti-torque system has 10 blades rotating inside a shroud integrated into the vertical fin.",ref:"Ch.01 §3"},
{q:"When was the EC135 first certified?",o:["1991","1994","1996","1998"],a:2,e:"EC135 certification by the German LBA and the American FAA was completed in mid-1996.",ref:"Ch.01 §1"},
{q:"What is the direct predecessor of the EC135?",o:["BO105","BK117","BO108","EC120"],a:2,e:"The EC135 developed from the BO108, which first flew on 15 October 1988.",ref:"Ch.01 §1"},
{q:"On what date did the BO108 (EC135 predecessor) make its first flight?",o:["12 March 1985","15 October 1988","3 June 1990","22 January 1993"],a:1,e:"The BO108 made its first flight on 15 October 1988.",ref:"Ch.01 §1"},
{q:"Which engine powers the EC135 P3H?",o:["Turbomeca ARRIUS 2B2 Plus","Pratt & Whitney PW206B3","Turbomeca ARRIUS 2B1","Pratt & Whitney PT6B-37A"],a:1,e:"The EC135 P3H is powered by two Pratt & Whitney Canada PW206B3 turboshaft engines.",ref:"Ch.01 §2"},
{q:"Which engine powers the EC135 T3H?",o:["Pratt & Whitney PW206B3","Turbomeca ARRIUS 2B1","Turbomeca ARRIUS 2B2 Plus","Pratt & Whitney PW207D"],a:2,e:"The EC135 T3H is powered by two Turbomeca ARRIUS 2B2 Plus turboshaft engines.",ref:"Ch.01 §2"},
{q:"What is the standard seating capacity of the EC135?",o:["5 (1 crew + 4 pax)","6 (2 crew + 4 pax)","7 (2 crew + 5 pax)","8 (2 crew + 6 pax)"],a:2,e:"Standard configuration is 7 occupants: 2 crew and 5 passengers. An optional 8th seat is available.",ref:"Ch.01 §3"},
{q:"What type of landing gear does the EC135 use?",o:["Wheeled retractable","Wheeled fixed","Skid type","Floats only"],a:2,e:"The EC135 uses skid-type landing gear: two aluminium crosstubes with two skids.",ref:"Ch.01 §3"},
{q:"What type of anti-torque system does the EC135 use?",o:["Conventional open tail rotor","NOTAR (No Tail Rotor)","Fenestron® (shrouded fan)","Twin tail rotors"],a:2,e:"The EC135 uses a Fenestron® — a fan-in-shroud anti-torque system enclosed within the vertical fin.",ref:"Ch.01 §3"},
{q:"What is the EC135's electrical system voltage?",o:["14 V DC","24 V DC","28 V DC","115 V AC"],a:2,e:"The EC135 uses a fully redundant 28 V DC electrical system, standard for modern military and civil helicopters.",ref:"Ch.01 §3"},
{q:"How many fuel tanks does the EC135 have?",o:["1","2","3","4"],a:1,e:"The EC135 has two bladder fuel tanks mounted under the cabin floor (a main tank and a split supply tank).",ref:"Ch.01 §3"},
{q:"What avionics suite is fitted to the EC135 P3H/T3H?",o:["Collins Pro Line 21","Garmin G1000H","Honeywell Primus","Helionix® IMA"],a:3,e:"The EC135 P3H/T3H features the Helionix® Integrated Modular Avionics suite developed by Airbus Helicopters.",ref:"Ch.01 §4"},
{q:"What power class are the PW206B3 and ARRIUS 2B2 Plus engines?",o:["250 kW class","350 kW class","450 kW class","550 kW class"],a:2,e:"Both the PW206B3 (P3H) and ARRIUS 2B2 Plus (T3H) are in the 450 kW class turboshaft engines.",ref:"Ch.01 §2"}
],
h:[
{q:"Before being known as Airbus Helicopters, what was the company previously called?",o:["MBB then Eurocopter","Eurocopter then Airbus Helicopters","Bölkow then MBB then Eurocopter then Airbus Helicopters","Aerospatiale then Airbus Helicopters"],a:2,e:"The lineage is: Bölkow → MBB/Bölkow (first hingeless rotor tested 1962) → Eurocopter (after merger) → Airbus Helicopters.",ref:"Ch.01 §1"},
{q:"What year did MBB/Bölkow first test the hingeless rotor system that led to the EC135 design?",o:["1958","1962","1968","1975"],a:1,e:"The hingeless rotor system was first tested in 1962 by MBB/Bölkow, forming the basis for the EC135 BMR design philosophy.",ref:"Ch.01 §1"},
{q:"What specific customer feedback drove the BO108-to-EC135 design changes?",o:["Demand for more powerful engines and higher speed","Request for enlarged cabin, improved visibility, and adoption of the Fenestron®","Requirement for retractable landing gear","Need for reduced empty weight"],a:1,e:"Customer feedback on the BO108 led to an enlarged cabin, improved visibility angles, and adoption of the Aerospatiale-developed Fenestron® anti-torque system.",ref:"Ch.01 §1"},
{q:"What is the maximum optional seating configuration for the EC135?",o:["7","8","9","10"],a:1,e:"The EC135 standard seats 7 (2 crew + 5 pax). An optional 8th seat position is available, giving 2 crew + 6 passengers.",ref:"Ch.01 §3"},
{q:"The EC135 fuselage is described as semi-monocoque. What does this mean in terms of primary structure?",o:["Composite-only skin structure with no internal frames","Sheet metal skin with internal frames and bulkheads sharing structural loads","Titanium monocoque shell with composite fairings","Welded steel tube frame with composite panels"],a:1,e:"Semi-monocoque means the skin (sheet metal) and the internal frames/bulkheads share structural loads. The EC135 uses sheet metal as primary structure with composite for the cabin frame, doors, and tail boom.",ref:"Ch.01 §3"},
{q:"What is the function of the flexbeam in the EC135 BMR?",o:["Generates aerodynamic lift at the blade root","Acts as a structural member allowing blade flap, lead-lag, and pitch without conventional bearings","Provides electrical bonding between blades and hub","Absorbs blade impact forces during hard landings"],a:1,e:"The flexbeam is the inboard structural element of the BMR blade. Its flexibility allows blade movement in all three axes (flap, lag, pitch) without conventional bearings — hence 'bearingless.'",ref:"Ch.01 §3"},
{q:"How is pitch input applied to the EC135 BMR blades?",o:["Via elastomeric bearings at the blade root","Through the flexbeam twisting","Via glass/carbon fibre pitch control cuffs around the flexbeam","Through conventional feathering bearings"],a:2,e:"Pitch control is applied through pitch control cuffs — glass/carbon fibre structures surrounding the flexbeam — through which the control rod inputs change the blade pitch angle.",ref:"Ch.01 §3"},
{q:"What does 'P3H' specifically denote in the designation EC135 P3H?",o:["P = Prototype, 3 = third series, H = High-altitude","P = Pratt & Whitney, 3 = third generation engine, H = Helionix®","P = Production, 3 = 3-crew, H = High performance","P = Passenger, 3 = 3-blade rotor, H = Heavy"],a:1,e:"P3H designates: P = Pratt & Whitney engine family, 3 = third-generation engine (PW206B3), H = fitted with Helionix® IMA avionics suite.",ref:"Ch.01 §2"},
{q:"What advantage does the Fenestron® offer over a conventional open tail rotor in terms of safety?",o:["Higher thrust output","The blades are enclosed in a protective shroud, reducing personnel and FOD risk","Lower maintenance requirements","Simpler mechanical design"],a:1,e:"The Fenestron® shroud physically encloses the blades, protecting ground personnel from the rotating blades and protecting the tail rotor from foreign object damage (FOD).",ref:"Ch.01 §3"},
{q:"How does the EC135 reduce main rotor and MGB vibration transmission to the cabin?",o:["Active vibration cancellation via piezo actuators","Liquid inertia vibration eliminators (LIVE units)","ARIS (Anti Resonance Isolation System) tuned struts","Elastomeric tail boom attachment"],a:2,e:"ARIS (Anti Resonance Isolation System) uses specially designed tuned struts/mounts to attenuate vibrations from the main rotor and MGB before they reach the fuselage structure.",ref:"Ch.01 §3"},
{q:"When was both the LBA (German) and FAA (American) certification of the EC135 completed?",o:["1994","1995","Mid-1996","1998"],a:2,e:"The EC135 received simultaneous LBA (Luftfahrt-Bundesamt) German certification and FAA American certification in mid-1996.",ref:"Ch.01 §1"},
{q:"What controls pitch and roll on the EC135?",o:["The collective lever (fore-aft/lateral inputs)","The cyclic stick (tilts the rotor disc fore-aft and left-right)","The anti-torque pedals (combined with cyclic)","The trim switches (primary inputs)"],a:1,e:"The cyclic stick tilts the main rotor disc: forward/aft movement controls pitch attitude; left/right movement controls roll. The collective lever controls altitude/power.",ref:"Ch.01 §3"},
{q:"What feature of the Fenestron® blade arrangement reduces tonal noise?",o:["Carbon fibre blade tips","Variable pitch at high speed","Uneven (non-uniform) blade spacing","Shroud acoustic lining"],a:2,e:"The Fenestron® uses uneven (asymmetric) blade spacing. This distributes the aerodynamic pulses at multiple frequencies instead of one dominant tone, significantly reducing tonal noise.",ref:"Ch.01 §3"},
{q:"What is the swashplate's function in the EC135 rotor system?",o:["It monitors rotor speed for the FLI","It transmits collective and cyclic inputs from the non-rotating control system to the rotating blade pitch control rods","It provides vibration damping between hub and blade","It connects the ARIS struts to the rotor head"],a:1,e:"The swashplate is the interface between the non-rotating control system and the rotating rotor. Its non-rotating plate receives collective/cyclic inputs; the rotating plate transmits them via push-pull rods to the blade pitch control cuffs.",ref:"Ch.01 §3"},
{q:"What is the maximum MTOM when carrying an external load (sling load)?",o:["2,720 kg","2,835 kg","2,900 kg","2,980 kg"],a:3,e:"When carrying an external sling load, the EC135 P3H/T3H MTOM remains 2,980 kg (the same as the standard MTOM). Check AFM for specific external load configurations.",ref:"Ch.01 §4"}
]
},

// ─────────────────────────────────────────
// CHAPTER 02 — Integrated Modular Avionics (Helionix)
// ─────────────────────────────────────────
{
m:[
{q:"How many MFDs (Multi-Function Displays) does the Helionix® system have?",o:["1","2","3","4"],a:2,e:"Helionix® uses 3 MFDs: one for the pilot (left), one centre (shared), and one for the copilot (right).",ref:"Ch.02 §1"},
{q:"How many AMCs (Aircraft Management Computers) are in the Helionix® system?",o:["1","2","3","4"],a:1,e:"Helionix® uses 2 AMCs. They run multiple avionics functions in parallel via ARINC 653 software partitioning.",ref:"Ch.02 §1"},
{q:"What is the FND display format?",o:["Fuel and Navigation Display","Flight and Navigation Display","Forward Navigation Display","Full Navigation Display"],a:1,e:"FND = Flight and Navigation Display — the primary flight display format, equivalent to a PFD (Primary Flight Display).",ref:"Ch.02 §3"},
{q:"What does the NAVD display show?",o:["Engine parameters and fuel","Navigation Display (horizontal situation / map)","Vertical speed and altitude","Communications frequencies"],a:1,e:"NAVD = Navigation Display. It shows the horizontal situation, map, navigation sources, and traffic/terrain data.",ref:"Ch.02 §3"},
{q:"What does the VMS display page show?",o:["Speed and altitude only","Vertical Manoeuvre System data","Vehicle Management System — engine and systems data","VOR and marker beacon data"],a:2,e:"VMS = Vehicle Management System display page. It shows engine parameters (TQ, T4, N1, N2), fuel, hydraulics, and system status.",ref:"Ch.02 §3"},
{q:"What colour is a WARNING alert in the Helionix® Master List?",o:["Amber","Green","Cyan","Red"],a:3,e:"WARNING alerts are displayed in RED. They require IMMEDIATE crew action and are accompanied by an aural tone and voice message.",ref:"Ch.02 §5"},
{q:"What colour is a CAUTION alert in the Helionix® Master List?",o:["Red","Amber","Green","Blue"],a:1,e:"CAUTION alerts are displayed in AMBER. They indicate an abnormal condition requiring crew awareness.",ref:"Ch.02 §5"},
{q:"What colour is an ADVISORY alert?",o:["Red","Amber","Green","Cyan"],a:3,e:"ADVISORY alerts are displayed in CYAN. They provide information requiring crew attention but no immediate action.",ref:"Ch.02 §5"},
{q:"What does HTAWS provide?",o:["Automatic hover position hold","Helicopter Terrain Awareness and Warning System","High-Temperature Airworthiness Warning System","Hydraulic Thrust and Attitude Warning System"],a:1,e:"HTAWS = Helicopter Terrain Awareness and Warning System. It provides Forward-Looking Terrain Avoidance (FLTA) and GPWS modes.",ref:"Ch.02 §6"},
{q:"What does ACAS provide the crew?",o:["Automatic approach guidance","Fuel consumption advisory","Traffic Advisories (TA) and Resolution Advisories (RA)","Collision avoidance by autopilot only"],a:2,e:"ACAS = Airborne Collision Avoidance System. It provides TA (Traffic Advisory) for awareness and RA (Resolution Advisory) requiring crew action to avoid conflict.",ref:"Ch.02 §6"},
{q:"How many AHRS are fitted to the EC135 P3H/T3H?",o:["1","2","3","4"],a:1,e:"Two AHRS (Attitude and Heading Reference Systems) are fitted. AHRS 1 is primary; AHRS 2 provides redundancy.",ref:"Ch.02 §1"},
{q:"What does IESI stand for?",o:["Integrated Engine Status Indicator","Integrated Electronic Standby Instrument","Internal Electronic Sensor Interface","Inertial Engine Speed Indicator"],a:1,e:"IESI = Integrated Electronic Standby Instrument. It provides independent backup for attitude, altitude, and airspeed.",ref:"Ch.02 §1"},
{q:"What is the FLI used for in normal AEO operation?",o:["Shows remaining fuel only","Shows gear ratio status","Shows the first engine parameter approaching its limit","Shows collective position"],a:2,e:"In AEO (All Engines Operative) mode, the FLI rotary display shows the power margin — the distance of the first parameter from its limit across all monitored parameters.",ref:"Ch.02 §4"},
{q:"What does Training Mode on the FLI allow?",o:["Shows recorded flight data","Simulates OEI for training without reducing actual power","Tests warning system alerts","Adjusts MFD brightness"],a:1,e:"Training Mode simulates OEI on the FLI display for crew training. FADEC does NOT actually reduce power — the 'training' engine remains fully operative.",ref:"Ch.02 §4"},
{q:"What standby instrument provides independent backup if all MFDs fail?",o:["A magnetic compass only","The IESI (Integrated Electronic Standby Instrument)","A standby ADI and altimeter","The GPS display on the MCP"],a:1,e:"The IESI is an independent standby instrument providing attitude, altitude, and airspeed independent of the Helionix® IMA — available even on battery power alone.",ref:"Ch.02 §1"}
],
h:[
{q:"What software partitioning standard does the Helionix® IMA use to isolate applications?",o:["DO-178C","ARINC 429","ARINC 653","DO-254"],a:2,e:"ARINC 653 defines the software partitioning (time and space) that allows multiple independent applications to share the same AMC hardware without interference.",ref:"Ch.02 §1"},
{q:"What ARINC bus standard is used for the EC135 Flight Data Recorder communication?",o:["ARINC 429","ARINC 708","ARINC 717","Ethernet"],a:2,e:"ARINC 717 is the serial digital bus standard used for Flight Data Recorder (FDCR) communication in the EC135.",ref:"Ch.02 §2"},
{q:"What ARINC bus is used for weather radar data in Helionix®?",o:["ARINC 429","ARINC 708","ARINC 717","RS-422"],a:1,e:"ARINC 708 is the standard digital bus for airborne weather radar data within the Helionix® IMA.",ref:"Ch.02 §2"},
{q:"What happens to the Helionix® display system if two MFDs fail simultaneously?",o:["All avionics shut down — IESI becomes sole reference","The system automatically reconfigures to show critical information on the remaining MFD","The IESI replaces both failed MFDs","Nothing — redundancy is only for single failures"],a:1,e:"Helionix® has automatic reconfiguration logic: upon dual MFD failure, critical information is automatically redistributed to the remaining functional MFD.",ref:"Ch.02 §3"},
{q:"What is the FLTA capability within HTAWS?",o:["Forward Landing Terrain Avoidance — warns of terrain during approach","Forward-Looking Terrain Avoidance — provides predictive terrain/obstacle warnings ahead of the aircraft","Flight Level Terrain Avoidance — altitude-based warning","Final Landing Terrain Assessment — checks for obstacles in the landing zone"],a:1,e:"FLTA = Forward-Looking Terrain Avoidance. It looks ahead along the flight path and predicted trajectory to provide early warning of terrain/obstacles, even in VMC.",ref:"Ch.02 §6"},
{q:"What GPWS mode warns of excessive altitude loss after takeoff?",o:["Mode 1","Mode 2","Mode 3","Mode 5"],a:2,e:"GPWS Mode 3 activates when excessive altitude loss occurs after takeoff or go-around — protecting against inadvertent descents in the initial climb phase.",ref:"Ch.02 §6"},
{q:"What GPWS mode warns of excessive ILS glide slope deviation?",o:["Mode 2","Mode 4","Mode 5","Mode 6"],a:2,e:"GPWS Mode 5 activates when the aircraft is significantly below the ILS glide slope (flying too low on the approach).",ref:"Ch.02 §6"},
{q:"In what specific scenario would a pilot use the FLI OEI 30-second rating?",o:["During normal hover operations","Immediately after engine failure to get maximum emergency power for a short period","During autorotation to arrest descent rate","During engine start"],a:1,e:"The OEI 30-second rating is the maximum emergency power rating available immediately after engine failure. It is time-limited (30 seconds) and used only to prevent a crash or gain a safe flight path.",ref:"Ch.02 §4"},
{q:"How does the Helionix® aural alerting system differentiate between alert levels?",o:["Only by colour — no aural distinction","WARNING has a continuous tone + voice message; CAUTION has a single chime; ADVISORY is visual only","All alerts use the same single-chime tone","ADVISORY uses voice only; WARNING is visual only"],a:1,e:"WARNING: continuous tone + synthesized voice message (e.g., 'Fire, Engine One'). CAUTION: single aural chime. ADVISORY: visual only. This ensures crew attention is proportional to urgency.",ref:"Ch.02 §5"},
{q:"What is the MCP (Multi-Control Panel) used for in Helionix®?",o:["Only to control engine parameters","The primary crew interface for Helionix® — selecting formats, entering data, controlling systems","To control the AFCS modes only","To manage IFF/SSR transponder codes"],a:1,e:"The MCP is the primary human-machine interface for the Helionix® IMA system — used to select MFD formats, enter navigation data, configure systems, and interact with avionics.",ref:"Ch.02 §1"},
{q:"What is the DTD used for in day-to-day Helionix® operation?",o:["Permanent data storage for FDCR","Loading software updates, navigation databases, and crew preferences into the IMA","Controlling MFD brightness","Providing redundant GPS receiver"],a:1,e:"The DTD (Data Transfer Device) is used to load software updates, navigation databases (airways, airports, obstacles, terrain), and configuration data into the Helionix® IMA.",ref:"Ch.02 §1"},
{q:"What is the significance of the Warning Unit (W/U) in the EC135 alerting system?",o:["It is the primary MFD display","It provides the master WARNING and CAUTION warning lights, independent of the MFDs","It controls the audio management system only","It monitors the AFCS engagement status"],a:1,e:"The Warning Unit (W/U) provides dedicated master WARNING (red) and CAUTION (amber) lights visible to both pilots. It is a hardware unit independent of the MFD software display — providing a fallback alert even if MFDs fail.",ref:"Ch.02 §5"},
{q:"What does an ACAS Resolution Advisory (RA) require the crew to do?",o:["Monitor traffic on NAVD — no action needed","Immediately follow the RA manoeuvre instruction — climb or descend as indicated","Squawk 7700 and declare emergency","Reduce speed to below 80 kt"],a:1,e:"An RA requires the crew to immediately fly the indicated manoeuvre (e.g., 'Climb, Climb' or 'Descend, Descend') to achieve safe vertical separation. It is not advisory — it requires positive action.",ref:"Ch.02 §6"},
{q:"What is SVS (Synthetic Vision System) in the Helionix® context?",o:["A system that automatically controls the aircraft in poor visibility","An optional terrain database visualization showing a virtual 3D view of terrain on the FND","A synthetic aperture radar for ground mapping","The VOR synthetic course display"],a:1,e:"SVS = Synthetic Vision System (optional). It displays a computer-generated 3D terrain view on the FND using a GPS position and terrain database, improving situational awareness in IMC or at night.",ref:"Ch.02 §3"},
{q:"Why does the EC135 have two AHRS units?",o:["One is for the pilot MFD, one for the copilot MFD — no cross-connection","Redundancy — AHRS 2 provides backup if AHRS 1 fails, and AFCS can continue on AHRS 2","One for the SAS, one for the AFCS upper modes","They provide attitude on different axes: AHRS 1 for pitch/roll, AHRS 2 for heading"],a:1,e:"Two AHRS provide redundancy. AHRS 1 is the primary source. If AHRS 1 fails, AHRS 2 takes over and the AFCS and displays continue to function normally — critical for IFR operations.",ref:"Ch.02 §1"}
]
},

// ─────────────────────────────────────────
// CHAPTER 03 — Handling of the Helicopter
// ─────────────────────────────────────────
{
m:[
{q:"Which hoisting device is used to lift the fully equipped EC135 helicopter?",o:["TM2812G001","PWC 64211","M12699/P1","L535G1001101"],a:2,e:"M12699/P1 is the approved hoisting device for the fully equipped helicopter, the MGB, and the main rotor hub shaft.",ref:"Ch.03 §1"},
{q:"Which hoisting device is approved for the Turbomeca ARRIUS 2B2 Plus engine?",o:["M12699/P1","PWC 64211","TM2812G001","L535G1001101"],a:2,e:"TM2812G001 (or the common alternative L710M1009101H113-01) is approved for hoisting the Turbomeca ARRIUS 2B2 Plus engine.",ref:"Ch.03 §2"},
{q:"Which hoisting device is used for the Pratt & Whitney PW206B3 engine?",o:["M12699/P1","PWC 64211","TM2812G001","L535G1001101"],a:1,e:"PWC 64211 (or the common alternative L710M1009101H113-01) is approved for hoisting the PW206B3 engine.",ref:"Ch.03 §2"},
{q:"Which device is used to hoist the EC135 rear structure?",o:["M12699/P1","PWC 64211","TM2812G001","L535G1001101"],a:3,e:"L535G1001101 is the approved hoisting device for the rear structure of the EC135.",ref:"Ch.03 §2"},
{q:"How many jacking points does the EC135 have?",o:["2","3","4","6"],a:2,e:"The EC135 has 4 jacking points — one below each of the four landing gear fittings on the fuselage subfloor.",ref:"Ch.03 §3"},
{q:"What must be supported when hoisting the complete helicopter?",o:["The main rotor blades","The tail boom","The engine cowlings","The cockpit nose"],a:1,e:"The tail boom must be supported during helicopter hoisting to maintain balance and prevent the helicopter from tipping.",ref:"Ch.03 §1"},
{q:"What movements must be avoided during helicopter hoisting?",o:["Vertical movements","Lateral swinging movements","Forward tilting","Rotor engagement"],a:1,e:"Swinging movements must be avoided during hoisting — they create dynamic loads that can exceed equipment limits and cause damage.",ref:"Ch.03 §1"},
{q:"Which AMM chapter covers EC135 jacking and lifting procedures?",o:["AMM Chapter 03","AMM Chapter 05","AMM Chapter 07","AMM Chapter 12"],a:2,e:"All jacking and lifting operations must be performed in accordance with AMM Chapter 07.",ref:"Ch.03 §3"},
{q:"Where is the weighing bracket installed for the EC135?",o:["On the aft fuselage frame","Centrally on the forward crosstube","On the main transmission deck","Under the tail boom"],a:1,e:"The weighing bracket for measuring the helicopter's weight is installed centrally on the forward crosstube of the landing gear.",ref:"Ch.03 §3"},
{q:"Can the M12699/P1 device also be used for the MGB?",o:["No — a different device is required","Yes — it is approved for both the complete helicopter and the MGB","Only for the MGB without the oil filled","Only during final assembly"],a:1,e:"M12699/P1 is approved for the fully equipped helicopter, the MGB, and the main rotor hub shaft — the same device covers all three.",ref:"Ch.03 §2"},
{q:"What is L710M1009101H113-01 used for?",o:["Only for the PW engine","Only for the ARRIUS engine","A common device approved for both engine types","For the MGB only"],a:2,e:"L710M1009101H113-01 is a common hoisting device approved for both the PW206B3 and the ARRIUS 2B2 Plus engines.",ref:"Ch.03 §2"},
{q:"For what purpose are jacking brackets used on the EC135?",o:["Towing and ground movement","Maintenance and weighing","Engine removal only","External load attachment"],a:1,e:"Jacking brackets are used for jacking the helicopter during maintenance operations and for accurate weighing.",ref:"Ch.03 §3"},
{q:"What document must be consulted for all EC135 hoisting operations?",o:["The Flight Manual (AFM)","The Aircraft Maintenance Manual (AMM)","The Quick Reference Handbook (QRH)","The Illustrated Parts Catalogue (IPC)"],a:1,e:"All hoisting operations must use approved devices listed in and performed in accordance with the AMM (Aircraft Maintenance Manual).",ref:"Ch.03 §1"},
{q:"How many approved hoisting devices exist for the PW206B3 engine?",o:["1","2","3","4"],a:1,e:"Two devices are approved for the PW206B3: PWC 64211 (primary) and L710M1009101H113-01 (common alternative).",ref:"Ch.03 §2"},
{q:"What type of operations require the helicopter to be jacked?",o:["Only engine replacement","Only fuel system servicing","Maintenance operations and weighing","Preflight inspection only"],a:2,e:"The helicopter is jacked for maintenance operations (e.g., landing gear inspection) and for weighing purposes.",ref:"Ch.03 §3"}
],
h:[
{q:"Why must the tail boom be supported during complete helicopter hoisting?",o:["To protect the tail rotor from damage","Because the CG is forward of the MGB hoisting point, creating a nose-down moment without tail support","To allow removal of the tail boom during the lift","To prevent the rotor brake from releasing"],a:1,e:"When lifting the helicopter from its MGB/transmission deck, the CG (which is forward) would create a nose-down tipping moment without tail boom support. Supporting the tail boom balances the helicopter during the lift.",ref:"Ch.03 §1"},
{q:"What is the consequence of using an unapproved hoisting device on an EC135 component?",o:["Minor documentation non-compliance only","Risk of structural damage to the component, dropped load, personnel injury, and airworthiness violation","Only an issue if maintenance logs are not updated","No consequence if the load limit is not exceeded"],a:1,e:"Using unapproved hoisting devices risks structural damage (wrong attachment geometry), dropped loads causing component or airframe damage, and personnel injury. It also constitutes an airworthiness violation requiring the component to be inspected before return to service.",ref:"Ch.03 §1"},
{q:"Are hoisting and jacking operations pilot responsibilities?",o:["Yes — pilots conduct all preflight ground handling","No — these are maintenance functions performed by licensed engineers per the AMM","Yes — but only for the preflight hoisting check","Only if no licensed engineer is available"],a:1,e:"Hoisting and jacking are maintenance functions. They must be performed by licensed engineers following AMM procedures. Pilots do not perform these operations.",ref:"Ch.03 §1"},
{q:"What structural failure mode is being avoided when jacking brackets are placed at all four landing gear fittings?",o:["Fuel tank puncture","Uneven load causing crosstube bending beyond limits","Electrical short circuit in the subfloor","MGB oil spillage"],a:1,e:"Jacking at all four gear fittings ensures loads are distributed through the designed load paths (subfloor fittings). Jacking from incorrect points or fewer points creates uneven loading that could bend or damage crosstubes and subfloor structure.",ref:"Ch.03 §3"},
{q:"Why does the weighing bracket need to be centrally positioned on the forward crosstube?",o:["To connect to the main structural frame","A central position on the crosstube allows balanced vertical load without inducing a moment that would skew the weight measurement","To avoid interfering with fuel system components","For accessibility with standard scales"],a:1,e:"The central position on the forward crosstube places the weighing reference point at the design datum, giving an accurate centre-of-gravity measurement and preventing lateral balance errors in the weight reading.",ref:"Ch.03 §3"},
{q:"What does 'dynamic load' mean in the context of avoiding swinging during hoisting?",o:["The combined mass of all dynamic components","Oscillating inertial forces generated by the swinging mass that exceed static load limits by a significant factor","The power output of the hoisting crane motor","Vibration from the rotor during test runs"],a:1,e:"Swinging generates dynamic (oscillating) forces proportional to swing amplitude and speed. These can multiply the static weight by factors of 2–3x or more at the peak of each swing, potentially exceeding the rated capacity of hoisting devices and attachment hardware.",ref:"Ch.03 §1"},
{q:"Which hoisting device is specifically used for the rear structure — and why is a separate device needed?",o:["M12699/P1 — the same universal device covers all components","L535G1001101 — different attachment geometry and load distribution for the rear structural assembly","TM2812G001 — because the rear structure contains the fuel tanks","PWC 64211 — provides a wider sling base"],a:1,e:"L535G1001101 is specifically designed for the rear structure's attachment points and load distribution requirements, which differ from the MGB or engine attachment geometry. Using the wrong device could cause attachment failure.",ref:"Ch.03 §2"},
{q:"What is the risk of applying the rotor brake before hoisting the helicopter?",o:["There is no risk — rotor brake is required to be ON during hoisting","Risk of the rotor head rotating during hoisting creating gyroscopic forces; rotor brake should be applied but blades secured","Rotor brake must always be OFF during maintenance hoisting","Rotor brake application prevents jacking brackets from being installed"],a:1,e:"The rotor brake should be applied to prevent inadvertent rotor rotation, but rotor blade restraints (tying down blades) are also required before hoisting to prevent dynamic forces if the helicopter swings. The two measures work together.",ref:"Ch.03 §1"},
{q:"Why is weighing the helicopter important from an airworthiness perspective?",o:["To verify the fuel load is within limits","To establish the aircraft's empty weight and CG, which are used to calculate weight and balance limits for each flight","To check that the MGB is correctly installed","To verify cargo door seal integrity"],a:1,e:"Aircraft weighing establishes empty weight and empty CG. These values, combined with loading charts, allow crews and dispatchers to verify that the aircraft remains within certified weight and CG limits for every flight.",ref:"Ch.03 §3"},
{q:"Can the helicopter be raised from only one end (nose or tail) using the jacking system?",o:["Yes — this is the normal procedure for nose gear inspection","No — the 4-point jacking system requires symmetric loading at all four points","Yes — but only the tail end for TGB access","Yes — nose only for avionics bay access"],a:1,e:"The 4-point jacking system is designed for symmetric loading. Jacking from fewer points or asymmetrically can over-stress the subfloor structure and the crosstube fittings at the raised end.",ref:"Ch.03 §3"},
{q:"What documentation requirement follows any jacking or hoisting operation?",o:["No documentation required for routine operations","The maintenance action must be recorded in the aircraft log book with date, hours, engineer signature, licence number, and any defects found","Only required if a defect was found","Required only for first-of-type maintenance events"],a:1,e:"All maintenance operations — including jacking and hoisting — must be recorded in the aircraft log book. This creates the airworthiness trail required for continued certification.",ref:"Ch.03 §1"},
{q:"What is the consequence if hoisting is performed without an approved hoisting device, and the helicopter is undamaged?",o:["No consequence if no damage occurred","The aircraft is still unairworthy until an inspection per AMM confirms no damage — the operation is a deviation from the approved maintenance data","Only the engineer is liable — the aircraft is not affected","A preflight check is sufficient to clear the aircraft"],a:1,e:"Even if no apparent damage occurred, using unapproved equipment is a deviation from approved maintenance data. The aircraft is considered unairworthy until a formal inspection per AMM confirms no hidden damage.",ref:"Ch.03 §1"},
{q:"How does the jacking system interact with the weight distribution across the EC135 landing gear?",o:["Jacking points are at midspan of the crosstubes","Jacking points are at the landing gear-to-fuselage attachment fittings — the same structural hard points as the landing gear loads","Jacking points are independent of the landing gear structure","Jacking forces go through the fuel tanks via the subfloor"],a:1,e:"The jacking brackets are placed below the landing gear attachment fittings — the same structural hard points designed to handle large vertical loads during landing. This ensures jacking forces follow the certified load path.",ref:"Ch.03 §3"},
{q:"What is the primary purpose of the L710M1009101H113-01 being approved for both engine types?",o:["Cost reduction by having a single device","Logistical simplification — one tool can be used at maintenance facilities that operate both P-type and T-type EC135s","It has the highest load rating and is therefore safe for any component","To allow quick engine swap between P and T variants"],a:1,e:"L710M1009101H113-01 serves as a common tool approved for both engine families. This simplifies tooling requirements for MRO facilities maintaining both EC135 P-type (PW) and T-type (ARRIUS) variants.",ref:"Ch.03 §2"},
{q:"Why is the AMM (Aircraft Maintenance Manual) the authoritative reference for hoisting rather than the training manual?",o:["The training manual has higher authority for ground operations","The AMM is the approved, current airworthiness document; the training manual is a static learning aid that may not reflect current aircraft modifications or revisions","Both have equal authority","The training manual contains the actual procedures; AMM only has part numbers"],a:1,e:"The AMM is issued and controlled as an approved airworthiness document, subject to mandatory revisions and Airworthiness Directives. The training manual is a static course document — it cannot be used as a maintenance authority.",ref:"Ch.03 §1"}
]
},

// ─────────────────────────────────────────
// CHAPTER 04 — Lifting System
// ─────────────────────────────────────────
{
m:[
{q:"What is the normal main rotor speed (Nr) of the EC135?",o:["320 RPM","360 RPM","395 RPM","420 RPM"],a:2,e:"The EC135 main rotor rotates at 395 RPM, derived from the engine input speed of 5,898 RPM through the 14.923:1 gear ratio.",ref:"Ch.04 §2"},
{q:"What is the MGB main rotor gear ratio?",o:["10.500:1","12.680:1","14.923:1","17.412:1"],a:2,e:"The main transmission gear ratio is 14.923:1 — reducing 5,898 RPM engine input to 395 RPM main rotor speed.",ref:"Ch.04 §2"},
{q:"What is the engine input drive speed to the MGB?",o:["4,200 RPM","5,000 RPM","5,898 RPM","6,500 RPM"],a:2,e:"The input drive speed from each engine to the MGB is 5,898 RPM.",ref:"Ch.04 §2"},
{q:"What is the tail rotor output speed?",o:["3,450 RPM","4,012 RPM","4,986 RPM","5,500 RPM"],a:2,e:"The tail rotor (Fenestron®) rotates at 4,986 RPM, derived from the MGB tail rotor output at a gear ratio of 1.183:1.",ref:"Ch.04 §2"},
{q:"What is the approximate mass of the EC135 MGB?",o:["95 kg","120 kg","143.5 kg","175 kg"],a:2,e:"The EC135 Main Gear Box (MGB) has a mass of approximately 143.5 kg.",ref:"Ch.04 §2"},
{q:"What oil type is used in the EC135 MGB?",o:["Mobil Jet Oil II","Aeroshell Turbine Oil 560","AirGO 3001","Castrol 5000"],a:2,e:"The EC135 main transmission uses AirGO 3001 oil. Using any other oil type is not approved.",ref:"Ch.04 §2"},
{q:"What is the MGB oil quantity?",o:["4.5 L","7.2 L","10.0 L","14.5 L"],a:2,e:"The MGB holds approximately 10.0 litres of AirGO 3001 oil.",ref:"Ch.04 §2"},
{q:"What material is the MGB casing made of?",o:["Steel alloy","Titanium","Magnesium alloy","Aluminium alloy"],a:3,e:"The MGB casing is made of aluminium alloy, providing good strength-to-weight ratio for the transmission housing.",ref:"Ch.04 §2"},
{q:"What is the purpose of the freewheel unit in the EC135 drivetrain?",o:["Limits maximum rotor speed","Allows the main rotor to spin freely in autorotation","Synchronises both engines","Transmits tail rotor drive"],a:1,e:"The freewheel (one-way clutch) allows the main rotor to decouple from the engines — enabling autorotation when both freewheels overrun.",ref:"Ch.04 §3"},
{q:"What is the function of ARIS?",o:["Automatic rotor speed control","Isolates MGB vibrations from the fuselage","Provides rotor brake force","Controls blade pitch in gusts"],a:1,e:"ARIS = Anti Resonance Isolation System. It mounts the MGB on tuned struts to attenuate rotor/MGB vibrations before they reach the fuselage.",ref:"Ch.04 §4"},
{q:"What is the purpose of the rotor brake?",o:["Slows the rotor in flight for autorotation","Stops the main and tail rotor after engine shutdown","Provides emergency stop in flight","Limits rotor speed during power checks"],a:1,e:"The rotor brake is used to stop the rotor system after the engines are shut down. It must NOT be used in flight.",ref:"Ch.04 §5"},
{q:"What makes the EC135 main rotor 'bearingless'?",o:["The rotor hub has no main shaft bearing","The flexbeam allows blade movement in all axes without conventional pitch/flap/lag bearings","The blades are attached without any hardware","The swashplate uses magnetic bearings"],a:1,e:"'Bearingless' means there are no conventional feathering, flap, or lag bearings at the blade root. The flexbeam provides all necessary flexibility without them.",ref:"Ch.04 §6"},
{q:"What are the MGB accessory drives used for?",o:["Cabin heating and pressurisation","Tail rotor control only","Hydraulic pumps and cooling fans","Electrical generators only"],a:2,e:"The MGB accessory drives (LH and RH) drive the hydraulic pumps and cooling fans for the transmission system.",ref:"Ch.04 §2"},
{q:"What is the tail rotor gear ratio?",o:["0.803:1","1.000:1","1.183:1","1.450:1"],a:2,e:"The tail rotor gear ratio is 1.183:1 at the TGB, resulting in 4,986 RPM Fenestron® speed from the MGB output.",ref:"Ch.04 §2"},
{q:"What connects each engine to the MGB input drives?",o:["Direct mechanical coupling","Hydraulic torque converters","Driveshafts with flexible couplings","Chain drives"],a:2,e:"Two driveshafts with flexible couplings connect each engine to the MGB. The flexible couplings absorb angular misalignment and shaft length changes.",ref:"Ch.04 §3"}
],
h:[
{q:"How is the 395 RPM main rotor speed calculated from the engine input?",o:["5,898 × 14.923 = 395 RPM","5,898 ÷ 14.923 = 395 RPM","395 × 14.923 = 5,898 RPM (same calculation)","It is a fixed setting not derived from gear ratio"],a:1,e:"Main rotor speed = Engine input speed ÷ gear ratio = 5,898 ÷ 14.923 = 395 RPM. Understanding this relationship is important for diagnosing Nr deviations.",ref:"Ch.04 §2"},
{q:"What happens to the second engine's freewheel unit when only one engine is running during ground run?",o:["It locks, preventing the MGB from overdriving it","It overruns — the second engine's drive does not engage until it reaches the same speed as the running engine","It is disabled by the FADEC","It causes a secondary input to the MGB"],a:1,e:"When only one engine is running, the other engine's freewheel overruns — it spins freely without transmitting torque. This allows one engine to drive the MGB while the other starts or remains shut down.",ref:"Ch.04 §3"},
{q:"What is the specific condition during autorotation in which both freewheels must overrun?",o:["Only one freewheel overruns; the other maintains drive","Both freewheels overrun simultaneously when rotor speed exceeds engine speed, allowing the rotor to drive without engine drag","Both freewheels lock to maintain rotor speed","Freewheels are bypassed by the FADEC in autorotation"],a:1,e:"During autorotation, rotor speed exceeds engine speed (windmilling or shutdown). Both freewheels overrun — decoupling the engines completely — so the rotor can spin freely with no drag from the engines.",ref:"Ch.04 §3"},
{q:"What physical mechanism does ARIS use to attenuate vibrations?",o:["Active piezoelectric actuators that cancel vibration","Passive rubber/metal isolation mounts (gearbox struts) tuned to the main rotor frequency","Fluid-filled viscous dampers","Magnetic levitation of the MGB"],a:1,e:"ARIS uses passive rubber/metal isolation mounts called gearbox struts. They are tuned (by design geometry and material stiffness) to absorb vibrations at the main rotor passing frequency before they enter the fuselage.",ref:"Ch.04 §4"},
{q:"Why must the rotor brake only be applied after the rotor RPM has decreased to the approved level?",o:["Applying at high RPM provides better braking force","The brake disc would overheat and warp at high RPM, and the mechanical loads could cause structural damage to the brake and drivetrain","The FADEC prevents brake application above idle","Rotor speed does not decrease quickly enough at full speed for the brake to be effective"],a:1,e:"At high Nr, the kinetic energy in the rotor system is enormous. Applying the brake at too high an RPM causes excessive heat in the disc (potentially to failure), and mechanical shock loads that can damage the brake caliper, disc, and drivetrain structure.",ref:"Ch.04 §5"},
{q:"What three axes of blade movement does the flexbeam accommodate?",o:["Pitch and flap only","Flap and lead-lag only","Pitch, flap, and lead-lag (all three)","Only torsional (pitch) movement"],a:2,e:"The flexbeam accommodates: (1) Flap — out-of-plane blade movement, (2) Lead-lag — in-plane blade movement, (3) Pitch — blade feathering for collective/cyclic control. All without conventional bearings.",ref:"Ch.04 §6"},
{q:"What is the function of the flexible couplings in the EC135 tail rotor drive train?",o:["They allow the tail boom to be detached for transport","They compensate for angular misalignment between MGB and TGB, and for fuselage/tail boom flexing during flight","They provide a freewheel function for the tail rotor","They act as torque limiters to protect the TGB"],a:1,e:"The flexible couplings in the drive train compensate for angular misalignment (manufacturing tolerances), differential thermal expansion, and dynamic bending of the tail boom in flight — preventing bending loads from being introduced into the drive shafts.",ref:"Ch.04 §3"},
{q:"What is the significance of the modular design of the EC135 MGB?",o:["It allows the MGB to be repaired only as a complete unit","Each sub-module (input drives, tail output, accessory drives) can be removed and replaced independently, reducing maintenance time and cost","Modular design means it cannot be overloaded","It allows the MGB to be shared between P-type and T-type EC135s"],a:1,e:"Modular design allows individual replacement of LH/RH input drive modules (with freewheel units), tail rotor output, and accessory drive gearboxes without replacing the entire MGB housing — significantly reducing maintenance cost and downtime.",ref:"Ch.04 §2"},
{q:"During OEI (one engine failure), what prevents the failed engine from being driven by the MGB?",o:["The FADEC closes the fuel valve, stopping engine rotation immediately","The freewheel unit on the failed engine's input drive overruns — it can only transmit power from engine to MGB, not the reverse","The rotor brake is automatically applied to the failed engine","The coupling shaft between failed engine and MGB is automatically disconnected"],a:1,e:"The freewheel is a one-way clutch. It can only transmit torque in the drive direction (engine → MGB). During OEI, the MGB spins faster than the failed engine (windmilling), so the freewheel overruns and the failed engine is decoupled.",ref:"Ch.04 §3"},
{q:"What would be the consequence if the ARIS system failed (struts became rigid)?",o:["The main rotor would stop","Significant increase in fuselage vibration levels; potential fatigue damage to the airframe and discomfort for occupants","No noticeable effect on flight","The MGB would overheat due to reduced cooling"],a:1,e:"Without ARIS isolation, main rotor 4/rev and MGB mesh frequencies would transmit directly to the fuselage. This causes high vibration levels that can fatigue airframe structure, damage avionics, and create severe crew/passenger discomfort.",ref:"Ch.04 §4"},
{q:"What colour markings on EC135 main rotor blades indicate they are approved for installation?",o:["No markings — all blades are interchangeable","Specific colour band markings that identify the approved blade type for the installed MGB configuration","Serial numbers only — no colour coding","Red tip caps indicate airworthiness"],a:1,e:"EC135 rotor blades have specific colour band markings that identify the approved blade type. It is critical to verify correct blade type/colour coding before installation, as incorrect blades could affect rotor balance and structural limits.",ref:"Ch.04 §6"},
{q:"What are the two stages of the MGB as described by ZF Friedrichshafen?",o:["A single-stage spiral bevel gear only","A two-stage flat gearbox (spiral bevel input stage + planetary output stage)","Two input stages only — one per engine","A two-stage planetary gearbox"],a:1,e:"The MGB is a two-stage flat gearbox manufactured by ZF Friedrichshafen: the first stage reduces engine speed through bevel gears, and the second stage provides the final reduction to the main rotor shaft.",ref:"Ch.04 §2"},
{q:"How does the pitch control cuff transmit collective input to the rotor blade?",o:["Via a mechanical push-pull rod directly attached to the blade tip","The cuff surrounds the flexbeam; rotation of the cuff by the swashplate control rod changes the pitch angle of the entire blade assembly","Through the flexbeam twisting under torsional load only","Via a hydraulic actuator inside each blade cuff"],a:1,e:"The pitch control cuff encases the outer end of the flexbeam. A push-pull rod from the rotating swashplate rotates the cuff, which changes the pitch angle of the blade. The cuff is the mechanical interface between the control system and the blade.",ref:"Ch.04 §6"},
{q:"What is the tail rotor gear ratio at the TGB (not the MGB output)?",o:["The TGB has a 1:1 ratio (no reduction)","The TGB gear ratio is 1.183:1","The TGB ratio is the same as the MGB main rotor ratio","The TGB provides a 90° bevel conversion only — no speed change"],a:1,e:"The TGB (Tail Gearbox) provides a gear ratio of 1.183:1 — a slight speed increase from the input shaft to the Fenestron® rotor shaft, in addition to changing the drive direction by 90°.",ref:"Ch.04 §2"},
{q:"What is the purpose of the weight compensation system on the collective control?",o:["Automatically adjusts CG","Reduces the pilot's physical effort required to hold or move the collective lever","Provides a safety stop preventing over-collective","Acts as an automatic trim system"],a:1,e:"The weight compensation system (a spring or counterweight mechanism) reduces the physical force the pilot must exert to hold the collective in position, preventing fatigue during long flights and reducing the workload during power changes.",ref:"Ch.04 §2"}
]
}

,

// ─────────────────────────────────────────
// CHAPTER 05 — Fuselage
// ─────────────────────────────────────────
{
m:[
{q:"How many doors does the EC135 have in total?",o:["4","5","6","8"],a:2,e:"The EC135 has 6 doors: 2 hinged crew doors (forward), 2 sliding passenger doors (mid), and 2 aft clamshell doors.",ref:"Ch.05 §3"},
{q:"What material is the EC135 tail boom made of?",o:["Sheet aluminium","Titanium","Composite material","Steel tube"],a:2,e:"The EC135 tail boom is made entirely of composite material, reducing weight while providing structural integrity.",ref:"Ch.05 §2"},
{q:"What is the primary structural material of the EC135 fuselage?",o:["Composite only","Sheet metal (aluminium)","Carbon fibre","Welded steel tube"],a:1,e:"The primary fuselage structure is sheet metal design. Composite panels are used for doors, tail boom, cabin frame, and cowlings.",ref:"Ch.05 §2"},
{q:"What type are the EC135 forward crew doors?",o:["Sliding","Gull-wing","Hinged (can be jettisoned)","Canopy-type"],a:2,e:"The two forward crew doors are hinged and can be jettisoned in an emergency by pulling the red release handle.",ref:"Ch.05 §3"},
{q:"What type are the EC135 passenger doors?",o:["Hinged","Sliding (rear-ward)","Clamshell","Gull-wing"],a:1,e:"The two passenger doors are sliding doors that slide rearward to open, providing a wide entry to the cabin.",ref:"Ch.05 §3"},
{q:"What coordinate standard is used for EC135 structural dimensions?",o:["NATO STANAG","LN 65619 metric (mm)","ICAO Annex 8","SAE AS 9100"],a:1,e:"EC135 frame coordinates are defined per LN 65619 — a German aviation standard — in the metric system (millimetres).",ref:"Ch.05 §1"},
{q:"What does 'FS' stand for in the EC135 coordinate system?",o:["Frame Structure","Fuselage Station","Forward Section","Fuel Station"],a:1,e:"FS = Fuselage Station — the longitudinal (X-axis) coordinate measuring distance from the reference datum.",ref:"Ch.05 §1"},
{q:"What provides access to fuel tank equipment?",o:["Four removable panels in the lower shell","A single hatch under the nose","Side panels in the cabin","The aft clamshell doors"],a:0,e:"Four removable equipment plates in the lower shell of the fuselage provide access to the fuel tanks and installed fuel system components.",ref:"Ch.05 §4"},
{q:"What are the aft clamshell doors used for?",o:["Engine access","Pilot entry","Rear compartment access (cargo/litter)","Avionics access"],a:2,e:"The two aft clamshell doors open rearward to provide access to the rear cargo compartment, used for cargo, litter/stretcher loading, or mission equipment.",ref:"Ch.05 §3"},
{q:"What material are the engine cowlings made of?",o:["Sheet aluminium","Titanium","Composite material","Fiberglass only"],a:2,e:"Engine cowlings are made of composite material. They open upward and are held open by gas struts for engine access.",ref:"Ch.05 §4"},
{q:"What is BL in the EC135 coordinate system?",o:["Bearing Line","Buttline — lateral distance from aircraft centreline","Boom Length","Base Level"],a:1,e:"BL = Buttline — the Y-axis coordinate measuring lateral distance from the aircraft centreline (positive to the right).",ref:"Ch.05 §1"},
{q:"What is WL in the EC135 coordinate system?",o:["Wing Level","Weight Limit","Waterline — vertical distance from a datum","Width Line"],a:2,e:"WL = Waterline — the Z-axis coordinate measuring vertical distance. WL 0 is located 1,505 mm below a reference datum.",ref:"Ch.05 §1"},
{q:"How is the crew door jettisoned in an emergency?",o:["Push the door outward forcefully","Pull the red release handle — the door falls away from the aircraft","Unscrew the hinge bolts","Push the yellow emergency push-pad"],a:1,e:"The crew door jettison is activated by pulling the red handle on the door, which releases the hinge mechanisms and allows the door to fall away from the aircraft.",ref:"Ch.05 §3"},
{q:"Which ATA chapters cover EC135 doors and cabin structure?",o:["ATA 21 and 24","ATA 32 and 33","ATA 52 and 53","ATA 71 and 73"],a:2,e:"Doors are covered by ATA 52, Cabin Structure by ATA 53 in the EC135 AMM.",ref:"Ch.05 §2"},
{q:"What composite areas are found in the EC135 fuselage structure?",o:["Only the tail boom","Doors, tail boom, cabin frame, engine cowlings, and nose access panel","Engine mounts and MGB deck only","All structure except the subfloor"],a:1,e:"Composite panels are used for: cabin frame, bottom shell, all doors, engine cowlings, nose access panel, and the entire tail boom.",ref:"Ch.05 §2"}
],
h:[
{q:"Why does the EC135 use a combination of sheet metal and composite materials rather than all-composite?",o:["Composite is too expensive for the entire airframe","Sheet metal provides cost-effective primary structure with well-understood fatigue properties; composites provide weight saving and corrosion resistance in non-primary panels","Regulatory requirements mandate metal primary structure for CS-27 aircraft","Composite cannot be used near fuel tanks"],a:1,e:"Sheet metal provides predictable, well-characterised structural behaviour for primary frames under dynamic helicopter loads. Composites are used where weight saving and corrosion resistance are priority (doors, tail boom, fairings) without compromising primary structural integrity.",ref:"Ch.05 §2"},
{q:"What is the waterline WL 0 datum referenced to?",o:["The cabin floor level","The main rotor hub axis","1,505 mm below a structural reference datum","Ground level with the helicopter on standard landing gear"],a:2,e:"WL 0 is defined as a plane 1,505 mm below the structural reference datum per LN 65619. This provides a consistent reference for vertical measurements throughout the aircraft.",ref:"Ch.05 §1"},
{q:"Why are there four fuel access panels rather than a single large hatch?",o:["Four panels are required by CS-27","Multiple smaller panels maintain more subfloor structural integrity while still providing access to all tank/equipment positions","Four panels reduce the chance of contamination","One panel per fuel pump — the layout mirrors the pump arrangement"],a:1,e:"Multiple smaller removable panels preserve more of the subfloor structural box section. Cutting one large opening would require significant structural reinforcement. Four panels distribute the access across the structure while maintaining overall floor stiffness.",ref:"Ch.05 §4"},
{q:"What forces do the tail boom composite structure need to withstand in normal flight?",o:["Only bending from tail rotor thrust","Torsion, bending (from tail rotor thrust and mass), and vibration from drive shaft rotation","Only tension from the tail unit mass","Compression loads from rotor wake"],a:1,e:"The tail boom carries: (1) Bending moments from tail rotor anti-torque thrust and tail unit mass, (2) Torsional loads from tail rotor torque reaction, (3) Dynamic loads from driveshaft rotation, and (4) Vibration from Fenestron® operation.",ref:"Ch.05 §2"},
{q:"What structural requirement does the crew door jettison system satisfy?",o:["Cost-effective door removal for maintenance","Emergency evacuation from water or inverted crash — crew can exit if the door jams on a distorted frame","Weight reduction by removing heavy hinges","FAR Part 27 requirement for convertible configuration"],a:1,e:"EASA CS-27 requires that crew (and key emergency exits) can be opened even if the fuselage is distorted in a crash. Jettison capability ensures the door can be shed even when frame distortion prevents normal opening.",ref:"Ch.05 §3"},
{q:"Why do the engine cowlings open upward (held by gas struts) rather than hinge downward?",o:["Upward opening is required by ATA 54","Upward opening provides a stable working platform and prevents cowlings from contacting ground equipment; gas struts hold them open without requiring a separate locking device","Downward opening would exceed the helicopter's turning radius","Upward opening allows faster engine removal"],a:1,e:"Upward-opening cowlings with gas struts: keep the cowling clear of personnel working at engine level, prevent accidental closure during maintenance (gas strut holds it open), and avoid the cowling contacting GSE or the fuselage lower section.",ref:"Ch.05 §4"},
{q:"What is the significance of the avionics bay being in the nose compartment?",o:["For aerodynamic reasons only","Nose location keeps avionics cool in the nose airflow, provides easy ground access without a ladder, and positions electronics forward of the CG for balance","Nose position is required by Helionix® architecture","To keep weight aft for hover stability"],a:1,e:"Nose-mounted avionics: (1) Ram air cooling from forward flight, (2) Low-level access for line maintenance without ground support equipment, (3) Weight contribution forward of CG helps longitudinal balance, (4) Short harness runs to antenna locations.",ref:"Ch.05 §4"},
{q:"If a sliding passenger door is jammed and cannot slide, what alternative exit is available on that side?",o:["No alternative — jammed door is an emergency","The hinged crew door on the same side can be used","The clamshell doors can be opened from inside","There are no alternate exits on the same side"],a:1,e:"If the sliding pax door jams, the crew door on the same side provides an alternative exit. Crew door jettison capability also provides emergency exit. This redundancy is required by CS-27 emergency exit provisions.",ref:"Ch.05 §3"},
{q:"What is the structural reason for the semi-monocoque design vs. a pure monocoque design?",o:["Semi-monocoque is lighter in all cases","Pure monocoque requires very thick skin to resist all loads alone; semi-monocoque uses internal frames/stringers to share loads, allowing thinner skin and lower total weight with better damage tolerance","Monocoque is not allowed by CS-27","Semi-monocoque allows faster production"],a:1,e:"In a pure monocoque, the skin carries all loads — requiring thick, heavy skin. Semi-monocoque uses internal frames, bulkheads, and stringers to redistribute loads, allowing thinner skin. This achieves better strength-to-weight ratio and improved damage tolerance (a crack in the skin doesn't propagate through the entire structure).",ref:"Ch.05 §2"},
{q:"What is the purpose of the fuselage subfloor structure?",o:["Houses the avionics bay","Provides the primary load path for landing gear forces and fuel tank support","Is only a cosmetic floor panel","Carries the tail boom attachment loads"],a:1,e:"The subfloor structure is the primary structural element that: (1) Carries and distributes landing gear vertical loads into the fuselage frames, (2) Supports the fuel bladder tanks, (3) Provides the fuel access panel mounting, and (4) Transfers CG-area loads to the cabin structure.",ref:"Ch.05 §2"},
{q:"What is the purpose of the sliding door design (vs. hinged) for passenger entry?",o:["Sliding requires fewer components than hinged","Sliding doors do not swing out into the rotor downwash, do not require clearance area alongside the helicopter, and provide a wider entry opening","Sliding doors are lighter than hinged doors","CS-27 mandates sliding doors for passenger transport category"],a:1,e:"Sliding doors: (1) Cannot be blown open or closed by rotor downwash, (2) Don't require lateral clearance (useful in confined landing areas), (3) Provide maximum opening width equal to the door panel width, (4) Cannot be opened inadvertently by wind loads during cruise flight.",ref:"Ch.05 §3"},
{q:"Why is LN 65619 used rather than an ICAO or FAA standard for EC135 dimensions?",o:["LN 65619 provides metric units while ICAO uses imperial","LN 65619 is the German industrial standard (Luftfahrtnorm) applicable to the original German manufacturer — Bölkow/MBB/Eurocopter tradition","ICAO standards only apply to fixed-wing aircraft","EC135 predates all international coordinate standards"],a:1,e:"LN 65619 is a German aviation dimensional standard (Luftfahrtnorm) inherited from the MBB/Bölkow design tradition. The EC135 design originated in Germany, and the coordinate system follows German aerospace standards.",ref:"Ch.05 §1"},
{q:"What maintenance consideration applies to composite areas (doors, tail boom) vs. sheet metal areas?",o:["Composite repairs are always faster and cheaper","Composite areas require different inspection methods (visual/tap test) and repair procedures; metal areas allow standard riveting/welding — technicians must be trained for both","Composite and metal areas use identical repair procedures","Composite areas are 'life items' and cannot be repaired"],a:1,e:"Composite repairs require specialized techniques (bonding, prepregs, vacuum bagging), different inspection methods (tap test, thermography, ultrasonic), and materials. Standard metal repair techniques (drilling, riveting) cannot be applied to composite. Technicians require composite repair qualification.",ref:"Ch.05 §2"},
{q:"What is the consequence if the door jettison is inadvertently activated in flight?",o:["The door is held by a secondary latch and does not fall","The door departs the aircraft, creating an asymmetric opening that causes airflow turbulence and possible structural stress","The door folds back against the fuselage","The AFCS automatically compensates for the drag change"],a:1,e:"Inadvertent jettison in flight causes the door to separate from the aircraft. This creates sudden airflow change, potential door-rotor strike risk if the door is deflected up, asymmetric drag, possible loss of crew/passenger, and damage to horizontal stabilizer or tail rotor.",ref:"Ch.05 §3"},
{q:"What is the purpose of the nose access panel?",o:["Provides pilot entry from forward","Gives access to the avionics bay (Helionix® computers, radio racks, antenna connections)","Covers the pitot-static system only","Is a jettison panel for emergency nose egress"],a:1,e:"The nose access panel (composite) provides maintenance access to the nose avionics bay, where AMCs, AHRS, ADC, communication radios, and their antenna connections are installed.",ref:"Ch.05 §4"}
]
},

// ─────────────────────────────────────────
// CHAPTER 06 — Tail Unit
// ─────────────────────────────────────────
{
m:[
{q:"How many blades does the EC135 Fenestron® have?",o:["8","10","12","14"],a:1,e:"The Fenestron® has 10 blades with uneven spacing, rotating inside the vertical fin housing.",ref:"Ch.06 §1"},
{q:"What type of gearbox is the EC135 TGB?",o:["Planetary gearbox","Spur gear gearbox","Right-angle bevel gearbox","Worm drive gearbox"],a:2,e:"The TGB (Tail Gearbox) is a right-angle bevel gearbox that changes the drive direction 90° from the tail boom drive shaft to the Fenestron® rotor shaft.",ref:"Ch.06 §4"},
{q:"What feature reduces the tonal noise of the EC135 Fenestron®?",o:["Composite blade material","Variable pitch operation","Uneven (non-uniform) blade spacing","Acoustic lining in the shroud"],a:2,e:"Uneven blade spacing distributes aerodynamic pulses across multiple frequencies instead of one dominant tone, significantly reducing the Fenestron® noise signature.",ref:"Ch.06 §1"},
{q:"What is the horizontal stabilizer on the EC135 tail unit?",o:["Fixed — non-adjustable","Adjustable (variable incidence)","Automatically controlled by the AFCS","Removed on some variants"],a:1,e:"The EC135 horizontal stabilizer is adjustable — its incidence angle can be set on the ground to optimise pitch trim for different loading configurations.",ref:"Ch.06 §2"},
{q:"Can the EC135 tail unit be separated from the fuselage?",o:["No — it is a fixed permanent structure","Yes — it can be detached as a complete unit","Only the tail boom cone can be removed","Only the Fenestron® housing can be separated"],a:1,e:"The tail unit (tail boom, cone, horizontal stabilizer, vertical fin with Fenestron®, TGB) can be separated from the fuselage as a complete unit for transport or major maintenance.",ref:"Ch.06 §2"},
{q:"What does the Fenestron® shroud contribute aerodynamically?",o:["Creates downwash similar to the main rotor","Generates additional anti-torque thrust and reduces induced losses","Acts as a vertical stabilizer only","Protects the Fenestron® from blade-vortex interaction"],a:1,e:"The Fenestron® duct (shroud) acts as a diffuser: it generates additional thrust by recovering kinetic energy from the airflow through the duct, improving anti-torque efficiency — especially at higher speeds.",ref:"Ch.06 §1"},
{q:"Where is the TGB oil level checked?",o:["Via the MFD VMS page only","Through a sight glass and drain plug accessible on the TGB body","Via a dipstick in the vertical fin","Through the Helionix® oil monitoring system"],a:1,e:"The TGB has its own oil supply. A sight glass and drain plug are accessible on the TGB body for preflight oil level checks and oil servicing.",ref:"Ch.06 §4"},
{q:"What is routed through the tail boom to the TGB?",o:["Hydraulic lines only","Fuel lines and electrical cables only","Drive shafts and the tail rotor control cable","Only the Fenestron® control cable"],a:2,e:"The tail boom contains the tail rotor drive shafts (forward, centre, aft) and the Flexball control cable from the pedals to the Fenestron® pitch actuator.",ref:"Ch.06 §3"},
{q:"What is the forward drive shaft connected to in the tail rotor drive train?",o:["Directly to the Fenestron® from the MGB","From the MGB tail rotor output to the first flexible coupling","From the TGB to the Fenestron® directly","From the accessory gearbox to the tail boom"],a:1,e:"The forward drive shaft runs from the MGB tail rotor output to the first flexible coupling at the fuselage/tail boom junction.",ref:"Ch.06 §3"},
{q:"What failure could result from not checking TGB oil level during preflight?",o:["Increased fuel consumption","TGB bearing failure leading to loss of anti-torque (Fenestron® failure)","Reduced rotor speed only","Increased noise from the tail unit"],a:1,e:"Low TGB oil level causes bearing and gear surface lubrication failure. This leads to overheating, rapid wear, and potential TGB seizure — resulting in loss of anti-torque control, which is a serious emergency.",ref:"Ch.06 §4"},
{q:"What advantage does the Fenestron® have over a conventional tail rotor in terms of safety?",o:["Higher maximum anti-torque thrust","The blades are enclosed in a protective shroud, reducing risk to personnel and FOD damage","Lower maintenance requirements","Simpler hydraulic control system"],a:1,e:"The Fenestron® shroud encloses the blades completely, protecting ground personnel from the rotating blades and protecting the tail rotor from foreign object damage (FOD) and ground strikes.",ref:"Ch.06 §1"},
{q:"What are the components of the tail unit structure?",o:["Tail boom only","Tail boom, tail boom cone, horizontal stabilizer, vertical fin, TGB, and fairings","Tail boom and TGB only","Fenestron® and TGB only"],a:1,e:"The tail unit consists of: tail boom (composite), tail boom cone, adjustable horizontal stabilizer, vertical fin (houses Fenestron®), TGB, and aerodynamic fairings.",ref:"Ch.06 §2"},
{q:"What is the centre drive shaft in the tail rotor drive train?",o:["A flexible coupling only","The main drive shaft running through the tail boom from the forward coupling to the TGB input","The shaft from TGB to the Fenestron® rotor","The shaft from engine to MGB"],a:1,e:"The centre drive shaft is the main drive shaft routed through the tail boom, connecting the first flexible coupling to the TGB input (aft drive shaft).",ref:"Ch.06 §3"},
{q:"What provides the Nr (rotor RPM) signal for monitoring?",o:["The FADEC computer","A sensor on the main rotor hub shaft","The engine N2 signal only","The hydraulic pump pressure sensor"],a:1,e:"An Nr sensor on the main rotor hub shaft sends RPM data to the AMC for processing, display on the FND, and for alerting (low Nr warning).",ref:"Ch.06 §5"},
{q:"What does the TGB separate from the main MGB oil system?",o:["Nothing — they share the same oil","The TGB has its own independent oil supply, separate from the MGB","The TGB uses grease, not oil","The TGB uses the engine oil system"],a:1,e:"The TGB has its own oil supply, completely independent of the MGB oil system. This requires separate level checks and servicing.",ref:"Ch.06 §4"}
],
h:[
{q:"Why does the Fenestron® achieve better anti-torque efficiency at higher forward speeds?",o:["Higher disc loading at speed","The duct (shroud) generates increasing thrust as ram air enters the intake at higher speeds, supplementing the blade thrust","Blade pitch is automatically increased at speed","Centrifugal forces increase blade twist at higher RPM"],a:1,e:"At higher forward speeds, ram pressure increases at the Fenestron® intake, increasing mass flow through the duct. The duct itself acts as a diffuser, generating additional thrust proportional to forward speed — so Fenestron® efficiency increases with speed, unlike a conventional tail rotor which loses efficiency in translational flight.",ref:"Ch.06 §1"},
{q:"What is the consequence of a TGB failure in flight?",o:["Slight reduction in tail rotor RPM only","Loss of anti-torque — the helicopter will yaw uncontrollably due to main rotor torque reaction without corrective tail rotor thrust","Only loss of Nr indication","Loss of Fenestron® noise reduction only"],a:1,e:"Loss of anti-torque means the main rotor torque reaction cannot be balanced. The helicopter will spin (yaw) continuously in the direction opposite to rotor rotation. This is a critical emergency requiring immediate autorotation to a landing.",ref:"Ch.06 §4"},
{q:"Why is the Fenestron® blade spacing uneven — what frequency-domain effect does this achieve?",o:["Uneven spacing balances mass to prevent vibration","Uneven spacing distributes the aerodynamic blade passage pulses across many frequencies instead of concentrating energy at one dominant blade-passing frequency, drastically reducing tonal noise","Uneven spacing increases thrust coefficient","It prevents resonance at one rotor speed only"],a:1,e:"Even blade spacing produces a strong fundamental tone at blade-passing frequency (10 × RPM) and harmonics. Uneven spacing breaks this periodicity, spreading the energy across the frequency spectrum. The result is dramatically lower tonal noise — particularly important near populated areas.",ref:"Ch.06 §1"},
{q:"What happens to the tail rotor drive shafts during in-flight tail boom bending?",o:["They are rigid and prevent tail boom bending","Flexible couplings accommodate shaft angular misalignment caused by tail boom deflection, preventing bending stress from entering the shafts","The shafts automatically align via the TGB","Tail boom bending has no effect on the drive shafts"],a:1,e:"In flight, aerodynamic loads and dynamic vibrations cause the tail boom to flex slightly. Without flexible couplings, this would introduce bending moments into the drive shafts, potentially causing fatigue failure. The flexible couplings absorb these angular displacements.",ref:"Ch.06 §3"},
{q:"The horizontal stabilizer on the EC135 is described as 'adjustable.' When would this adjustment be made?",o:["Automatically by AFCS during flight to control pitch","On the ground only, to optimise longitudinal trim for specific loading (CG) configurations","By the pilot in flight using a trim switch","It adjusts automatically with collective position"],a:1,e:"The horizontal stabilizer incidence is set on the ground (maintenance action) to optimize longitudinal pitch trim for the typical loading configuration. It is not adjusted during flight. Incorrect setting would cause the aircraft to require persistent nose-up or nose-down cyclic in cruise.",ref:"Ch.06 §2"},
{q:"What is the relationship between the Fenestron® control cable and the hydraulic system?",o:["The Flexball cable replaces the hydraulic actuator entirely — no hydraulics for tail rotor","The Flexball cable transmits mechanical pedal input to the EHA (Electro-Hydraulic Actuator) inside the Fenestron® stator — hydraulics provide the force","The tail rotor has no hydraulic actuator","The control cable pressurises the TGB housing"],a:1,e:"The Flexball cable routes the mechanical pedal displacement to the EHA (Electro-Hydraulic Actuator) inside the Fenestron® stator hub. The pilot's pedal input tells the EHA where to move; the hydraulics provide the force to change blade pitch.",ref:"Ch.06 §3"},
{q:"Why is the TGB oil system separate from the MGB?",o:["To allow different oil types to be used","Physical separation and different oil volumes/pressures; a TGB oil failure must not affect MGB function, and vice versa","To simplify maintenance by having independent servicing points","Required by ZF Friedrichshafen manufacturing specification"],a:1,e:"Physical isolation of oil systems means: (1) A TGB oil leak cannot drain the MGB, (2) TGB oil can be at different quantity/temperature than MGB, (3) A TGB oil-related failure affects only anti-torque, not the main rotor drive — crew can potentially manage a TGB oil issue while maintaining main rotor power.",ref:"Ch.06 §4"},
{q:"What is the aerodynamic function of the vertical fin that houses the Fenestron®?",o:["Provides lift like a wing in forward flight","Acts as a weathervane and provides directional stability; at cruise speeds generates yaw moment that reduces Fenestron® power requirement","Provides only structural support for the TGB","Is purely a maintenance access structure"],a:1,e:"The vertical fin provides natural weathervane stability. At cruise speeds it generates a yaw moment that partially offsets the main rotor torque — reducing the anti-torque demand on the Fenestron®, saving power. This synergy between fin and Fenestron® is a key EC135 efficiency feature.",ref:"Ch.06 §2"},
{q:"What is the purpose of the tail boom cone (aft fairing)?",o:["Houses the emergency locator transmitter (ELT)","Provides an aerodynamic fairing closing the aft end of the tail boom, reducing drag and protecting the TGB from direct airstream","Provides structural attachment for the horizontal stabilizer","Contains the tail rotor fuel shutoff valve"],a:1,e:"The tail boom cone is a composite aerodynamic fairing that closes the aft end of the tail boom structure, smooths airflow around the TGB mounting, reduces form drag, and protects the TGB from direct airstream erosion.",ref:"Ch.06 §2"},
{q:"During an Nr (rotor RPM) low warning, what is the crew's concern regarding the tail unit?",o:["TGB oil pressure will drop proportionally","Low Nr means Fenestron® RPM is also low — anti-torque authority may be reduced at low rotor speed","The horizontal stabilizer becomes ineffective","The Fenestron® drive shaft will disengage at low RPM"],a:1,e:"Since Fenestron® speed is driven by the MGB (proportional to Nr), a low Nr condition also means lower Fenestron® speed and reduced anti-torque authority. The pilot must manage yaw more carefully and recover Nr to maintain full control authority.",ref:"Ch.06 §5"},
{q:"If the Nr sensor on the main rotor hub shaft fails, what happens to the rotor speed indication?",o:["Nr is no longer displayed and the FLI shows dashes or fault indication; the crew must monitor other indicators","The AFCS automatically corrects for the loss","Nr is provided by a backup sensor in the MGB oil pump","Nr continues to display from engine N2 speed"],a:1,e:"If the Nr sensor fails, rotor speed indication is lost from that source. The Helionix® system annunciates the sensor fault and the FLI may show dashes or a caution. The crew must use other cues (aural Nr tone, N2 correlation) to monitor rotor speed.",ref:"Ch.06 §5"},
{q:"Why are there three drive shaft segments in the tail rotor drive train rather than one long shaft?",o:["One long shaft would be too heavy","Multiple shorter shafts are easier to manufacture","Critical speed (whirling) requirements, tail boom flex accommodation, and assembly/maintenance access — a single long unsupported shaft would be prone to whirling resonance and difficult to install/remove","Three shafts provide redundancy — if one fails, the others continue"],a:1,e:"Multiple shaft segments: (1) Each segment is shorter, raising its critical (whirling) speed above the operating range, (2) Flexible couplings between segments accommodate tail boom flex, (3) Each segment can be accessed/replaced independently during maintenance.",ref:"Ch.06 §3"},
{q:"What certification requirement does the shrouded Fenestron® design address that a conventional tail rotor does not?",o:["CS-27 requires shrouded tail rotors for all helicopters above 1,500 kg","EASA CS-27 personnel protection requirements — the shroud ensures rotating components are not exposed to inadvertent contact by ground personnel","FAA requires Fenestron® for over-water operations","There is no specific certification advantage — the Fenestron® is purely for noise"],a:1,e:"EASA CS-27 has provisions for personnel protection around rotating components. The Fenestron® shroud provides inherent physical guarding of the rotating blades, meeting personnel safety requirements that would otherwise require additional guards on a conventional tail rotor installation.",ref:"Ch.06 §1"},
{q:"What is the sequence of drive components from MGB to Fenestron® in the correct order?",o:["MGB → flexible coupling → TGB → drive shafts → Fenestron®","MGB → forward shaft → flexible coupling → centre shaft → aft shaft → TGB → Fenestron®","MGB → aft shaft → TGB → centre shaft → Fenestron®","MGB directly drives TGB via the tail boom structure"],a:1,e:"Complete sequence: MGB tail rotor output → forward drive shaft → flexible coupling → centre drive shaft → aft drive shaft → TGB (90° bevel gear) → Fenestron® rotor shaft.",ref:"Ch.06 §3"},
{q:"How does low Fenestron® blade pitch affect anti-torque output?",o:["Lower pitch produces more thrust (higher airspeed through duct)","Lower pitch reduces the angle of attack of the blades, reducing thrust output and therefore reducing the yaw moment against main rotor torque","Blade pitch has no effect — only RPM matters","Lower pitch prevents cavitation of the duct airflow"],a:1,e:"Anti-torque thrust is directly related to blade pitch angle (which sets the angle of attack and the pressure differential across the blades). Low pitch = low thrust = reduced yaw moment. The pilot applies pedal to increase blade pitch and anti-torque force.",ref:"Ch.06 §1"}
]
},

// ─────────────────────────────────────────
// CHAPTER 07 — Flight Control
// ─────────────────────────────────────────
{
m:[
{q:"What type of cable is used to route tail rotor control from pedals to the Fenestron®?",o:["Push-pull rigid rod","Flexball-type cable","Aircraft control cable with pulleys","Hydraulic line"],a:1,e:"A Flexball-type cable routes through bends in the tail boom with minimal friction, transmitting pedal input to the Fenestron® EHA actuator.",ref:"Ch.07 §4"},
{q:"What does LVDT stand for and what does it measure?",o:["Linear Valve Distribution Transducer — controls hydraulic flow","Linear Variable Differential Transducer — converts control position to electrical signal","Load Vibration Detection Transmitter — detects overload","Lateral Velocity Data Transmitter — measures airspeed"],a:1,e:"LVDT = Linear Variable Differential Transducer. It converts the mechanical position of the control inputs into electrical signals used by the AFCS.",ref:"Ch.07 §2"},
{q:"What is the function of the Mixing Unit?",o:["Mixes hydraulic fluid from both systems","Combines all three control inputs before reaching the hydraulic actuators","Splits electrical power to trim actuators","Blends engine thrust between left and right engines"],a:1,e:"The Mixing Unit mechanically combines collective, cyclic pitch, and cyclic roll inputs so that each input is sent to the correct hydraulic actuator without cross-coupling.",ref:"Ch.07 §3"},
{q:"How many hydraulic main rotor actuators does the EC135 have?",o:["2","3","4","6"],a:1,e:"There are 3 dual (tandem) main rotor actuators, one for each control axis (fore-aft, left-right, and mixed collective).",ref:"Ch.07 §3"},
{q:"Where is the tail rotor EHA (Electro-Hydraulic Actuator) located?",o:["At the forward end of the tail boom","Inside the Fenestron® stator hub","At the TGB output shaft","On the aft fuselage bulkhead"],a:1,e:"The EHA for tail rotor pitch control is located inside the Fenestron® stator hub, directly at the pitch change mechanism.",ref:"Ch.07 §4"},
{q:"What does the cyclic stick control?",o:["Collective pitch of all blades (altitude)","Individual blade pitch sequentially","Pitch (fore-aft) and roll (left-right) attitude via tilting the rotor disc","Yaw (heading) only"],a:2,e:"The cyclic stick controls pitch attitude (fore-aft) and roll attitude (left-right) by tilting the main rotor disc.",ref:"Ch.07 §1"},
{q:"What does the collective lever control?",o:["Blade pitch on each blade sequentially","Pitch attitude of the helicopter","Simultaneous pitch angle of all blades — controls altitude and power","Only rotor speed"],a:2,e:"The collective lever simultaneously increases or decreases pitch on all main rotor blades, changing the lift generated and controlling altitude/vertical speed.",ref:"Ch.07 §1"},
{q:"What do the anti-torque pedals control?",o:["Cyclic roll","Engine fuel flow","Fenestron® blade pitch — controls yaw (heading)","Landing gear extension/retraction"],a:2,e:"The anti-torque pedals control the pitch angle of the Fenestron® blades — changing anti-torque thrust and therefore controlling the helicopter's yaw (heading).",ref:"Ch.07 §1"},
{q:"How does the trim system work in the EC135 flight controls?",o:["Trim tabs on the rotor blades","Parallel electric actuators that reposition the control datum","Separate hydraulic trim circuit","Weight-and-balance fuel transfer"],a:1,e:"The trim system uses parallel electric actuators (SEMAs) that move the control input datum position. Pilots use 4-way trim switches on the cyclic to adjust trim.",ref:"Ch.07 §2"},
{q:"What is a parallel actuator (SEMA) in the flight control system?",o:["An actuator that provides the main control force","An electric motor that repositions the trim (datum) position without removing pilot authority","A hydraulic backup actuator","A mechanical lock for the controls"],a:1,e:"A parallel (trim) actuator is an electric motor connected in parallel with the control input. It moves the control datum to remove any steady-state force required by the pilot, without preventing pilot override.",ref:"Ch.07 §2"},
{q:"What prevents control cross-coupling (e.g., a collective input causing an unwanted cyclic pitch change)?",o:["The AFCS corrects for it electronically","The Mixing Unit mechanically separates and correctly routes each control input","Separate hydraulic circuits for each axis","The pilot manually compensates"],a:1,e:"The Mixing Unit ensures that each control axis input is correctly resolved and routed to the three actuators. Without it, a collective input would cause unintended cyclic effects.",ref:"Ch.07 §3"},
{q:"What provides position feedback from the flight controls to the AFCS?",o:["Pressure transducers in the hydraulic lines","LVDTs (Linear Variable Differential Transducers) on each control axis","The FADEC torque signal","Blade tip sensors"],a:1,e:"LVDTs are installed on each control axis (collective, cyclic pitch, cyclic roll) to convert mechanical position into electrical signals — providing the AFCS with accurate control position feedback.",ref:"Ch.07 §2"},
{q:"What type of actuator is used for the Fenestron® EHA?",o:["Mechano-Hydraulic Actuator (MHA)","Pneumatic actuator","Electro-Hydraulic Actuator (EHA)","Direct electric servo"],a:2,e:"The Fenestron® uses an Electro-Hydraulic Actuator (EHA) whose valve spool is controlled by electrical signals from the AFCS and pilot pedal input.",ref:"Ch.07 §4"},
{q:"What is the friction brake on the collective used for?",o:["Emergency rotor stop","Holding collective position against aerodynamic forces without pilot effort","Locking collective during engine start","As a trim system backup"],a:1,e:"The collective friction brake provides adjustable resistance to hold the collective lever in position, reducing pilot workload during steady-state flight conditions.",ref:"Ch.07 §2"},
{q:"What is the centering device on the cyclic?",o:["A mechanical stop at full deflection","A spring-loaded device providing centre-feel to the cyclic stick","An electric motor that holds cyclic at centre","The AFCS ATT mode engagement"],a:1,e:"A spring-loaded centering device in the cyclic gives the pilot a 'feel' for the neutral position and a centring force, improving control precision and reducing inadvertent inputs.",ref:"Ch.07 §2"}
],
h:[
{q:"Why does the EC135 use a Flexball cable rather than push-pull rods for the tail rotor control?",o:["Push-pull rods are too heavy for the tail boom","The Flexball cable can route through the curved tail boom without significant friction, whereas a rigid push-pull rod system would require complex bellcrank arrangements at every bend","Flexball cables provide hydraulic boost","Push-pull rods cannot transmit the high forces required"],a:1,e:"The tail boom is curved and requires the control run to change direction multiple times. A Flexball cable (inner cable within a flexible conduit) handles this routing naturally with minimal friction. A push-pull rod system would need heavy, complex bellcrank linkages at each direction change.",ref:"Ch.07 §4"},
{q:"What is 'cross-coupling' in helicopter flight controls and how does the Mixing Unit prevent it?",o:["Cross-coupling is electrical interference between avionics — prevented by shielded wiring","Cross-coupling is the unintended effect of one control axis on another. The Mixing Unit mathematically resolves all three inputs so each actuator receives only the correct combined signal","Cross-coupling is engine torque affecting rotor speed — corrected by FADEC","Cross-coupling is vibration transmission — prevented by ARIS"],a:1,e:"Cross-coupling: a collective input changes the angle of attack at all three actuators equally, which if fed directly would also change the cyclic attitude. The Mixing Unit is a mechanical computer that resolves collective, pitch, and roll inputs into the correct actuator displacements with no cross-axis contamination.",ref:"Ch.07 §3"},
{q:"What is the difference between a 'series' actuator and a 'parallel' (trim) actuator in the SAS/AFCS context?",o:["Series actuator provides higher force; parallel provides position","Series actuators (EHAs in the direct path) add corrections to pilot inputs; parallel actuators (SEMAs) reposition the trim datum — both affect control but at different authority levels","There is no functional difference","Series are for main rotor; parallel are for tail rotor only"],a:1,e:"Series actuators (EHAs) are in the direct control path — they add small, fast corrections to pilot inputs for SAS damping. Parallel (trim) actuators (SEMAs) reposition the zero-force point (datum) — they remove steady-state offsets without adding to or subtracting from pilot authority.",ref:"Ch.07 §2"},
{q:"What happens to flight control authority if one hydraulic system fails?",o:["Full authority is lost — manual reversion only","Control authority is unchanged — the remaining hydraulic system maintains full actuator force on the tandem pistons","Authority is reduced by 50% — careful handling required","Only tail rotor control is affected"],a:1,e:"Each main rotor actuator has tandem (dual) pistons — one per hydraulic system. Each system alone provides sufficient force for full control authority. Loss of one system does NOT reduce control authority or require special handling techniques.",ref:"Ch.07 §3"},
{q:"What happens when a SEMA (trim actuator) fails?",o:["Complete loss of control on that axis","That axis loses AFCS upper-mode (trim) authority but retains full pilot authority; the SAS (EHA) continues to operate","The AFCS automatically uses the other axis SEMA to compensate","The FADEC reduces power to reduce control demands"],a:1,e:"A SEMA failure means the AFCS can no longer trim that control axis (the pilot must hold force or AFCS disengages from that axis). But the pilot retains full manual control, and the SAS EHA continues providing rate-damping — safe flight is maintained.",ref:"Ch.07 §2"},
{q:"How does the weight compensation system on the collective affect OEI performance?",o:["It has no effect on OEI — purely a comfort feature","In OEI the collective is typically raised, increasing the upward force needed; weight compensation partially offsets this, reducing the physical effort the pilot needs to sustain the higher power setting","Weight compensation locks the collective during OEI to prevent overtorque","It automatically raises the collective to OEI power setting"],a:1,e:"During OEI, the pilot typically holds the collective at a higher setting (increased power) for an extended time. Without weight compensation, this requires continuous significant upward force. The weight compensation reduces this effort, critical during a high-workload OEI emergency.",ref:"Ch.07 §2"},
{q:"Why are there 3 main rotor actuators rather than a single large actuator?",o:["Redundancy only — any one of the three could control the rotor alone","Three actuators allow independent control of collective (all rise/fall), longitudinal cyclic (fore-aft tilt), and lateral cyclic (left-right tilt) via the swashplate geometry","Three actuators share the load to reduce each actuator's size","Regulatory requirement — CS-27 mandates triple redundancy"],a:1,e:"The swashplate has three attachment points. Moving all three together changes collective. Moving one relative to the others changes cyclic. This 3-point geometry means three independent actuators are needed to provide the mechanical degrees of freedom for independent cyclic and collective control.",ref:"Ch.07 §3"},
{q:"If the Flexball cable for tail rotor control jams, what effect does this have on controllability?",o:["Only a slight increase in pedal forces","Loss of tail rotor pitch control — the Fenestron® is fixed at whatever pitch it was when the jam occurred, with no ability to control yaw","The AFCS automatically compensates via the SAS","The FADEC reduces power to prevent yaw divergence"],a:1,e:"A jammed Flexball cable means Fenestron® blade pitch is fixed. If fixed at zero pitch: no anti-torque, helicopter spins. If fixed at some pitch: helicopter yaws at a fixed rate unless speed/power adjusted. This requires immediate autorotation and emergency landing.",ref:"Ch.07 §4"},
{q:"What is the purpose of the 4-way trim switch on the cyclic grip?",o:["Controls the engine manual override mode","Allows the pilot to electrically move the cyclic trim datum to remove steady-state forces","Engages the AFCS approach mode","Controls the SAS gain setting"],a:1,e:"The 4-way trim switch drives the cyclic SEMAs to reposition the trim datum in the desired direction. This removes any residual force the pilot must hold in level flight, reducing workload and fatigue.",ref:"Ch.07 §2"},
{q:"How does the collective LVDT provide information to the AFCS that is different from the cyclic LVDTs?",o:["Collective LVDT measures position from zero-pitch reference; cyclic LVDTs measure displacement from the trim datum in two axes","They provide identical signals — no functional difference","Collective LVDT provides speed data; cyclic LVDTs provide position data","Collective LVDT is analogue; cyclic LVDTs are digital"],a:0,e:"The collective LVDT measures absolute position from the low-pitch stop (full down collective = reference). Cyclic LVDTs measure displacement in the pitch and roll axes from the current trim datum position. These different reference points provide the AFCS with accurate position data for both vertical and horizontal manoeuvring.",ref:"Ch.07 §2"},
{q:"What is the 'torsion tube' construction used in both the collective and cyclic controls?",o:["A rubber isolation tube preventing vibration","A hollow shaft that transmits torque (rotational input) along its length — it is the primary load-carrying member of the control input linkage","A tube filled with hydraulic fluid for damping","A composite over-wrap on steel control rods"],a:1,e:"The torsion tube (also called the shaft) is a hollow structural tube that transmits rotational inputs from the pilot's hands/feet to the mixing unit. It is the primary structural member of the control column — stiff against bending, designed to transmit torsional loads.",ref:"Ch.07 §2"},
{q:"Why does the tail rotor use a single EHA while the main rotor uses three dual MHAs?",o:["Cost reduction — fewer actuators on the tail rotor","The tail rotor has only one degree of freedom (collective pitch only); the main rotor needs three independent actuators for its 3-point swashplate. Dual pistons (tandem) provide main rotor hydraulic redundancy; the EHA provides tail rotor electrical redundancy","The EHA is more powerful than three MHAs combined","The Flexball cable cannot drive multiple actuators"],a:1,e:"Tail rotor pitch has ONE degree of freedom — increase/decrease blade pitch. One actuator suffices. Main rotor requires 3 actuators for 3-point swashplate control (collective + 2-axis cyclic). Main rotor actuators are DUAL (tandem) for hydraulic redundancy — tail rotor EHA uses the single hydraulic system.",ref:"Ch.07 §3"},
{q:"What would happen if the Mixing Unit were to malfunction and transmit a cyclic input as a collective change?",o:["No effect — the AFCS would correct it","All three main rotor actuators would move in the same direction (collective change) instead of the intended tilting motion — causing unintended altitude change without the expected pitch/roll response","The FADEC would reduce power to prevent the response","The rotor brake would automatically engage"],a:1,e:"A Mixing Unit malfunction that mislabels cyclic as collective would cause an unintended altitude/power change when the pilot makes a cyclic input. The expected pitch or roll response would be absent. This is a serious malfunction requiring immediate reference to emergency procedures.",ref:"Ch.07 §3"},
{q:"How does the spring centering device in the cyclic differ from the AFCS ATT (attitude hold) mode?",o:["There is no difference — the spring IS the ATT mode","The spring gives feel to the control but makes no active correction — it always returns toward centre. ATT mode uses the SEMAs to actively maintain the attitude at whatever angle was set when engaged","The spring is electrically controlled; ATT is mechanical","ATT mode uses a separate spring within the AFCS unit"],a:1,e:"The spring centering is passive — it always pulls toward a fixed mechanical neutral, regardless of aircraft attitude or flight conditions. ATT mode is an active, closed-loop system — it measures actual aircraft attitude via AHRS and commands SEMAs to maintain whatever attitude was set when ATT was engaged.",ref:"Ch.07 §2"},
{q:"What safety feature prevents the AFCS from overriding the pilot through the SEMA trim actuators?",o:["A shear pin in each SEMA breaks under pilot force","The pilot can always override the SEMAs — they have limited authority and the pilot's mechanical input can always move the controls regardless of SEMA position","The AFCS automatically disengages when the pilot applies force","SEMAs are locked when the pilot's hands are on the controls"],a:1,e:"SEMAs are parallel actuators with limited travel (authority). The pilot can always physically override the SEMA output because the pilot's mechanical input and the SEMA input sum together — a strong pilot input overcomes the SEMA. This 'soft' authority ensures the pilot always has final control.",ref:"Ch.07 §2"}
]
},

// ─────────────────────────────────────────
// CHAPTER 08 — Hydraulic System
// ─────────────────────────────────────────
{
m:[
{q:"How many hydraulic pressure supply systems does the EC135 have?",o:["1","2","3","4"],a:1,e:"The EC135 has 2 identical, independent hydraulic pressure supply systems — both active simultaneously.",ref:"Ch.08 §1"},
{q:"What drives the EC135 hydraulic pumps?",o:["Dedicated electric motors","The main engines directly","The MGB LH and RH accessory gearboxes","Battery-powered hydraulic motors"],a:2,e:"The hydraulic pumps are driven by the LH and RH accessory gearboxes — part of the main transmission — providing hydraulic power whenever the rotors are turning.",ref:"Ch.08 §2"},
{q:"How many main rotor actuators does the EC135 hydraulic system power?",o:["2","3","4","6"],a:1,e:"There are 3 dual (tandem) main rotor actuators. Each actuator has two pistons — one powered by each independent hydraulic system simultaneously.",ref:"Ch.08 §2"},
{q:"What type of actuator is used for the main rotor?",o:["EHA (Electro-Hydraulic Actuator)","MHA (Mechano-Hydraulic Actuator)","Pneumatic actuator","Linear electric actuator"],a:1,e:"MHA = Mechano-Hydraulic Actuator. Its valve spool is directly operated mechanically by pilot control rod input — no electrical signal required.",ref:"Ch.08 §3"},
{q:"What type of actuator is used for the tail rotor?",o:["MHA (Mechano-Hydraulic Actuator)","Manual cable-operated actuator","EHA (Electro-Hydraulic Actuator)","Dual MHA"],a:2,e:"EHA = Electro-Hydraulic Actuator. The tail rotor EHA valve spool is operated by electrical signal (AFCS + pilot pedal input via LVDT).",ref:"Ch.08 §3"},
{q:"Can the EC135 be controlled safely with only one hydraulic system operating?",o:["No — dual systems required at all times","Yes — one system alone provides full control authority","Only for the tail rotor","Only in cruise — not in hover"],a:1,e:"If one hydraulic system fails, the remaining system powers one piston in each tandem main rotor actuator — providing full control authority for safe flight and landing.",ref:"Ch.08 §1"},
{q:"What does a HYDR SYS 1 CAUTION message indicate?",o:["Both hydraulic systems have failed","Hydraulic system 1 pressure supply has failed — controls remain fully operative on system 2","Hydraulic fluid temperature is too high","A hydraulic leak has been detected"],a:1,e:"HYDR SYS 1 (or 2) CAUTION means that one pressure supply has failed. Full control is maintained on the remaining system. The aircraft should land as soon as practicable.",ref:"Ch.08 §4"},
{q:"Where are the hydraulic supply system components located?",o:["In the nose avionics bay","Mounted on top of LH and RH MGB accessory gearboxes","Under the cabin floor","In the tail boom"],a:1,e:"The two hydraulic supply systems are mounted on top of the LH and RH MGB accessory gearboxes — integrating pump, reservoir, and pressure regulation in the transmission compartment.",ref:"Ch.08 §2"},
{q:"What is the purpose of the hydraulic test procedure?",o:["Sets hydraulic pressure to flight levels","Verifies correct operation of both hydraulic systems on the ground — checks pressure, leaks, and actuator response","Replaces the annual hydraulic fluid change","Tests the rotor brake only"],a:1,e:"The pre-flight hydraulic test procedure verifies correct operation of both systems: confirming supply pressure, checking for leaks, and verifying actuator response before committing to flight.",ref:"Ch.08 §4"},
{q:"What is a 'tandem' (dual) actuator in the EC135 hydraulic system?",o:["Two separate actuators mechanically linked","A single actuator body with two independent piston chambers — one powered by each hydraulic system","An actuator with two output rods","A backup actuator that engages on main failure"],a:1,e:"A tandem actuator has two pistons in one housing. Each piston is powered by a separate hydraulic system. Both pistons act together for full output force; either alone provides full output force if the other system fails.",ref:"Ch.08 §3"},
{q:"What provides cockpit indication of hydraulic system status?",o:["A dedicated hydraulic pressure gauge only","Pressure indicators on the instrument panel, VMS page on MFD, and CAUTION messages in the Master List","Only the W/U warning light","A hydraulic hour meter"],a:1,e:"Hydraulic status is displayed on pressure indicators, the VMS system page on the MFD, and through CAUTION messages in the Helionix® Master List.",ref:"Ch.08 §4"},
{q:"How does the MHA valve spool receive its control input?",o:["From the AFCS AMC via electrical signal","Directly and mechanically from the pilot control rod","From the LVDTs via electrical signal","From hydraulic pilot pressure"],a:1,e:"The MHA valve spool is directly operated by mechanical input from the pilot control rod — the pilot's physical control movement opens or closes the valve to port hydraulic fluid to the actuator piston.",ref:"Ch.08 §3"},
{q:"Why are both hydraulic systems active simultaneously rather than one active and one standby?",o:["To double the available control force for manoeuvrability","Both systems active means each system carries only half the load — reducing wear; and no switchover transient if one fails","To simplify the hydraulic logic","Required for tail rotor actuation only"],a:1,e:"Both systems active simultaneously: (1) Each carries half the load in each actuator, extending component life, (2) No switchover delay or transient if one system fails — the remaining system already has full authority immediately, (3) Both systems are continuously monitored in their operating state.",ref:"Ch.08 §1"},
{q:"Where are the main rotor actuators located?",o:["Inside the MGB","On the forward side of the MGB","In the landing gear bay","On the rotor hub"],a:1,e:"The three main rotor actuators are mounted on the forward side of the MGB, directly below the swashplate input points.",ref:"Ch.08 §2"},
{q:"What action should the crew take when a HYDR SYS caution illuminates?",o:["Immediately enter autorotation","Shut down both engines","Land as soon as practicable — full control is maintained on the remaining system","Switch to manual reversion controls"],a:2,e:"A single hydraulic system failure (HYDR SYS CAUTION) means full control is maintained. The crew should land as soon as practicable to avoid a situation where the second system also fails.",ref:"Ch.08 §4"}
],
h:[
{q:"Why does each main rotor actuator use tandem pistons (one per hydraulic system) rather than having a dedicated actuator per system?",o:["Tandem pistons are lighter than two separate actuators","Single tandem unit ensures both systems act on exactly the same control point with the same geometry — two separate actuators would require complex synchronisation to prevent control binding","Regulatory requirement","Tandem pistons provide twice the force of separate actuators"],a:1,e:"If two separate actuators were used on the same control point, any slight differential in output (due to pressure variation or wear) would create opposing forces, causing binding or control fight. A tandem unit ensures both pistons act collinearly on the same output rod, with either piston able to carry the full load if the other system fails.",ref:"Ch.08 §3"},
{q:"What is the significance of the MHA not requiring electrical input for main rotor control?",o:["It allows the AFCS to work without power","In a complete electrical failure, the pilot retains full manual hydraulic control of the main rotor — the mechanical control rod directly operates the valve","It reduces the number of electrical connections to the transmission compartment","The FADEC can use the MHA as a backup engine control"],a:1,e:"The MHA's purely mechanical operation means: COMPLETE electrical failure → both hydraulic pumps continue running (MGB-driven) → pilot's physical control inputs still operate the MHA valve → full main rotor control is maintained. This is a critical safety feature for electrical emergency scenarios.",ref:"Ch.08 §3"},
{q:"If both hydraulic systems fail simultaneously, how can the pilot control the helicopter?",o:["Manual reversion — the control rods drive the swashplate directly without hydraulic assistance","It is impossible to control — immediate autorotation is required","The SAS EHA provides emergency hydraulic power","The AFCS SEMA actuators provide the remaining control force"],a:0,e:"The control rods are always mechanically connected to the swashplate even without hydraulics. However, without hydraulic boost, aerodynamic hinge moments at the swashplate require much higher physical force. Dual hydraulic failure is an extreme emergency — control may be possible but requires significant pilot strength and is difficult.",ref:"Ch.08 §1"},
{q:"What is the hydraulic pump input speed, and how does this relate to rotor speed?",o:["Hydraulic pumps run at a fixed speed independent of rotor speed","Hydraulic pumps are MGB accessory gearbox-driven — their speed is proportional to rotor speed (Nr). Lower Nr = lower pump speed = lower hydraulic pressure","Pumps run at engine speed only","Pumps are electrically driven and independent of Nr"],a:1,e:"Since pumps are MGB-driven, hydraulic pressure varies with Nr. At very low Nr (e.g., during autorotation or rotor wind-down), hydraulic pressure decreases. This is why hydraulic caution may appear at very low Nr — and why the rotor should not be slowed to very low Nr before shutting down.",ref:"Ch.08 §2"},
{q:"What is the potential failure mode if only one piston of a tandem actuator is functional and a significant sustained cyclic force is required?",o:["No failure mode — single piston provides full force indefinitely","With only one piston providing force (half the design redundancy), the remaining piston is working at full rated output. Sustained operation at full load accelerates wear and increases temperature — requiring inspection after any significant single-system operation","The actuator will jam after 15 minutes","The control automatically limits cyclic deflection"],a:1,e:"One-system operation of the MHA is certificated as safe for full control authority, but it increases the workload of the remaining piston. Prolonged operation in this state (especially in high-demand conditions) accelerates wear. This is why 'land as soon as practicable' is the correct action — not 'continue normal operations.'",ref:"Ch.08 §1"},
{q:"How does the EHA differ from the MHA in terms of redundancy architecture?",o:["EHA has no redundancy — single hydraulic channel only","EHA receives electrical input from the AFCS (which has dual AMC redundancy) but runs on a single hydraulic channel; MHA has mechanical input redundancy (both pilot and copilot inputs sum) plus dual hydraulic pistons","Both use identical redundancy architecture","MHA has no redundancy — purely mechanical"],a:1,e:"MHA: dual hydraulic redundancy (tandem pistons, 2 systems). EHA: single hydraulic system but electrical redundancy via dual AMC control paths. The tail rotor uses a single hydraulic system because the Fenestron® hydraulic actuator is in an inaccessible location, and the EHA architecture provides the required reliability through electronic redundancy.",ref:"Ch.08 §3"},
{q:"What is the purpose of pressure switches in the EC135 hydraulic system?",o:["Regulate pump output pressure","Detect and signal loss of hydraulic pressure to trigger CAUTION messages in the cockpit","Control the test procedure automatically","Open the tandem actuator bypass valve"],a:1,e:"Pressure switches continuously monitor each hydraulic system pressure. If pressure drops below a threshold (indicating pump failure, serious leak, or blockage), the switch signals the Helionix® AMC to generate the HYDR SYS 1/2 CAUTION message.",ref:"Ch.08 §4"},
{q:"Why would a hydraulic test be performed before an IFR flight but might be considered optional for a short VFR hop?",o:["IFR has higher hydraulic requirements than VFR","IFR flight involves higher workloads and flight into conditions where a hydraulic failure has higher consequences. Regulations typically require full systems checks before IFR. VFR flexibility exists in some operations, but the test remains highly recommended","Hydraulic pressure is only critical in cloud","VFR flights use lower hydraulic pressures"],a:1,e:"The pre-flight hydraulic test confirms correct operation before flight. For IFR, where the pilot cannot rely on visual references during an emergency, full systems confirmation is essential. Regulatory frameworks and operator procedures typically make this mandatory for IFR. Smart operators perform it regardless of flight rules.",ref:"Ch.08 §4"},
{q:"What happens to the tail rotor EHA if the hydraulic system feeding it fails?",o:["The Flexball cable provides direct mechanical control without hydraulics","Loss of hydraulic power to the EHA means loss of Fenestron® pitch control authority — tail rotor becomes fixed at current pitch","The EHA automatically switches to electric-only operation","The second MHA provides backup tail rotor control"],a:1,e:"The EHA requires hydraulic power to operate. If the single hydraulic system feeding the EHA fails, the actuator loses authority. The Fenestron® blade pitch is fixed at wherever the actuator was when pressure was lost. This is equivalent to a tail rotor control jam — an emergency requiring immediate autorotation.",ref:"Ch.08 §3"},
{q:"What is the specific advantage of both hydraulic pumps being MGB-driven (vs. engine-driven)?",o:["MGB-driven pumps are cheaper","Both pumps remain operative as long as the rotors are turning, regardless of whether one or both engines are running. This means hydraulic power is available through autorotation when both engines are off","Engine-driven pumps would require additional drive shafts","MGB-driven pumps have higher output pressure"],a:1,e:"MGB-driven pumps = hydraulic power available whenever Nr > minimum threshold. During autorotation (both engines failed), the rotors continue to drive the MGB, which drives the pumps — hydraulic control assistance is maintained throughout the autorotation and flare, giving the pilot full hydraulic-boosted control authority at the critical phase of an autorotation.",ref:"Ch.08 §2"},
{q:"During the hydraulic test procedure on the ground, what specific response verifies correct actuator function?",o:["The hydraulic fluid temperature must exceed 50°C","Each actuator must demonstrate smooth movement to full travel in both directions without binding, stiction, or pressure anomalies","Only pressure readings matter — actuator movement is not verified","The swashplate must remain perfectly stationary"],a:1,e:"The hydraulic test verifies: correct supply pressure, no abnormal pressure fluctuations, smooth full-range actuator movement, no binding or jerky motion, and no leaks. These checks together confirm that the hydraulic system will provide smooth, full-authority control response throughout the flight.",ref:"Ch.08 §4"},
{q:"What is the structural reason main rotor actuators are on the forward side of the MGB?",o:["For access during maintenance only","The swashplate is located below and forward of the MGB main rotor shaft — actuators positioned there have the shortest, most direct mechanical connection to the swashplate control points","Forward mounting reduces gyroscopic effects","Required by the Mixing Unit geometry"],a:1,e:"The swashplate is mounted on the main rotor shaft below the rotor head — positioned forward of the MGB body due to the shaft angle and transmission geometry. Mounting actuators directly below the swashplate attach points minimises control rod length, reducing play, friction, and potential for bending-induced inaccuracy.",ref:"Ch.08 §2"},
{q:"Why are the hydraulic reservoirs integrated with the pump units on the MGB rather than in a separate location?",o:["Weight reduction — removing separate reservoir lines","Integrated reservoir keeps suction lines (from reservoir to pump inlet) very short, minimising cavitation risk, reduces fluid temperature rise, and ensures constant fluid availability at the pump inlet even in unusual attitudes","Integration is cheaper to manufacture","Reservoir location in the transmission compartment provides external leak indication"],a:1,e:"Short suction lines prevent cavitation at high RPM. Integrated location ensures the fluid supply to the pump is always gravity-fed and immersion-fed regardless of aircraft attitude, critical during manoeuvres. Proximity to the MGB provides thermal mass that moderates fluid temperature.",ref:"Ch.08 §2"},
{q:"After a HYDR SYS 1 caution, what must the crew be concerned about for the NEXT hydraulic system?",o:["Nothing — one system is certified for indefinite flight","Loss of the remaining system would result in dual failure with very limited control authority. Crew must minimise time at risk by landing as soon as practicable, and avoid high-demand manoeuvres that stress the remaining system","The crew should immediately shut down the engine on the affected side","The AFCS must be disengaged to reduce hydraulic demand"],a:1,e:"After one system fails, the crew now has zero hydraulic redundancy. Any failure of the remaining system creates a critical emergency. Landing as soon as practicable is the correct action — not continuing the mission — because the single remaining system has no backup.",ref:"Ch.08 §4"}
]
},

// ─────────────────────────────────────────
// CHAPTER 09 — Landing Gear
// ─────────────────────────────────────────
{
m:[
{q:"What is the skid track width of the EC135?",o:["1.8 m","2.0 m","2.3 m","2.6 m"],a:2,e:"The EC135 landing gear has a skid track of 2.3 m, providing good lateral stability on the ground.",ref:"Ch.09 §2"},
{q:"How does the EC135 landing gear absorb touchdown impact?",o:["Hydraulic shock absorbers","Bending of the aluminium crosstubes","Rubber isolation mounts","Composite skid deformation"],a:1,e:"The crosstubes absorb landing impact by bending elastically. Bearing rings swivel in their brackets so forces go into crosstube bending, not the attachment fittings.",ref:"Ch.09 §2"},
{q:"What is the approximate maximum touchdown speed for the EC135?",o:["0.5 m/s","1 m/s","1.5 m/s","2 m/s"],a:1,e:"The maximum touchdown speed is approximately 1 m/s. Higher speeds cause permanent plastic deformation of the crosstubes.",ref:"Ch.09 §2"},
{q:"How many fittings attach the EC135 landing gear to the fuselage?",o:["2","3","4","6"],a:2,e:"The landing gear is attached through 4 fittings to the lower fuselage subfloor structure — one at each crosstube-fuselage connection point.",ref:"Ch.09 §1"},
{q:"What material are the EC135 crosstubes made of?",o:["Steel tube","Composite material","Titanium","Hollow aluminium"],a:3,e:"The crosstubes are made of hollow aluminium (circular cross section) — providing light weight with sufficient structural flexibility to absorb landing energy by bending.",ref:"Ch.09 §1"},
{q:"What is the purpose of bonding jumpers on the landing gear?",o:["Strengthen the skid-crosstube connection","Allow landing gear height adjustment","Discharge static electricity","Provide compass reference"],a:2,e:"Bonding jumpers provide an electrical path to discharge static electricity that builds up on the landing gear skids during flight.",ref:"Ch.09 §1"},
{q:"What optional equipment can be fitted for water operations?",o:["Inflatable floats (emergency flotation system)","Retractable wheels","Amphibious skids","Water jet propulsion"],a:0,e:"An emergency flotation system with inflatable floats can be fitted to the EC135 for over-water operations, allowing the helicopter to remain on the water surface after a forced landing.",ref:"Ch.09 §3"},
{q:"What are 'skid shoes' on the EC135 landing gear?",o:["Rubber anti-skid pads on the skid bottoms","Clamps that connect the skids to the crosstubes","Wheels fitted for ground manoeuvring","Flotation attachment points"],a:1,e:"Skid shoes are clamping connections between the aluminium skids and the aluminium crosstubes — they secure the skids without welding.",ref:"Ch.09 §1"},
{q:"What is the number of crosstubes on the EC135 landing gear?",o:["1","2","3","4"],a:1,e:"The EC135 has 2 aluminium crosstubes — one forward and one aft — mounted approximately 2 metres apart laterally.",ref:"Ch.09 §1"},
{q:"What is the consequence of exceeding the maximum touchdown speed?",o:["Engine flameout","Fuel tank puncture","Permanent plastic deformation of the crosstubes","Complete landing gear collapse"],a:2,e:"Exceeding approximately 1 m/s touchdown speed causes the crosstubes to permanently plastically deform beyond their elastic limit — they cannot spring back and must be inspected/replaced.",ref:"Ch.09 §2"},
{q:"What optional equipment protects the skids for operations in soft ground or sand?",o:["Snow skids","Settling protectors","Ground handling wheels","High gear version"],a:1,e:"Settling protectors can be fitted to prevent the skids from sinking into soft ground or sand, which could tip the helicopter or make departure difficult.",ref:"Ch.09 §3"},
{q:"What is the purpose of 'bearing rings' on the crosstubes?",o:["Provide a wear-resistant surface for the skid shoe clamps","Allow the crosstubes to swivel in their fuselage fittings so landing loads go into tube bending","Seal the hollow crosstube ends","Connect bonding jumpers to the crosstubes"],a:1,e:"Bearing rings on the crosstubes swivel in their fuselage bracket bearings. This allows the crosstubes to flex freely under landing loads, ensuring forces go into elastic tube bending rather than being transmitted as bending moments to the fuselage fittings.",ref:"Ch.09 §2"},
{q:"What is the purpose of snow skids as optional equipment?",o:["Reduce ground resonance on ice","Extended skids for operations on snow or ice surfaces where standard skid shoes would dig in","Provide flotation on snow","Replace skid shoes for cold weather"],a:1,e:"Snow skids are extended skid surfaces that distribute the helicopter's weight over a larger area on snow or ice, preventing the standard skid shoes from digging in or catching.",ref:"Ch.09 §3"},
{q:"What are the two types of aluminium components in the EC135 landing gear?",o:["Tubes and shoes","Crosstubes and skids","Crosstubes and attachment fittings","Skids and bonding jumpers"],a:1,e:"The EC135 skid landing gear consists of two main aluminium components: crosstubes (hollow, circular section) and skids (longitudinal running surfaces), connected by skid shoes.",ref:"Ch.09 §1"},
{q:"How many skids does the EC135 have?",o:["1","2","3","4"],a:1,e:"The EC135 has 2 aluminium skids — one on each side — clamped to the two crosstubes by skid shoes.",ref:"Ch.09 §1"}
],
h:[
{q:"Why do the crosstubes use a hollow circular cross section rather than a solid or rectangular section?",o:["Hollow circular section is cheaper to manufacture","A hollow circular tube has the highest torsional stiffness-to-weight ratio, and the circular section ensures equal bending stiffness in all directions — critical for multi-directional landing loads","Circular cross section allows the skid shoes to rotate on the tube","To allow the crosstube to be filled with emergency buoyancy foam"],a:1,e:"Hollow circular tubes are optimal for: (1) Bending in any plane (equal moment of inertia in all directions — important for landing loads from any angle), (2) High specific stiffness (stiff relative to weight), (3) Low weight for the required elastic energy absorption, (4) Simple attachment of skid shoes around the circular cross section.",ref:"Ch.09 §1"},
{q:"What is the engineering basis for the 1 m/s maximum touchdown speed limit?",o:["1 m/s is the maximum rotor downwash that provides ground effect","It is the speed at which the aluminium crosstube's elastic limit (yield stress) is reached. Above this, plastic deformation occurs — the crosstube cannot recover its original shape","1 m/s was chosen arbitrarily based on pilot feedback","It corresponds to a specific sink rate at MTOM on a hard surface"],a:1,e:"The 1 m/s limit is derived from materials engineering: the kinetic energy at that touchdown speed, converted to peak bending stress in the crosstube, equals the material's proof stress (elastic limit) at MTOM. Exceeding this causes permanent plastic set — the crosstube does not spring back to its original shape.",ref:"Ch.09 §2"},
{q:"What is the significance of the bearing ring allowing crosstube rotation in its bracket?",o:["It allows the landing gear to fold for transport","By allowing the crosstube end to rotate in the bracket, landing loads are resolved as pure bending in the crosstube tube body, not as bending moments at the fuselage attachment fitting — protecting the subfloor fittings from potentially fatigue-inducing moments","It allows adjustment of the skid track width","It provides vibration isolation between gear and fuselage"],a:1,e:"If the crosstube were rigidly clamped (no rotation), a hard landing would impose a bending moment at the clamp — potentially cracking the fuselage fitting or the crosstube at the clamp. The bearing ring allows the crosstube to rotate, converting the moment at the bracket to a pure bending deflection along the tube length — where it is designed to flex.",ref:"Ch.09 §2"},
{q:"What inspection is required after an exceedance of the maximum touchdown speed?",o:["No inspection required for a single exceedance","An AMM-specified inspection of the crosstubes, skid shoes, subfloor fittings, and fuel tank area to check for plastic deformation, cracks, or structural damage","Operational check only — check that landing gear feels symmetric","X-ray inspection of all structural frames"],a:1,e:"A hard landing (exceeding the structural speed or creating unusual loads) requires a formal hard-landing inspection per AMM procedures. This includes: measuring crosstube permanent set, checking all four subfloor attachment fittings for deformation or cracks, inspecting fuel bladder tanks for damage, and checking the entire subfloor structure.",ref:"Ch.09 §2"},
{q:"How does the emergency flotation system work in a forced landing on water?",o:["The floats inflate automatically on impact with water","The crew activates the flotation system prior to water impact — inflating floats with compressed gas. If automatic, a water-sensing trigger activates gas inflation before impact","The standard skids provide enough buoyancy","Water enters hollow crosstubes to provide buoyancy"],a:1,e:"The emergency flotation system has inflatable bags (floats) attached to the skids. Either manual activation (crew selects before water contact) or automatic water-sensor activation triggers compressed gas inflation. This must happen before impact to provide buoyancy that keeps the helicopter upright on the water surface.",ref:"Ch.09 §3"},
{q:"What is the consequence of a landing gear crosstube that has been permanently deformed?",o:["Only aesthetic damage — no structural consequence","The deformed crosstube has reduced elastic energy absorption capacity — it cannot absorb subsequent landing loads as designed. It may fracture in a subsequent normal landing. The crosstube must be replaced before next flight","The crosstube can be straightened in the field","Only heavy landings require crosstube replacement"],a:1,e:"Permanently deformed (plastically set) crosstubes have had their material loaded beyond yield. The metal has work-hardened in the deformed region and has reduced remaining ductility. The deformed geometry also changes the load distribution in subsequent landings. Replacement is mandatory — field straightening is not permitted.",ref:"Ch.09 §2"},
{q:"What is the purpose of the multipurpose carrier optional equipment?",o:["Extends fuel range","An underbelly hard-point attachment allowing special equipment (sensors, tanks, cargo pods) to be mounted below the fuselage","Provides additional seating","Is an alternative to the flotation system"],a:1,e:"The multipurpose carrier is an underbelly attachment system that provides a hard-point for external mission equipment such as sensor pods (FLIR, searchlight), auxiliary fuel tanks, or cargo containers.",ref:"Ch.09 §3"},
{q:"If a helicopter with emergency floats lands on hard ground, what must be checked before the next flight?",o:["Nothing — floats are designed for both water and hard landings","The floats and their attachment structure must be inspected for damage; landing on hard ground with inflated floats can overstress the float attachment points","The crosstubes must be replaced due to float interference","Only the FADEC system needs to be reset"],a:1,e:"Emergency floats are designed for water landings only. Hard ground contact with inflated floats can cause the floats to absorb ground loads outside their design envelope, potentially damaging float bags, straps, or the skid attachment structure. A full inspection per AMM is required.",ref:"Ch.09 §3"},
{q:"How does the EC135's 2.3 m skid track relate to its stability against lateral tip-over?",o:["Wider track reduces ground resonance frequency","The wider the track relative to CG height, the greater the tipping angle required before the CG passes outside the support base — providing resistance to lateral tip-over in crosswind landings and on sloping ground","2.3 m is the minimum track for CS-27 certification","Track width affects only the nose-tail balance"],a:1,e:"Tip-over stability is determined by the angle formed between the CG height and the support base half-width. For the EC135, the 2.3 m track and a CG height of approximately 1.0–1.2 m gives a substantial tip-over angle — providing good stability in crosswind landings, sloped terrain, and rotor downwash effects.",ref:"Ch.09 §2"},
{q:"Why do the skids have a curved (ski-jump) upswept nose rather than a flat front?",o:["Aesthetic design feature","The upswept nose prevents the skid from digging into soft surfaces, grass, snow, or gravel during run-on landings and ground manoeuvring — allowing the helicopter to slide smoothly rather than catch and tip","To reduce radar cross-section","To provide a mounting point for snow skids"],a:1,e:"During run-on landings (moving landings on unprepared surfaces), the upswept skid nose prevents the front edge from catching in the surface and causing the helicopter to pitch violently. It also allows smooth skidding during slope landings and ground handling with the helicopter low on skids.",ref:"Ch.09 §1"},
{q:"What is the structural consequence if only two of the four subfloor fittings are functional (e.g., two attachment bolts missing)?",o:["No consequence — the crosstubes provide redundancy","The load path is asymmetric — landing loads through the intact fittings are doubled, and bending moments are introduced into the subfloor structure that it was not designed to withstand — potential structural failure","The helicopter will lean to one side but can still fly","The AFCS will compensate for the asymmetric CG"],a:1,e:"The subfloor attachment fittings are designed for symmetric 4-point load distribution. Missing fittings means remaining fittings carry excess load (double or more) and bending moments, potentially causing fatigue cracking or immediate failure in a normal landing. This is a serious airworthiness discrepancy requiring immediate grounding.",ref:"Ch.09 §1"},
{q:"Medium or high gear versions of the landing gear are available. What operational reason would drive the choice of high gear?",o:["High gear is lighter and preferred for performance","High gear provides increased ground clearance — required when operating with external equipment (stretchers, skis, ground equipment) that extends below the fuselage, or for operations where the nose-down attitude of the standard gear is not acceptable","High gear has better flotation","High gear is required for hot and high operations"],a:1,e:"High gear (taller crosstubes) provides greater fuselage ground clearance, which may be required for: fitting certain external equipment below the fuselage, operations from rough or high-grass surfaces, or medical configurations with wide base-plate equipment.",ref:"Ch.09 §3"},
{q:"What is the purpose of the four bonding jumpers specifically (not just one total)?",o:["One per skid shoe for convenience","One per crosstube-to-fuselage attachment — ensuring all four contact points between gear and fuselage have a low-resistance electrical path to discharge static from any point of the landing gear","They provide structural redundancy","One per main rotor attachment point"],a:1,e:"Static electricity can accumulate at any point of contact between the helicopter and the ground during taxiing or from the atmosphere during flight. Four bonding jumpers (one per attachment fitting) ensure any static charge anywhere on the landing gear structure has a short, direct path to the airframe ground at the nearest attachment point.",ref:"Ch.09 §1"},
{q:"During a slope landing, what specific concern applies to the EC135 skid landing gear?",o:["Crosstubes may fold under lateral load on a slope","The higher-side skid bears less weight and may lift; if the slope exceeds the tip-over angle, the helicopter will tip over. Maximum slope for safe landing is defined in the AFM and depends on rotor thrust direction","Skids are designed to resist any slope angle","The AFCS prevents slopes exceeding 5°"],a:1,e:"On a slope, gravity pulls the CG toward the low side. If the slope angle causes the CG to pass beyond the low-side skid (outside the landing gear footprint), the helicopter tips over. The AFM defines maximum slope angles accounting for rotor thrust direction (which can assist or worsen stability depending on orientation to slope).",ref:"Ch.09 §2"}
]
}

,

// ─────────────────────────────────────────
// CHAPTER 10 — Fuel System
// ─────────────────────────────────────────
{
m:[
{q:"What type of fuel tanks does the EC135 use?",o:["Integral (wet bay) tanks","Aluminium rigid tanks","Bladder (flexible rubber) tanks","Composite pressure vessels"],a:2,e:"The EC135 uses bladder tanks — impact-resistant flexible cells made of reinforced rubberized nylon fabric, installed under the cabin floor.",ref:"Ch.10 §1"},
{q:"Why is the supply tank divided by a fence?",o:["To separate fuel types","To meet engine separation certification requirements","To improve CG range","To prevent fuel sloshing"],a:1,e:"The fence divides the supply tank into LH and RH sections so each engine is fed from its own dedicated section — an engine-feed separation certification requirement.",ref:"Ch.10 §1"},
{q:"How many boost pumps are in the EC135 fuel system?",o:["1","2","3","4"],a:1,e:"There are 2 boost pumps — one in each section of the split supply tank, powered from separate electrical buses.",ref:"Ch.10 §2"},
{q:"Where is fuel quantity displayed in the cockpit?",o:["Dedicated fuel gauge panel","VMS page on the MFD","Overhead panel","IESI standby instrument"],a:1,e:"Fuel quantity and fuel flow are displayed on the VMS (Vehicle Management System) page on the Helionix® MFD.",ref:"Ch.10 §3"},
{q:"What fueling methods does the EC135 support?",o:["Gravity only","Pressure only","Both gravity and pressure refueling","Only single-point pressure refueling"],a:2,e:"The EC135 supports both gravity refueling (via filler caps) and single-point pressure refueling through a connector on the fuselage.",ref:"Ch.10 §4"},
{q:"What fuel types are approved for the EC135?",o:["AVGAS 100LL only","Jet-A1 / JP-8 / Jet-A (per AFM)","Diesel and Jet-A1","Any aviation turbine fuel"],a:1,e:"Approved fuels are Jet-A1, JP-8, and Jet-A as specified in the AFM. Using incorrect fuel type is a serious airworthiness violation.",ref:"Ch.10 §4"},
{q:"What type of fuel quantity sensors does the EC135 use?",o:["Float-type sensors","Ultrasonic sensors","Capacitance-type transmitters","Mechanical dipsticks"],a:2,e:"Capacitance-type fuel quantity transmitters measure the dielectric change caused by fuel level in each tank cell.",ref:"Ch.10 §3"},
{q:"Where are the EC135 fuel tanks located?",o:["In the tail boom","In the engine nacelles","Under the cabin floor in the subfloor structure","Above the transmission deck"],a:2,e:"Both fuel tank cells (main tank and split supply tank) are located under the cabin floor in the fuselage subfloor area.",ref:"Ch.10 §1"},
{q:"What provides redundancy in the EC135 boost pump system?",o:["A backup electric pump in the main tank","Each pump is powered from a separate electrical bus","Both pumps share one bus but have separate fuses","A mechanical hand pump backup"],a:1,e:"The two boost pumps are powered from separate electrical buses, ensuring that a single bus failure cannot take out both pumps simultaneously.",ref:"Ch.10 §2"},
{q:"What is the LOW FUEL warning based on?",o:["Main tank level only","Both tanks combined level","Supply tank level dropping below a set threshold — approximately 30 minutes remaining","Engine fuel pressure drop"],a:2,e:"The low fuel CAUTION triggers when the supply tank drops below a set threshold, indicating approximately 30 minutes of flight remaining (condition-dependent).",ref:"Ch.10 §3"},
{q:"What is required before pressure refueling?",o:["Rotor must be running","Engines must be started first","Static grounding of the helicopter to the fuel truck","Crew must be on board"],a:2,e:"Static grounding is mandatory before pressure refueling to prevent static spark ignition of fuel vapour during the refueling process.",ref:"Ch.10 §4"},
{q:"What is the purpose of the optional auxiliary fuel tank?",o:["Emergency fuel reserve for OEI","Extended range operations (offshore, EMS, law enforcement)","Additional fuel for high-altitude operations only","Fuel for the combustion heater"],a:1,e:"An optional auxiliary fuel tank connects to the RH supply tank, extending range for long-range missions such as offshore, EMS, or law enforcement operations.",ref:"Ch.10 §1"},
{q:"What does the fuel shutoff valve do?",o:["Controls fuel flow rate to the engine","Allows crossfeed between tanks","Closes to cut fuel supply to that engine on emergency shutdown","Regulates fuel pump pressure"],a:2,e:"One fuel shutoff valve per engine closes on emergency shutdown, cutting the fuel supply from the tank to that engine's fuel control.",ref:"Ch.10 §2"},
{q:"What is the fuel flow path from the supply tank to the engine?",o:["Gravity feed → engine","Supply tank → boost pump → shutoff valve → engine fuel control","Main tank → crossfeed → engine directly","Supply tank → filter → FADEC → engine"],a:1,e:"Fuel flows: supply tank → boost pump → engine fuel shutoff valve → engine fuel control unit (FADEC-controlled).",ref:"Ch.10 §2"},
{q:"What monitoring does the fuel pressure switch provide?",o:["Fuel temperature monitoring","Detects boost pump failure and triggers a CAUTION message","Controls the crossfeed valve","Monitors fuel tank pressure"],a:1,e:"Pressure switches detect low fuel pressure (indicating boost pump failure) and trigger CAUTION messages in the Helionix® Master List.",ref:"Ch.10 §3"}
],
h:[
{q:"What is the structural and functional significance of the bladder tank design vs. integral tanks?",o:["Bladder tanks hold more fuel for the same volume","Bladder tanks are self-sealing on impact (the flexible material closes small punctures), prevent fuel leaks in crash scenarios, and can be removed and replaced without structural modification to the bay","Bladder tanks are lighter than integral tanks","Integral tanks are not approved for helicopters"],a:1,e:"Bladder tanks provide crashworthiness: the flexible material absorbs deformation without fracturing, and self-sealing properties can prevent fire after impact. Integral tanks (wet bays) in the structural box would spill fuel in any structural deformation — unacceptable for a low-flying helicopter.",ref:"Ch.10 §1"},
{q:"Why must the supply tank fence remain intact for certification compliance?",o:["The fence provides structural support for the tank bay","CS-27 engine separation requirements mandate that a single failure (fuel tank fault, pump failure) cannot deprive BOTH engines of fuel simultaneously — the fence ensures LH/RH isolation","The fence prevents fuel sloshing that would affect CG","The fence is required for pressure refueling"],a:1,e:"CS-27 requires that no single failure can cause loss of power to both engines simultaneously. The supply tank fence physically isolates LH and RH sections — a leak, pump failure, or contamination on one side cannot affect the other engine's fuel supply.",ref:"Ch.10 §1"},
{q:"What happens to engine fuel supply if a boost pump fails?",o:["Engine immediately flames out","Engine suction-feeds directly from the tank — most turboshaft engines can suction-feed for a limited time, but the FADEC generates a CAUTION and reduced performance may occur at altitude","The crossfeed valve automatically opens","Fuel shuts off immediately to prevent contamination"],a:1,e:"Turboshaft engine fuel systems can typically suction-feed (engine-driven fuel pump draws fuel without the boost pump), but only reliably at low altitude. The boost pump provides positive pressure to prevent vapour lock at altitude. A CAUTION is generated, and continued operation without boost pump is altitude-limited per the AFM.",ref:"Ch.10 §2"},
{q:"During a crossfeed operation, which engine can be supplied from which tank?",o:["Only LH engine can crossfeed to RH tank","Either engine can be supplied from either tank side using the crossfeed capability","Crossfeed only works on the ground","Only the main tank can crossfeed — supply tank has no crossfeed"],a:1,e:"The crossfeed capability allows either engine to be supplied from either side of the split supply tank. This is used when one side is imbalanced or one boost pump has failed — ensuring both engines remain fuelled from the available supply.",ref:"Ch.10 §2"},
{q:"Why are the boost pump electrical buses kept separate?",o:["To allow one pump to be turned off in normal operations","A single electrical bus failure (short circuit, overcurrent trip) cannot simultaneously disable both boost pumps — one pump always remains available if one bus fails","To allow different voltage ratings for each pump","Separate buses provide higher total current capacity"],a:1,e:"Single-point failure protection: if one DC bus shorts or trips its protection, only the pump on that bus is affected. The other bus (and pump) continues to operate. This is critical for flight safety — losing both boost pumps simultaneously could be catastrophic.",ref:"Ch.10 §2"},
{q:"What is the safety precaution regarding fuel quantity after pressure refueling?",o:["Check is not required — the single-point system prevents overfill","Always verify fuel quantity on the VMS page after refueling — do not rely on the refueling panel totalizer alone, as sensor errors can occur","Quantity check is only required before OEI training","Wait 5 minutes for fuel to settle before checking"],a:1,e:"After pressure refueling, visually and electronically verify actual fuel quantity on the VMS MFD page. Refueling systems can malfunction, over-fill (potential structural overload or contamination from vented overflow), or under-fill. Never take an assumed quantity for granted.",ref:"Ch.10 §4"},
{q:"What is the consequence of overfilling an EC135 fuel tank?",o:["No consequence — overflow vents prevent any issue","Overfilling can cause tank pressure during flight expansion (heat), potential structural deformation of the bladder, fuel venting through overflow channels, and potential contamination of fuel system components","Only causes fuel imbalance","The low-fuel warning prevents overfill from being detected"],a:1,e:"Overfilling: (1) Thermal expansion at altitude pressurizes the tank beyond design limits, (2) Fuel may vent through overflow channels into the lower fuselage, (3) If large enough, excess fuel affects weight and CG, (4) Overflow into bilge area creates fire risk.",ref:"Ch.10 §4"},
{q:"The capacitance fuel quantity system measures a physical property of the fuel. What property and what could cause measurement errors?",o:["Measures fuel weight — errors caused by fuel density changes","Measures the dielectric constant of the fuel/air mixture. Errors caused by: different fuel types (different dielectric constant), water contamination, or extreme temperature variation","Measures fuel electrical resistance — errors from contamination only","Measures fuel pressure head — errors from attitude"],a:1,e:"Capacitance sensors measure the electrical capacitance between two plates immersed in the fuel. The dielectric constant of jet fuel differs from air, so fuel level changes capacitance. Errors occur when: fuel type changes (different dielectric constant), water is present (high dielectric constant), or temperature significantly changes fuel density.",ref:"Ch.10 §3"},
{q:"Why is static grounding mandatory before pressure refueling and not strictly required for gravity refueling?",o:["Pressure refueling uses AC power; gravity uses DC","During pressure refueling, high-flow fuel through metal nozzles generates significant static charge that can spark at the fuel/air interface, potentially igniting vapour. Gravity refueling generates less static due to lower flow velocity","Static grounding is required for both — the question contains an error","Gravity refueling uses grounded filler caps that automatically dissipate static"],a:1,e:"Pressure refueling (high velocity through nozzles and fittings) generates significant triboelectric charge. This charge can discharge as a spark at the fuel cap or nozzle, potentially igniting fuel vapour. Gravity refueling at lower flow rates generates proportionally less static, but bonding is still good practice.",ref:"Ch.10 §4"},
{q:"What specific scenario requires the use of the auxiliary fuel tank?",o:["Any flight longer than 1 hour","Specifically long-range missions where standard fuel endurance is insufficient — offshore sector flying, EMS standby, or extended law enforcement patrol","Only allowed in training flights","Required when one engine is inoperative"],a:1,e:"The auxiliary tank extends endurance/range for specific operational requirements where standard fuel capacity is insufficient. It is connected to the RH supply tank section. All weight and CG implications of the additional fuel must be computed per the AFM weight and balance data.",ref:"Ch.10 §1"},
{q:"What is the role of the engine fuel control unit in relation to the boost pump?",o:["The FADEC controls boost pump speed","The engine's own fuel pump (driven by the engine accessory gearbox) draws fuel from the supply line — boost pump provides positive pressure at the inlet to prevent vapour lock and ensure reliable supply at altitude","The boost pump and engine fuel control are the same unit","The fuel control unit replaces the boost pump at altitude"],a:1,e:"The engine has its own driven fuel pump that provides metering and high-pressure delivery to the fuel nozzles. The boost pump upstream provides low-pressure positive feed to the engine pump's inlet — preventing cavitation and vapour lock, ensuring reliable priming during start and at altitude.",ref:"Ch.10 §2"},
{q:"Why does the supply tank overflow channel connect to the main tank?",o:["For emergency fuel transfer from main to supply","When the supply tank is filled past capacity, overflow channels route excess fuel to the main tank, preventing pressure buildup in the supply tank during refueling","To allow bidirectional fuel transfer in flight","To equalise CG between tanks"],a:1,e:"During refueling, the supply tank fills first. Overflow channels route excess fuel into the main (forward) tank, filling the entire system without requiring a separate refueling connection for the main tank.",ref:"Ch.10 §1"},
{q:"What operational consideration applies to flying with fuel imbalance between LH and RH supply tank sections?",o:["Fuel imbalance has no effect on the EC135","A significant LH/RH fuel imbalance creates a lateral CG offset that requires constant lateral cyclic to counteract, increasing pilot workload and potentially limiting the available cyclic range","The AFCS automatically transfers fuel to equalise tanks","Fuel imbalance only affects MTOM calculation"],a:1,e:"LH/RH supply tank sections feed independently. If one section is significantly heavier (more fuel), it creates a lateral CG offset. This requires lateral cyclic offset in hover and cruise, reducing available cyclic in that direction. AFM provides fuel imbalance limits.",ref:"Ch.10 §1"},
{q:"What is the minimum fuel quantity required before each flight and where is this defined?",o:["At least 30 minutes at best endurance speed — defined in regulations","Minimum fuel for the planned flight plus reserves as defined in the AFM, applicable regulations (SERA/EASA OPS), and the operator's operations manual","Any quantity above the LOW FUEL caution threshold","Full tanks are always required"],a:1,e:"Minimum fuel requirements are layered: AFM defines minimum fuel for specific operations (OEI reserves, etc.), EASA regulations define reserve fuel requirements (30 min VFR, contingency + final reserve IFR), and operator's ops manual may impose additional requirements.",ref:"Ch.10 §3"},
{q:"What happens if contaminated fuel (water, dirt) enters the EC135 fuel system?",o:["The boost pump filters all contaminants","Contaminants can block fuel filters (causing low fuel pressure, CAUTION, potential engine flameout if severe), damage fuel control components, or cause engine instability. Contaminated fuel requires immediate fuel system flush per AMM","The FADEC detects contamination and shuts the engine down safely","Contaminants settle to the tank bottom and are harmless"],a:1,e:"Fuel contamination is a serious airworthiness issue. Filter blockage → low pressure → boost pump CAUTION → potential engine flameout. Water contamination can cause FADEC sensor errors, ice crystal formation at altitude blocking fuel lines, and combustion anomalies. Contaminated fuel requires complete fuel system decontamination per AMM.",ref:"Ch.10 §4"}
]
},

// ─────────────────────────────────────────
// CHAPTER 11 — Power Plant
// ─────────────────────────────────────────
{
m:[
{q:"What type of compressor do both the PW206B3 and ARRIUS 2B2+ use?",o:["Axial two-stage","Single-stage centrifugal","Dual centrifugal","Axial + centrifugal combined"],a:1,e:"Both engines use a single-stage centrifugal compressor — compact, light, and suitable for the 450 kW class turboshaft.",ref:"Ch.11 §2"},
{q:"What does FADEC stand for?",o:["Full Authority Digital Engine Control","Fuel Adjusting Digital Engine Controller","Flight Authority Digital Engine Computer","Full Automatic Drive and Engine Control"],a:0,e:"FADEC = Full Authority Digital Engine Control — the primary digital engine management system controlling all aspects of engine operation.",ref:"Ch.11 §4"},
{q:"What happens to FADEC engine control if the FADEC fails?",o:["Engine shuts down automatically","Pilot has no control — engine must be shut down","Mechanical backup (FMM) maintains basic fuel flow — pilot manually controls power with the twist-grip","FADEC failure has no effect — a secondary FADEC takes over"],a:2,e:"If FADEC fails, the mechanical Fuel Management Module (PW) or mechanical backup (TM) maintains basic fuel flow. The pilot manually controls power via the ENG CONT twist-grip, but all FADEC protections (overspeed, overtorque) are LOST.",ref:"Ch.11 §4"},
{q:"What is the purpose of Training Mode (ETO)?",o:["Test engine start sequence","Simulate OEI in flight for crew training without actually failing an engine","Verify FADEC calibration","Reduce fuel flow for economy training"],a:1,e:"Training Mode (ETO) simulates OEI: FADEC reduces power on one 'training' engine for crew practice, but the engine remains fully operative and available.",ref:"Ch.11 §5"},
{q:"What happens to a failed engine's freewheel unit during OEI?",o:["It locks, maintaining MGB drive","It overruns, decoupling the dead engine from the MGB","It applies the rotor brake","It transfers drive to the tail rotor only"],a:1,e:"The freewheel (one-way clutch) overruns during OEI — it decouples the non-driving (dead) engine from the MGB so the MGB is not driven by the windmilling dead engine.",ref:"Ch.11 §5"},
{q:"How many spark igniters are fitted per engine?",o:["1","2","3","4"],a:1,e:"Each engine has 2 spark igniters located in the combustion chamber, powered by a high-voltage ignition exciter unit.",ref:"Ch.11 §6"},
{q:"What is the PW206B3 reduction gearbox output shaft angle?",o:["0° (horizontal)","15° upward","26° upward","45° upward"],a:2,e:"The PW206B3 reduction gearbox output shaft is inclined 26° upward to match the MGB input drive shaft angle.",ref:"Ch.11 §2"},
{q:"What is the engine class of both EC135 turboshaft options?",o:["250 kW class","350 kW class","450 kW class","550 kW class"],a:2,e:"Both the PW206B3 (P3H) and ARRIUS 2B2 Plus (T3H) are in the 450 kW class — free-turbine turboshaft engines.",ref:"Ch.11 §1"},
{q:"What critical protections are LOST in Manual (backup) mode?",o:["Only fuel flow control is lost","All FADEC protections — overspeed, overtorque, and OEI automatic power increase","Only OEI rating is lost","Only the training mode is lost"],a:1,e:"In Manual mode, ALL FADEC protections are lost: overspeed protection, overtorque protection, power sharing between engines, and OEI automatic power increase — the pilot must manage all parameters manually.",ref:"Ch.11 §4"},
{q:"What does the ARRIUS 2B2 Plus EECU use for power when main DC supply is unavailable?",o:["Battery only","An engine-driven alternator provides independent EECU power","External GPU only","It cannot operate without main electrical power"],a:1,e:"The ARRIUS engine has an engine-driven alternator that provides power directly to the EECU, ensuring engine control even in a main electrical system failure.",ref:"Ch.11 §3"},
{q:"What is the combustion chamber design of the PW206B3?",o:["Straight-through tubular","Reverse-flow annular with 12 fuel nozzles","Single can combustor","Siamese double annular"],a:1,e:"The PW206B3 uses a reverse-flow annular combustion chamber with 12 fuel nozzles — the reverse-flow design reduces overall engine length.",ref:"Ch.11 §2"},
{q:"When can continuous ignition be manually selected?",o:["During all flights as standard","In icing conditions or precipitation to prevent flameout","Only during start","During high-altitude cruise only"],a:1,e:"Continuous ignition can be manually selected during flight in icing conditions or heavy precipitation, where there is risk of combustion chamber flame extinction.",ref:"Ch.11 §6"},
{q:"What type of turbine drives the PW206B3 compressor?",o:["Free power turbine","Single-stage compressor turbine","Two-stage axial turbine","Contra-rotating turbine"],a:1,e:"The PW206B3 has a single-stage compressor turbine that drives the centrifugal compressor, and a separate single-stage free power turbine that drives the reduction gearbox output.",ref:"Ch.11 §2"},
{q:"What is the OEI 2-minute power rating used for?",o:["Extended single-engine cruise","Emergency power for 2 minutes after engine failure to execute a safe escape manoeuvre","Normal take-off power","High-altitude operations only"],a:1,e:"The OEI 2-minute rating provides elevated emergency power for up to 2 minutes after engine failure — sufficient time to establish a safe flight path or conduct a precautionary landing.",ref:"Ch.11 §5"},
{q:"What does the torque limiter function in the FADEC do?",o:["Limits MGB input torque to protect the transmission","Limits engine temperature only","Controls rotor speed during autorotation","Reduces fuel flow at altitude"],a:0,e:"The FADEC torque limiter prevents the MGB input torque from exceeding its structural limit, protecting the transmission from overtorque damage during power transients or OEI.",ref:"Ch.11 §4"}
],
h:[
{q:"Why does the PW206B3 use a reverse-flow combustion chamber?",o:["Reverse flow provides higher combustion efficiency","Reverse-flow design folds the combustion path back on itself, shortening the overall engine length without sacrificing combustion residence time — critical for fitting two engines in the compact EC135 transmission compartment","Reverse flow reduces fuel nozzle count","Reverse flow prevents compressor surge"],a:1,e:"Reverse-flow combustor: hot gases from the compressor enter the aft end of the combustor, flow forward through the combustion zone, then reverse direction to exit through the turbine nozzle. This reduces engine length by ~30% compared to a straight-through design — enabling the compact twin-engine installation in the EC135.",ref:"Ch.11 §2"},
{q:"In Manual (backup) mode, what specific risk does operating at OEI power levels present?",o:["No additional risk — manual mode is as safe as FADEC","Without FADEC overtorque and overspeed protection, the pilot could unknowingly exceed the MGB torque limit or turbine temperature limit — causing immediate or latent structural damage","Manual mode automatically sets OEI power","Overtorque is not possible with the mechanical FMM controlling fuel flow"],a:1,e:"In Manual mode, the pilot controls fuel via the twist-grip. Without FADEC limiting, a rapid collective rise or aggressive power application can exceed MGB torque limits (overtorque) or turbine entry temperature limits (over-temperature) without any automatic warning or cutback. Careful, graduated power inputs are essential.",ref:"Ch.11 §4"},
{q:"What is the significance of the ARRIUS 2B2 Plus having an engine-driven alternator for the EECU?",o:["Reduces the load on the main electrical system","Ensures the EECU has completely independent power from the aircraft electrical buses — even total DC bus failure cannot cause loss of engine control","Allows the EECU to control both engines simultaneously","Provides power for the FADEC-to-AFCS interface only"],a:1,e:"The engine-driven alternator makes the EECU self-sufficient: (1) Total aircraft electrical failure cannot cause engine control loss — the running engine continues controlled, (2) During start, if the battery is depleted, the running engine's alternator can potentially power its own EECU, (3) Engine remains under FADEC protection even in catastrophic electrical emergencies.",ref:"Ch.11 §3"},
{q:"During OEI, the live engine's FADEC automatically increases to OEI power. What are the three power levels available?",o:["OEI Normal, OEI Maximum, OEI Emergency","OEI Continuous (OEI MCP), OEI 2-minute, OEI 30-second — each with increasing power and decreasing time limit","OEI 10-minute, OEI 30-minute, and OEI Unlimited","OEI Low, OEI Medium, OEI High"],a:1,e:"OEI has three time-limited ratings: (1) OEI 30-second (highest power — immediate emergency use only), (2) OEI 2-minute (high power for escape manoeuvre), (3) OEI MCP/Continuous (maximum continuous — for extended single-engine flight to landing). Exceeding time limits requires mandatory engine inspection.",ref:"Ch.11 §5"},
{q:"What is the compressor pressure ratio of a single-stage centrifugal compressor compared to a multi-stage axial? Why is this relevant for the EC135?",o:["Centrifugal achieves higher pressure ratios than axial in one stage — ideal for high-performance engines","A single centrifugal stage achieves pressure ratios of ~8:1 in one stage (vs. multiple axial stages required for the same ratio) — providing compact, robust compression suitable for the 450 kW class with less sensitivity to intake distortion","Centrifugal is less efficient than axial — chosen only for weight reasons","Axial compressors are not approved for helicopter use"],a:1,e:"Single-stage centrifugal compressors achieve high pressure ratios (6:1 to 10:1) in a compact diameter, are mechanically simple, and are tolerant of intake flow distortion (important in helicopter airflow environments). Multi-stage axials achieve higher overall pressure ratios for larger engines but are less appropriate for the 450 kW class.",ref:"Ch.11 §2"},
{q:"How does the FADEC power-sharing function work during AEO operation?",o:["Both engines always run at maximum power","FADEC on each engine communicates via a cross-engine bus to divide the total power demand equally between both engines, preventing one engine from carrying disproportionate load","Only one FADEC controls both engines simultaneously","Power sharing is mechanical — via the MGB freewheel"],a:1,e:"The two FADECs communicate via a cross-engine data link. When the pilot demands power (collective up), both FADECs coordinate to share the load equally — preventing torque split where one engine would be at limit while the other is underloaded, maximizing system efficiency and component life.",ref:"Ch.11 §4"},
{q:"What is the difference between 'droop' and 'isochronous' governor operation in the FADEC?",o:["There is no difference — FADEC is always isochronous","Droop governor allows Nr to decrease slightly with increasing load (natural mechanical response); isochronous governor maintains exactly constant Nr regardless of load. FADEC targets near-isochronous response with minimal droop for better power management","Droop is used in Manual mode; isochronous in FADEC mode only","Isochronous means constant fuel flow regardless of power demand"],a:1,e:"Droop: as torque demand increases, Nr decreases slightly (the governor 'droops'). Isochronous: Nr stays constant regardless of load changes. Modern FADEC systems target near-isochronous response — Nr is maintained very closely around 100% to provide consistent control response during manoeuvres.",ref:"Ch.11 §4"},
{q:"What is the function of the high Nr mode in the FADEC?",o:["Increases main rotor speed for better autorotation","Allows a higher Nr setting for specific operations (e.g., hot/high or performance-limited operations) where additional rotor thrust is needed","Reduces engine speed for fuel economy","Is used only during engine start"],a:1,e:"High Nr mode increases the governed rotor speed above the standard Nr setting. This increases rotor disc loading, which can provide better hover performance in hot/high conditions where standard Nr is insufficient to maintain MTOM at altitude and temperature.",ref:"Ch.11 §4"},
{q:"Why does Training Mode (ETO) not actually reduce power on the 'failed' engine?",o:["It would be too dangerous to actually fail an engine in training","The real engine remains at operational power in case the training scenario develops into a genuine emergency, requiring immediate full power from the 'training' engine — safety net for the crew","ETO does reduce power slightly — just not to zero","FADEC cannot control power below 50% in ETO mode"],a:1,e:"Safety principle: if a genuine OEI emergency occurs during Training Mode simulation (e.g., the real other engine fails), the crew can immediately exit Training Mode and have both engines at full power. Actually reducing one engine's power to zero (real OEI simulation) would leave no safety margin if the live engine then also fails.",ref:"Ch.11 §5"},
{q:"What are the accessories driven by the PW206B3 engine accessory gearbox?",o:["Only the starter/generator","Starter/generator, PMA (alternator), fuel pumps, and oil pumps","Hydraulic pump and cooling fan","Only the FADEC and fuel pump"],a:1,e:"The PW206B3 accessory gearbox drives: starter/generator (for electrical generation and engine start), PMA (Permanent Magnet Alternator for FADEC power), engine fuel pump (high-pressure metering), and engine oil pump.",ref:"Ch.11 §2"},
{q:"If the ignition is left in 'continuous' mode after it is no longer needed, what is the consequence?",o:["No consequence — ignition can remain on indefinitely","Unnecessary use shortens igniter and exciter unit life through thermal and electrical wear — they are time-limited components. Continuous operation also draws power from the Essential Bus unnecessarily","Continuous ignition prevents FADEC from modulating fuel flow","Ignition remaining on triggers a CAUTION after 10 minutes"],a:1,e:"Igniters and exciter units have finite life cycles based on operating hours. Continuous ignition is an accelerated wear mode. Best practice: use continuous ignition only when the AFM or procedures require it (icing, precipitation), then turn off when conditions improve.",ref:"Ch.11 §6"},
{q:"What is the mechanical link between the free power turbine and the output shaft in a free-turbine engine?",o:["They are mechanically coupled via a clutch","The free power turbine has no mechanical connection to the compressor — it is only aerodynamically coupled via the gas stream. It drives the output shaft (to the MGB) via its own shaft through the engine","The turbine connects via the FADEC-controlled coupling","The free turbine is coupled to the compressor at idle only"],a:1,e:"In a free-turbine (or 'two-spool') turboshaft: Spool 1 (gas generator) = compressor + compressor turbine, mechanically connected, run at their own optimal speed. Spool 2 (power turbine) = free turbine + output shaft, aerodynamically driven by gas stream from spool 1 but NOT mechanically connected to spool 1. This allows Nr to vary independently of gas generator speed.",ref:"Ch.11 §2"},
{q:"What is the significance of the engine output shaft being inclined at 26° (PW206B3)?",o:["26° inclination increases engine efficiency","The output shaft angle is matched to the MGB input shaft geometry — an angled connection allows the engine to be installed tilted, keeping the engine profile lower in the cowling while the MGB sits correctly above the cabin","26° is required for the driveshaft flexible coupling to function","The 26° angle ensures the engine exhaust points downward"],a:1,e:"The 26° upward inclination of the PW output shaft precisely matches the MGB input drive shaft inclination. This allows a short, direct driveshaft connection without complex angle gearboxes, while positioning the engine below and aft of the MGB at an angle that fits the transmission compartment envelope.",ref:"Ch.11 §2"},
{q:"During Manual (backup) mode, what specific technique prevents overtorque on the main rotor transmission?",o:["Apply rotor brake to limit torque","Make small, gradual collective inputs — do not make abrupt or large collective raises. Monitor the torque indicator (from the MFD VMS page if available) and stay within the displayed limits","Reduce rotor speed to low Nr before increasing collective","Set maximum fuel flow via the twist-grip before collective increase"],a:1,e:"In Manual mode, the FADEC torque limiter is inactive. The pilot must: (1) Make slow, incremental collective increases, (2) Watch the torque indicator on MFD VMS page continuously, (3) Reduce collective immediately if torque exceeds limits. Abrupt collective inputs without FADEC protection will produce torque spikes well above the MGB limit.",ref:"Ch.11 §4"},
{q:"What is the combustor 'flame tube' design purpose for the 12 fuel nozzles in the PW206B3?",o:["12 nozzles ensure even circumferential fuel distribution for uniform combustion temperature — preventing hot spots that would reduce turbine blade life","12 nozzles provide redundancy — the engine runs normally with up to 6 failed nozzles","12 nozzles are required for the reverse-flow design only","Nozzle count determines total fuel flow rate"],a:0,e:"12 uniformly spaced fuel nozzles in the annular combustor distribute fuel evenly around the entire circumference. This creates a uniform temperature profile at the turbine nozzle guide vanes and first-stage turbine blades — preventing thermal hot spots that would cause accelerated local oxidation and fatigue of turbine components.",ref:"Ch.11 §2"}
]
},

// ─────────────────────────────────────────
// CHAPTER 12 — Fire Protection System
// ─────────────────────────────────────────
{
m:[
{q:"How many fire detectors are installed per engine compartment?",o:["1","2","3","4"],a:1,e:"Each engine compartment has 2 fire detectors: one on the accessory gearbox and one beneath the combustion chamber casing.",ref:"Ch.12 §1"},
{q:"Where are the two fire detectors located in each engine compartment?",o:["Top of engine bay and tail pipe","Accessory gearbox and beneath combustion chamber casing","Intake and exhaust","Fuel nozzle area and compressor inlet"],a:1,e:"The two detectors per compartment are positioned at the accessory gearbox (where oil and fuel lines are concentrated) and beneath the combustion chamber casing.",ref:"Ch.12 §1"},
{q:"What type of extinguishant does the EC135 fire system use?",o:["CO₂","Dry powder","Water mist","BCF (Halon)"],a:3,e:"The EC135 fire extinguishing system uses BCF (Bromo-Chloro-difluoro methane / Halon) extinguishant.",ref:"Ch.12 §3"},
{q:"How many extinguisher discharges are available in the EC135?",o:["1 (one bottle shared between both engines)","2 (one per engine)","3 (with reserve)","4 (two shots per engine)"],a:0,e:"Only ONE discharge is available from a single shared bottle. After discharge the bottle must be replaced on the ground.",ref:"Ch.12 §3"},
{q:"What bus powers the fire detection system?",o:["Main Bus","AMC Bus","Essential Bus","High Load Bus"],a:2,e:"The fire warning system is powered from the Essential Bus — ensuring availability even in significant electrical failure scenarios.",ref:"Ch.12 §1"},
{q:"What does the FIRE warning trigger besides the red W/U caption?",o:["Red W/U caption only","Red W/U caption + red WARNING on FND + aural tone + voice message","Red W/U caption + auto engine shutdown","Red W/U caption + fuel shutoff only"],a:1,e:"A FIRE warning produces: red FIRE caption on W/U, red WARNING on FND Master List, continuous aural tone, and voice message ('Fire, engine one' or 'Fire, engine two').",ref:"Ch.12 §2"},
{q:"What system logic unit processes fire detection signals?",o:["The AMC computer","The FADEC","The Warning Unit (W/U)","The IESI"],a:2,e:"Fire warning logic is located in the Warning Unit (W/U), which processes detector signals and activates the FIRE caption and aural alerts.",ref:"Ch.12 §1"},
{q:"What is the fire system test procedure designed to verify?",o:["That the extinguisher bottle is full","That the detector circuit and warning system function correctly — FIRE caption and aural alert activate","That the extinguisher discharges correctly","That the FADEC responds to fire signals"],a:1,e:"The test switch simulates the detector circuit activation. The expected result: FIRE caption on W/U illuminates and aural alert activates — confirming the detection and warning system is functional.",ref:"Ch.12 §4"},
{q:"During normal monitoring, what triggers a CAUTION rather than a WARNING for the fire system?",o:["Low extinguisher pressure","An open circuit (detector wire broken) — indicating a detector fault","Smoke in the engine bay","High engine compartment temperature without fire"],a:1,e:"A break in the fire detector circuit (open circuit) triggers a CAUTION message in the Master List indicating a detector fault — not a fire warning. This prompts investigation before flight.",ref:"Ch.12 §4"},
{q:"What is the crew action sequence for a FIRE warning?",o:["Switch off all electrical systems","Identify which engine, shut it down, discharge extinguisher per emergency procedures","Increase power on remaining engine first","Descend immediately to sea level"],a:1,e:"The crew follows the emergency procedures: identify which engine (ENG 1 or ENG 2), shut down that engine, then discharge the extinguisher into the affected compartment.",ref:"Ch.12 §2"},
{q:"What is the consequence of the extinguisher bottle being discharged?",o:["It automatically recharges in flight","The bottle is empty — only one discharge is available, and the bottle must be replaced on the ground before next flight","The system is still armed for a second discharge","The second bottle automatically activates"],a:1,e:"The EC135 has one extinguisher bottle — one discharge. After use, the bottle must be replaced by a licensed engineer before the aircraft can fly again.",ref:"Ch.12 §3"},
{q:"Where are the spray nozzles that distribute extinguishant?",o:["Only at the engine outlet","Inside each engine compartment, positioned to cover the fire zones","In the cockpit only","In the exhaust pipe"],a:1,e:"Spray nozzles are positioned inside each engine compartment to distribute the Halon extinguishant throughout the compartment, covering all potential fire source areas.",ref:"Ch.12 §3"},
{q:"Which compartment does the extinguisher protect?",o:["Both engine compartments simultaneously","Only engine 1 compartment","Only engine 2 compartment","The pilot selects which compartment to discharge to"],a:0,e:"One discharge button/switch covers both engine compartments via the spray nozzle distribution system — the entire engine bay receives extinguishant from the single bottle discharge.",ref:"Ch.12 §3"},
{q:"What preflight check is required for the fire system?",o:["Visual inspection of extinguisher bottle only","Test switch activation to verify FIRE caption and aural alert — must be performed before flight","No preflight check is required","Only required for IFR flights"],a:1,e:"The fire system test must be performed during preflight checks, using the test switch to confirm FIRE caption illuminates and aural alert activates.",ref:"Ch.12 §4"},
{q:"What does a FIRE warning require in terms of timing?",o:["The crew has 5 minutes to assess before acting","IMMEDIATE action per Emergency Procedures — no delay","Assess for 30 seconds before confirming","Requires copilot confirmation before action"],a:1,e:"A FIRE WARNING requires IMMEDIATE action. There is no assessment delay — the red WARNING and voice message indicate the crew must immediately follow the fire emergency procedure.",ref:"Ch.12 §2"}
],
h:[
{q:"Why does the EC135 use two fire detectors per engine compartment rather than one?",o:["Redundancy only — either detector can trigger the warning alone","Two detectors provide both redundancy AND detection logic. If only one detector triggers, it may indicate a false alarm or local hot spot. The logic can require one OR both to activate (OR logic for sensitivity; AND logic for false alarm rejection depending on design)","Two detectors cover physically separate zones — accessory area and combustion area — ensuring full compartment coverage","Two detectors are required by EASA AMC 27.863"],a:2,e:"The two detectors are positioned at the most likely fire ignition points: (1) Accessory gearbox area (fuel/oil connections, seals), (2) Combustion chamber underside (highest temperature zone). This spatial separation ensures fire detection coverage throughout the entire engine compartment.",ref:"Ch.12 §1"},
{q:"Why is Halon (BCF) the approved extinguishant for the EC135 rather than CO₂ or dry powder?",o:["Halon is cheaper than CO₂","Halon is effective at low concentrations without displacing all oxygen (unlike CO₂ which suffocates crew if deployed in a confined space), leaves no residue (unlike dry powder), and does not damage engine components","Halon works at higher temperatures than CO₂","Dry powder is not approved for aviation"],a:1,e:"Halon advantages for engine compartment use: (1) Effective at low concentrations — minimal quantity needed, (2) No oxygen displacement risk to crew (unlike CO₂ in quantities needed for engine fires), (3) No corrosive or abrasive residue (unlike dry powder which would require major engine cleaning), (4) Works at high temperatures in the engine bay.",ref:"Ch.12 §3"},
{q:"What is the significance of the fire warning system being powered by the Essential Bus?",o:["Essential Bus provides higher voltage for the detectors","Even with significant electrical failures (both generators failed, operating on battery), the Essential Bus remains powered — fire detection and warning remain functional when the aircraft is most vulnerable (single engine, abnormal ops)","Essential Bus provides faster response time","Required by ATA 26 Fire Protection standard"],a:1,e:"During a fire scenario, the crew may already be managing an electrical abnormality (fire often causes electrical damage). The Essential Bus ensures fire detection and warning functions are the last systems to lose power — the warning remains active even on minimal battery power during the emergency.",ref:"Ch.12 §1"},
{q:"What is the consequence of a false fire warning on the EC135 in flight?",o:["No consequence — the crew would ignore it","The crew would shut down the engine and discharge the extinguisher per emergency procedures, losing one engine and the only extinguisher shot. Subsequent real fire would have no extinguisher available","False warnings are filtered by the AMC automatically","Only a CAUTION is generated for false warnings"],a:1,e:"A false FIRE warning followed by correct emergency response: (1) Engine shutdown — losing 50% power, (2) Extinguisher discharged — leaving zero fire suppression capacity for a subsequent real fire. This is why the test switch is designed to only test the warning system, and the detectors themselves are monitored for fault conditions.",ref:"Ch.12 §2"},
{q:"What happens if a FIRE DETECTOR FAULT CAUTION appears on the ground?",o:["The aircraft is grounded until the detector circuit is repaired — no MEL dispatch","This indicates an open circuit in the detector wiring, likely a broken detector or connector. The affected detection circuit is inoperative. Most operators cannot dispatch with a failed fire detector — check MEL for dispatch conditions","The crew can reset the fault using the test switch","Replace the extinguisher bottle before next flight"],a:1,e:"An open circuit in the fire detector circuit means one of the two detectors per compartment is non-functional — reducing fire detection reliability. Most MELs (Minimum Equipment Lists) for fire detection systems do not allow dispatch with a failed detector in an engine compartment due to the catastrophic nature of an undetected engine fire.",ref:"Ch.12 §4"},
{q:"Why is the extinguisher shared between both engine compartments rather than having one per engine?",o:["Cost reduction","A single bottle for both compartments means once discharged for any fire, BOTH compartment protection is gone. This is a weight/cost compromise accepted because: (a) simultaneous two-engine fires are extremely rare, (b) the single OEI engine landing after fire shut-down is the primary survival scenario","Having one per engine would cause confusion in emergency procedures","Single bottle provides higher extinguishant concentration"],a:1,e:"The design accepts the risk that a second fire (in the remaining engine) has no extinguisher protection, because: (a) the probability of two simultaneous independent engine fires is extremely low, (b) after shutting down a fire engine and landing, the primary threat is eliminated. The weight and complexity of two separate bottles was judged not warranted by the risk.",ref:"Ch.12 §3"},
{q:"What is the airworthiness limitation on operating the EC135 after the extinguisher has been discharged?",o:["Can continue flying — the discharge was a precaution","The aircraft cannot fly again until the extinguisher bottle is replaced and the fire system is restored to full operational status by a licensed engineer","Can continue for 1 more flight hour only","Can fly if the fire has been confirmed extinguished"],a:1,e:"The fire extinguisher is a mandatory safety system. Once discharged, the aircraft has NO fire suppression capability. This is a go/no-go item — the aircraft is grounded until the extinguisher is replaced and the fire system returns to full operational status.",ref:"Ch.12 §3"},
{q:"Why are the fire detectors positioned specifically at the accessory gearbox and combustion chamber underside?",o:["These are the only accessible locations in the engine bay","Accessory gearbox: highest concentration of fuel/oil lines and seals — most likely ignition source from a leak. Combustion chamber underside: highest sustained temperature and most likely location for hot-section cracks that could cause external ignition","Both positions are required by ATA 26 regardless of actual fire risk","They are the only locations with electrical access for the detection circuit"],a:1,e:"Risk-based placement: (1) Accessory gearbox area has fuel pump, oil pump, and hydraulic connections — any seal failure creates fuel/oil spray in a hot environment = highest ignition probability. (2) Combustion chamber casing underside — any combustor crack allows hot gas escape at the highest temperature location in the engine.",ref:"Ch.12 §1"},
{q:"What is the purpose of continuous fire detector circuit monitoring for open circuits?",o:["To measure detector temperature continuously","An open circuit means a detector is broken and not producing a signal. Without monitoring, the crew would have no warning of a non-functional detector until a fire occurred — making the fire warning system appear functional when it is not","To monitor battery consumption","To allow FADEC to adjust detector sensitivity"],a:1,e:"Continuous circuit monitoring implements the 'fail-safe' principle: the system monitors for the ability to detect, not just for detection signals. A broken wire (open circuit) generates a CAUTION — alerting the crew that the detection capability is degraded before a fire occurs.",ref:"Ch.12 §4"},
{q:"How does the voice message 'Fire, engine one' improve the crew's response compared to only a visual warning?",o:["Voice is louder than visual","In a high-workload emergency, visual scan may be momentarily elsewhere. The voice message provides immediate, unambiguous identification of which engine is on fire — allowing the crew to begin the memory emergency procedure without looking for the light. It reduces response time by eliminating visual search time","Voice messages are required by EASA for all emergencies","Visual warnings alone are not permitted by CS-27"],a:1,e:"Cockpit voice messages: (1) Attract attention even when crew is head-down, (2) Provide immediate positive identification (engine 1 vs 2 — no ambiguity), (3) Reduce cognitive load — crew doesn't need to read and interpret a warning light, (4) Critical in high-vibration or smoke-in-cockpit scenarios where visual warning legibility may be compromised.",ref:"Ch.12 §2"},
{q:"If a fire warning occurs at night, what additional challenge does the crew face?",o:["Night increases FIRE warning brightness — easier to see","External fire confirmation (looking at engine compartment) may be difficult or impossible at night. The crew must act on the cockpit indication alone without visual confirmation — reinforcing the need to follow memory procedures immediately without waiting for visual confirmation","Night operations are not permitted with the EC135","Night requires additional fire extinguisher capacity"],a:1,e:"At night: (1) Cannot visually see smoke or flames from the engine compartment, (2) Reflection of cockpit lighting may reduce warning light visibility, (3) Crew must trust the system and follow emergency procedures without the psychological confirmation of seeing the fire. Training for night emergency procedures is essential.",ref:"Ch.12 §2"},
{q:"Why is it important to identify WHICH engine has the fire before taking action?",o:["Both engines must always be shut down for any fire warning","Shutting down the WRONG engine: (a) leaves the fire engine running, (b) shuts down the good engine, possibly leaving no power for flight. Correct identification ensures the fire engine is shut down while the good engine provides power for emergency flight to landing","Fire identification is not required — procedure is the same for both engines","Both engines should be reduced to idle first"],a:1,e:"Identifying the correct engine is safety-critical: shutting down the wrong engine means the fire continues on the running engine while the good engine has been unnecessarily shut down — creating dual engine-off autorotation. Proper engine identification (visual check of FLI indication for which engine, confirming fire caption ENG 1 or ENG 2) is the critical first step.",ref:"Ch.12 §2"},
{q:"What risk does Halon pose to the environment, and why is this relevant to current operations?",o:["No environmental risk","Halon (BCF) depletes ozone layer (high ODP). Its manufacture is banned under the Montreal Protocol, making it a finite resource. Current stocks are recycled. Future alternatives are being certified, but Halon remains the approved extinguishant for EC135 fire systems due to its effectiveness","Halon is toxic only during combustion","Halon causes corrosion in engine components"],a:1,e:"Halon has ozone-depleting properties (ODP). Manufacturing was banned in 1994 under the Montreal Protocol. Current aircraft systems use recycled Halon stocks. Operators must: (1) Ensure discharged bottles are not vented to atmosphere unnecessarily, (2) Use certified recycling services for bottle refill, (3) Be aware that alternative clean agents may be approved in future AMM revisions.",ref:"Ch.12 §3"},
{q:"What is the difference between the fire warning and a fire detection fault from a crew action perspective?",o:["Both require the same emergency procedure","FIRE WARNING (red): IMMEDIATE emergency action per procedures. FIRE DETECTOR FAULT (amber CAUTION): investigate, check MEL for dispatch, likely ground until repaired — NOT an emergency action but an airworthiness dispatch decision","Detection fault requires testing the extinguisher","Detection fault means fire has been extinguished"],a:1,e:"FIRE WARNING = fire present now → immediate life-critical emergency. FIRE DETECTOR FAULT = potential inability to detect a future fire → airworthiness/dispatch issue. The crew responses are completely different in urgency, but both require action: warning = fly the emergency, fault = ground for maintenance.",ref:"Ch.12 §4"}
]
},

// ─────────────────────────────────────────
// CHAPTER 13 — Ice and Rain Protection
// ─────────────────────────────────────────
{
m:[
{q:"What are the three positions of the windshield wiper control switch?",o:["LOW / MED / HIGH","ON / PARK / OFF","SLOW / FAST / OFF","1 / 2 / STOP"],a:2,e:"The wiper switch has three positions: SLOW (normal speed), FAST (heavy rain or snow), and OFF (arm returns to parked position).",ref:"Ch.13 §1"},
{q:"From which electrical bus is the windshield wiper powered?",o:["Main Bus 1","High Load Bus 2","Essential Bus 1","AMC Bus"],a:2,e:"The windshield wiper is powered from Essential Bus 1, protected by a circuit breaker labelled WIPER on the overhead console.",ref:"Ch.13 §1"},
{q:"What type of heating does the EC135 pitot-static system use?",o:["Hot engine bleed air","Electric resistance heating elements","Hot fuel circulation","Thermoelectric (Peltier) devices"],a:1,e:"The pitot-static heating system uses electric resistance heating elements integrated in the pitot tubes to prevent ice formation.",ref:"Ch.13 §2"},
{q:"What does the IBF protect against?",o:["Icing only","Sand, dust, and foreign objects entering the engine intake","Bird strike on the windshield","Fuel tank contamination"],a:1,e:"IBF (Inlet Barrier Filter) prevents sand, dust, and foreign object debris (FOD) from entering the engine air intake — critical for desert/brownout operations.",ref:"Ch.13 §3"},
{q:"What happens to the IBF bypass doors if the filter differential pressure exceeds the limit?",o:["The IBF triggers a CAUTION only","The bypass doors open automatically to maintain engine airflow","The engine automatically shuts down","The IBF releases and falls away"],a:1,e:"IBF bypass doors open automatically when filter differential pressure exceeds the limit — ensuring unobstructed engine airflow even with a clogged filter.",ref:"Ch.13 §3"},
{q:"Where is the one-shot wiper push button located?",o:["On the overhead console","On the pilot's and copilot's collective levers","On the centre console","On the cyclic stick"],a:1,e:"A single-sweep one-shot push button is provided on both the pilot's and copilot's collective levers for a single wiper sweep without changing the switch position.",ref:"Ch.13 §1"},
{q:"What risk does pitot-static icing create?",o:["Structural damage to the pitot tube","Corrupts airspeed and altitude indications — leading to erroneous flight instruments","Causes engine flameout","Creates radio frequency interference"],a:1,e:"Ice on pitot tubes and static ports blocks pressure input, corrupting IAS and altitude indications. This can lead to incorrect autopilot inputs or pilot spatial disorientation.",ref:"Ch.13 §2"},
{q:"What monitors the pitot heat system for failure?",o:["The FADEC","The AMC monitors heater circuits — a FAIL caution is generated if a heater element fails","The crew checks by touch during preflight only","The IESI detects pitot heat failure"],a:1,e:"The AMC continuously monitors pitot heater circuits. If a heater element fails, a heating FAIL caution is generated in the Master List.",ref:"Ch.13 §2"},
{q:"What is the consequence of operating the windshield wiper on a dry windshield?",o:["No consequence","Damages the wiper blade, motor, or scratches the windshield","Triggers a CAUTION message","Causes the wiper to stop automatically"],a:1,e:"Operating the wiper on a dry windshield can damage the blade, overheat the motor, and scratch the windshield. A thermal switch protects the motor from overheating.",ref:"Ch.13 §1"},
{q:"The EC135 IBF status is displayed where in the cockpit?",o:["On a dedicated IBF panel","On the VMS page on the MFD","On the overhead console","Only via an engine instrument"],a:1,e:"IBF status and bypass door position are displayed on the VMS (Vehicle Management System) page on the Helionix® MFD.",ref:"Ch.13 §3"},
{q:"When should pitot heat be switched ON?",o:["Only when in actual icing conditions","Whenever icing conditions are possible — as a precaution","Only above FL100","Only during IFR flight"],a:1,e:"Pitot heat should be ON whenever icing conditions are possible — not only when actual icing is occurring. Prevention is critical since iced-over instruments give no warning of the icing event.",ref:"Ch.13 §2"},
{q:"What is the purpose of the CB labelled WIPER on the overhead console?",o:["Controls wiper speed","Provides circuit protection for the wiper motor","Connects the wiper to the backup bus","Controls the one-shot function only"],a:1,e:"The WIPER circuit breaker provides overcurrent protection for the windshield wiper motor and its electrical supply from Essential Bus 1.",ref:"Ch.13 §1"},
{q:"How many wiper arms does the EC135 windshield wiper system use?",o:["1","2","3","4"],a:1,e:"The EC135 wiper system has two wiper arms (pilot and copilot) driven by a single electric motor and gearbox assembly.",ref:"Ch.13 §1"},
{q:"What additional environmental use does the IBF partially address beyond sand and dust?",o:["Heavy rain protection","Ice crystal ingestion and light icing","Chemical fog","High altitude pressure recovery"],a:1,e:"When fitted, the IBF also partially addresses operations in light icing environments — check AFM for specific approved operations. It captures ice crystals before they can enter the engine.",ref:"Ch.13 §3"},
{q:"If the wiper arm is fully folded off the windshield, what must the crew avoid?",o:["Selecting FAST wiper speed","Operating the wiper motor — this can cause motor damage","Turning off the wiper bus","Using the one-shot button"],a:1,e:"If the wiper arm is folded off the windshield and the motor is operated, the arm may strike the windshield frame or jamb, damaging both the arm and potentially the motor.",ref:"Ch.13 §1"}
],
h:[
{q:"Why is the pitot-static system particularly vulnerable on a helicopter compared to a fixed-wing aircraft?",o:["Helicopters fly faster and accumulate more icing","Low airspeed operations (hover, low-speed cruise) mean less kinetic heating of pitot probes — inadequate heating during ground idle can allow ice to form on the probe before flight if icing is present","Helicopters have more pitot probes","Helicopter pitot tubes are unheated by design"],a:1,e:"Fixed-wing aircraft at cruise speed have significant kinetic (ram) heating of pitot probes. Helicopters hover and fly slowly, so kinetic heating is minimal. The pitot heater must overcome ambient cold temperature without kinetic assistance. During ground idle in freezing conditions, unheated probes in rotor downwash can rapidly ice up if heaters are not ON.",ref:"Ch.13 §2"},
{q:"What is the IBF differential pressure bypass mechanism designed to prevent?",o:["IBF frame structural overload","Engine power loss due to restricted airflow through a clogged filter — bypass doors open to provide unrestricted airflow, accepting increased risk of FOD ingestion but maintaining engine operation","IBF ejection from the mounting","Electrical overload in the IBF monitoring circuit"],a:1,e:"The bypass doors prevent engine flame-out due to airflow restriction. Priority: keep the engine running. If the filter becomes clogged (heavy sand, water saturation), the bypass opens, allowing dirty air to enter rather than stopping the engine. This accepts the FOD risk as preferable to power loss.",ref:"Ch.13 §3"},
{q:"What is the risk of continued flight with a pitot heater FAIL CAUTION?",o:["No risk — backup pitot probes are available","Continued flight in or near icing conditions risks ice formation on the failed probe, potentially blocking it and causing erroneous airspeed/altitude indication leading to autopilot errors or pilot disorientation","Only a minor documentation issue","The IESI automatically takes over pitot reference"],a:1,e:"With one pitot heater failed: if the aircraft enters icing conditions, the failed probe ices over. The resulting erroneous IAS/altitude corrupts the AFCS input (or pilot instrument), potentially causing an undetected dangerous attitude or collision with terrain on an approach. The CAUTION requires diversion from icing conditions.",ref:"Ch.13 §2"},
{q:"Why is the wiper powered from Essential Bus 1 specifically (not a non-essential bus)?",o:["To provide higher current capacity","Essential Bus 1 ensures the wiper remains available in significant electrical failures — heavy rain or ice precipitation that requires the wiper is also the condition most likely to require flight in degraded conditions where only essential buses are powered","Essential Bus 1 is closest to the wiper motor physically","Non-essential buses are not available on the EC135"],a:1,e:"Wiper availability is most critical during the worst weather — precisely the conditions where electrical system degradation might have already shed non-essential buses. Essential Bus 1 ensures wiper remains available as long as any electrical power exists.",ref:"Ch.13 §1"},
{q:"What is the thermal switch function on the wiper motor?",o:["Controls wiper speed automatically based on rainfall","Protects the wiper motor from overheating by interrupting power if the motor overheats — can occur if wiper stalls on dry glass or jams","Activates the wiper automatically in rain","Monitors wiper blade condition"],a:1,e:"The wiper motor thermal switch is a self-protecting feature: if the motor temperature exceeds limits (due to stall/jam/dry glass operation), the thermal switch opens and cuts power. Once cooled, it resets automatically. This prevents motor burnout from sustained overload.",ref:"Ch.13 §1"},
{q:"In a brownout or desert operation with IBF fitted, what crew monitoring is required?",o:["No additional monitoring — IBF is fully automatic","Monitor IBF differential pressure and bypass door status on VMS page — increasing differential pressure indicates filter loading and approaching bypass. If bypass opens, expect possible engine performance effects and sand ingestion","Manually close bypass doors during takeoff","Reduce power to 50% whenever IBF bypass is open"],a:1,e:"Crew monitoring: (1) VMS IBF differential pressure — watch for increasing trend indicating filter clogging, (2) Bypass door position — if open, sand/dust entering engine, (3) Engine performance indicators for any change indicating FOD damage, (4) Plan shorter IBF cleaning/replacement intervals in heavy contamination environments per the AMM.",ref:"Ch.13 §3"},
{q:"Why is windshield fogging particularly dangerous during helicopter operations?",o:["Only an aesthetic concern","Rapid fogging can completely eliminate forward visibility in seconds, especially during descent into cold humid air. Unlike fixed-wing where autopilot may continue, a helicopter in instrument or low-level flight without visual reference has very limited time before loss of control","Fogging is only relevant above 10,000 ft","Fogging only affects the copilot side"],a:1,e:"Helicopter operations frequently involve: (1) Rapid transitions from warm cabin to cold moist external air (door opening, altitude changes), (2) Low-level flight where immediate visual contact with terrain is critical, (3) No ability to 'wait it out' at altitude — terrain is below. Fogging onset can be immediate and total. Proactive defog selection is essential.",ref:"Ch.13 §1"},
{q:"What is the significance of pitot heat being checked during the pre-flight inspection?",o:["Only for documentation purposes","Verifies the heating elements are functional before entering conditions where they may be needed. On the ground, a slight warmth can be felt on a functioning probe (though caution — it can be hot). The AMC monitoring provides in-flight detection, but pre-flight confirmation ensures the system is operational from the start","Pitot heat check is not a required preflight item","Only required for IFR operations"],a:1,e:"Pre-flight check prevents: departing with an already-failed pitot heater that won't be detected until icing conditions are entered. The AMC generates a FAIL caution for circuit faults, but a partial resistance increase (element degrading) may pass the circuit monitor while providing insufficient heat. Physical warmth check on the probe supplements the electrical monitoring.",ref:"Ch.13 §2"},
{q:"The EC135 is NOT certified for flight in icing conditions (FIKI). What does this mean operationally?",o:["Icing can be encountered as long as the pitot heat is on","Flight into Known Icing (FIKI) is not approved — the aircraft lacks ice protection on rotor blades, engine intakes (beyond IBF), and airframe. Encountering icing is an emergency requiring immediate exit from icing conditions","The pitot heat is the only certification requirement for icing","Icing is only restricted above FL100"],a:1,e:"Without FIKI certification: (1) Rotor blade icing can cause severe imbalance and change aerofoil characteristics, (2) Engine intake icing can cause power loss or flameout, (3) Airframe ice changes aerodynamic performance. The pitot heat and IBF protect only specific components — they do not make the aircraft ice-protected. Encountering inadvertent icing requires immediate escape to ice-free conditions.",ref:"Ch.13 §2"},
{q:"What is the consequence for the crew if both pitot heater elements fail during IFR flight in IMC?",o:["The IESI provides reliable backup with no consequence","Both pitot probes icing over in IMC means loss of IAS indication from both primary and secondary sources. AFCS loses IAS reference. The IESI provides a limited backup, but the crew must declare MAYDAY, maintain best effort flight attitude, and exit IMC immediately","Only one probe is critical — the other can be used indefinitely","Losing pitot data only affects transponder reporting"],a:1,e:"Dual pitot failure in IMC: (1) Both MFD IAS indications become unreliable/zero, (2) AFCS IAS mode disengages, (3) IESI provides last-resort attitude reference but its pitot system may also be compromised, (4) Crew must fly attitude reference only, using power settings and vertical speed as surrogates for speed control — a highly demanding emergency.",ref:"Ch.13 §2"},
{q:"Why must IBF filter maintenance intervals be shortened in high-sand-contamination environments?",o:["More frequent changes are required by CS-27 for desert operations","As sand loads the filter, differential pressure increases, eventually triggering bypass door opening more frequently. Each bypass event risks sand ingestion. Shorter maintenance intervals keep differential pressure low, reducing bypass frequency and engine contamination exposure","IBF is a single-use item that must be replaced after each desert operation","Sand changes the chemical composition of the filter material"],a:1,e:"Filter loading rate depends on ambient contamination level. In heavy desert/brownout conditions, filter loading is rapid. AMM-defined interval is based on typical conditions — high-contamination environments require shorter intervals (defined in the AMM as an operational condition modifier) to prevent premature bypass and the associated sand ingestion risk.",ref:"Ch.13 §3"},
{q:"How does the one-shot wiper button on the collective lever improve operational safety?",o:["It provides backup wiper control if the switch fails","During critical flight phases (approach, hover, landing), the pilot's hands must remain on the cyclic and collective. A collective-mounted one-shot button allows a single wiper sweep without releasing the collective or reaching to the overhead panel — maintaining hands-on-controls compliance during flight-critical phases","It provides faster wiper speed than the panel switch","It is only used for the copilot's wiper"],a:1,e:"Pilot-technique safety: during approach and hover, regulations and SOPs require hands on controls. An overhead panel wiper switch would require releasing the collective during critical phases. The collective-mounted button allows the pilot to maintain control while clearing the windshield with a single button press.",ref:"Ch.13 §1"},
{q:"What would be the symptom of a completely blocked (iced) pitot tube in flight?",o:["IAS reads zero","IAS reads the last valid speed and doesn't change (frozen), OR IAS reads maximum speed due to pressure relief, depending on whether the drain hole is also blocked","IAS reads double the actual speed","Only altitude indication is affected"],a:1,e:"If pitot tube blocks with static port open: IAS reads the last valid speed (pressure trapped) — a 'frozen' indication that doesn't respond to speed changes. If drain hole also blocks: altitude-induced pressure increases/decreases may cause IAS to incorrectly increase during climb or decrease during descent — the famous iced pitot tube failure mode.",ref:"Ch.13 §2"},
{q:"What is the risk of selecting FAST wiper speed in light drizzle?",o:["No risk — FAST is always better than SLOW","In light precipitation, the wiper at FAST speed provides insufficient lubrication for the blade and creates drag streaks. More significantly, running at unnecessarily high speed causes premature blade and motor wear. Use SLOW in light rain, FAST only in heavy rain or snow","FAST speed triggers an AMC caution","FAST requires higher electrical load that may shed other systems"],a:1,e:"Operational best practice: (1) SLOW in light to moderate rain provides adequate wiping with lower wear rate, (2) FAST in heavy rain/snow ensures visibility maintained, (3) Unnecessary FAST operation in light conditions accelerates blade deterioration (requiring more frequent replacement) and increases motor wear.",ref:"Ch.13 §1"}
]
},

// ─────────────────────────────────────────
// CHAPTER 14 — Equipment and Furnishing
// ─────────────────────────────────────────
{
m:[
{q:"What class fires is the portable fire extinguisher rated for?",o:["Class A only","Class B and C only","Class A, B and C","Class D (metal fires)"],a:2,e:"The 2 kg Halon 1211 portable fire extinguisher is approved for Class A (solid), Class B (liquid), and Class C (electrical) fires.",ref:"Ch.14 §1"},
{q:"What is the emergency hammer used for?",o:["Breaking the windshield in emergency","As a belt cutter","Breaking passenger windows","Tapping hydraulic lines during maintenance"],a:1,e:"The EC135 emergency hammer is a BELT CUTTER — used to cut seat harnesses if occupants cannot release them after a crash. It is NOT a glass-breaking device.",ref:"Ch.14 §1"},
{q:"Where is the first-aid kit located?",o:["Overhead console","Pilot's door pocket","Luggage net on the LH cargo door","Aft cargo compartment"],a:2,e:"The first-aid kit is located in the luggage net on the LH (left-hand) cargo door.",ref:"Ch.14 §1"},
{q:"What is the operating pressure of the portable fire extinguisher?",o:["5.5 bar","8.0 bar","11.0 bar","15.0 bar"],a:2,e:"The portable Halon fire extinguisher has an operating pressure of approximately 11.0 bar, shown in the green zone on its pressure gauge.",ref:"Ch.14 §1"},
{q:"How many points does the crew seat harness have?",o:["2-point lap belt","3-point shoulder + lap","4-point (shoulder + lap + crotch)","5-point racing harness"],a:2,e:"Crew seats have a 4-point harness: left and right shoulder straps, lap belt, and crotch strap.",ref:"Ch.14 §2"},
{q:"What DIN standard governs the EC135 first-aid kit?",o:["DIN 13155","DIN 13164","DIN 13172","DIN 13200"],a:1,e:"The first-aid kit must conform to DIN 13164 and JAR-OPS 3 standards.",ref:"Ch.14 §1"},
{q:"What is the weight of the portable fire extinguisher?",o:["1 kg","2 kg","3 kg","5 kg"],a:1,e:"The EC135 portable fire extinguisher is a 2 kg Halon 1211 unit.",ref:"Ch.14 §1"},
{q:"What flashlight power source does the EC135 use?",o:["Rechargeable battery (aircraft-charged)","2 × 1.5 V monocells","Aircraft 28V DC power","4 × AA alkaline batteries"],a:1,e:"The standard EC135 flashlight is powered by 2 × 1.5 V monocells (D-cell batteries).",ref:"Ch.14 §1"},
{q:"Where is the standard flashlight located?",o:["On the overhead console","LH floor next to the pilot seat","In the first aid kit","On the centre console"],a:1,e:"Standard flashlight location is on the LH floor next to the pilot seat. Optional positions are at the pilot's or copilot's door in a clamping device.",ref:"Ch.14 §1"},
{q:"How many emergency hammer holders are on the EC135 centre post?",o:["1","2","3","4"],a:1,e:"Two emergency hammer holders are located on the centre post between the crew and passenger compartments.",ref:"Ch.14 §1"},
{q:"How many rows of passenger seats does the standard EC135 configuration have?",o:["1 row of 5","2 rows of 3 (6 total seats)","3 rows of 2","1 row of 6"],a:1,e:"Standard passenger seating is 2 rows of 3 (6 passengers total) in a 3+3 configuration, for a total of 7 occupants including 2 crew.",ref:"Ch.14 §3"},
{q:"What type of harness do passenger seats use?",o:["2-point lap belt","3-point shoulder + lap","4-point like crew","No harness — optional only"],a:1,e:"Passenger seats use a 3-point harness: lap belt and one shoulder strap.",ref:"Ch.14 §3"},
{q:"What makes the EC135 cabin floor suitable for rapid role change?",o:["The floor has built-in cargo nets","The flat, unobstructed cabin floor allows rapid conversion between passenger, cargo, and EMS configurations","The floor has dedicated medical equipment mounting","Folding floor panels create cargo space"],a:1,e:"The EC135's flat, unobstructed cabin floor means seats are quickly removable, enabling conversion between passenger transport, cargo, and EMS/Air Ambulance roles.",ref:"Ch.14 §3"},
{q:"What optional enhancement is available for crew seats in law enforcement/military roles?",o:["Ejection system","Armoured seat panels","Heated seat option","Automatic tightening harness"],a:1,e:"Optional armoured seat panels can be fitted to crew seats for protection against ballistic threats in law enforcement or military operations.",ref:"Ch.14 §2"},
{q:"What is the purpose of the soundproofing panels in the EC135 cabin?",o:["Provide thermal insulation only","Reduce transmitted noise levels to crew and passengers","Provide structural rigidity to the cabin","Are required for water tightness"],a:1,e:"Lightweight composite soundproofing panels are installed on cabin walls, floor, and ceiling to reduce transmitted noise from the main rotor, MGB, and engines to acceptable levels.",ref:"Ch.14 §4"}
],
h:[
{q:"Why does the EC135 use a belt cutter (emergency hammer) rather than a window punch for emergency egress?",o:["Window punches are not approved for composite glass","The EC135 uses composite and polycarbonate windows that are very difficult to break by hand or impact. The primary egress path is through the jettison door mechanism, not window breaking. A belt cutter is more universally useful for freeing trapped, injured, or inverted occupants","Belt cutters are lighter than window punches","Window punches are reserved for maintenance use only"],a:1,e:"EC135 windows are manufactured from polycarbonate or laminated glass composites designed to be highly impact-resistant — they do not break easily under strike. Emergency egress uses the door jettison system. The belt cutter serves the higher-probability need: cutting a jammed or inverted-occupant's harness that cannot be released by normal buckle operation.",ref:"Ch.14 §1"},
{q:"What is the consequence of the portable fire extinguisher pressure gauge showing below the green zone?",o:["No consequence — check pressure every 5 years only","The extinguisher may not have sufficient pressure to discharge effectively — the propellant gas that drives the Halon has leaked. The extinguisher is unserviceable and must be replaced before flight","Use only in serious fires — minor fires should use other methods","Requires a maintenance entry only, not replacement"],a:1,e:"The extinguisher uses compressed nitrogen (or Halon pressure) as propellant. Below-green-zone pressure means insufficient propellant to fully discharge the agent, potentially leaving agent in the bottle when most needed. An unserviceable extinguisher is a go/no-go maintenance item.",ref:"Ch.14 §1"},
{q:"Why does the crew seat require a 4-point harness while passenger seats use only 3-point?",o:["Regulatory difference — pilots require higher protection","Crew seats are crashworthy (energy-absorbing) and require the crotch strap to prevent 'submarining' (sliding under the lap belt in a forward deceleration crash) — a critical failure mode in helicopter crashes. Passenger seats accept the lower protection standard of automotive-equivalent 3-point","Cost difference between crew and passenger areas","4-point harnesses are too wide for passenger seats"],a:1,e:"Crew crashworthiness requirements (EASA CS-27 Appendix B) specify crew seat energy absorption and occupant protection. The crotch strap prevents submarining under the lap belt during the downward deceleration in a hard landing — common in helicopter crashes. Without it, the occupant's pelvis slides forward and under the lap belt, causing serious abdominal injury.",ref:"Ch.14 §2"},
{q:"What does the JAR-OPS 3 standard specify for the EC135 first-aid kit?",o:["Only the kit weight limit","Contents requirements for air ambulance operations","The first-aid kit contents and standards for helicopter commercial air operations — ensuring minimum medical supplies are available for passenger incidents","Only the kit storage location"],a:1,e:"JAR-OPS 3 (now EASA OPS) specifies minimum first-aid equipment for commercial helicopter operations: type and quantity of bandages, medications, instruments, and training materials. DIN 13164 specifies the contents for road vehicles, and the combination ensures appropriate standards for the EC135's mixed operations.",ref:"Ch.14 §1"},
{q:"What structural feature of crew seats provides crashworthiness?",o:["Foam padding only","Energy-absorbing (crash-attenuating) structure in the seat frame that progressively deforms during a crash to limit the deceleration force transmitted to the occupant","The 4-point harness alone provides crashworthiness","Seat mounting bolts are designed to shear at a specific force"],a:1,e:"Crash-attenuating seats have stroking mechanisms (collapsing tubes, crushable materials) that limit the peak G-force the occupant's spine experiences during vertical crash deceleration. The seat absorbs kinetic energy by controlled deformation, preventing spinal compression fractures from the extreme vertical deceleration common in helicopter hard landings.",ref:"Ch.14 §2"},
{q:"If the portable fire extinguisher is discharged during a ground training exercise, what is the airworthiness implication?",o:["No implication — it can be refilled on the ramp","The extinguisher is unserviceable immediately. It must be removed, refilled with Halon 1211 (at a certified facility), re-pressurised, and reinstalled before the aircraft can carry passengers. This is a mandatory maintenance action per the AMM","Can be returned to service after visual inspection","Only the pressure gauge needs to be checked"],a:1,e:"Any extinguisher discharge — training, accidental, or operational — renders it unserviceable. The specific requirements: (1) Remove and replace with a serviceable unit before flight, (2) Discharged unit must go to a Halon servicing facility for decontamination, recharge, and re-pressurisation, (3) Entry in aircraft technical log.",ref:"Ch.14 §1"},
{q:"What is the purpose of the 'High Support Frame' for EC135 passenger seats?",o:["Provides additional armour protection","A frame that combines 3-seat bench sections, distributing the structural load across a wider mounting footprint while maintaining the seat's crashworthiness certification","Provides overhead luggage support","Required for EMS configuration only"],a:1,e:"The High Support Frame (HSF) provides a structural mounting for the 3-seat bench combinations. Without it, three individual seats at three separate mounting points would require more fuselage attachment hardware. The HSF creates a single structural unit that can be removed as one piece for role change.",ref:"Ch.14 §3"},
{q:"Why are the passenger seats designed to be 'quickly removable'?",o:["For weight reduction during solo flights","EC135 operators often use the helicopter for multiple roles: passengers on Monday, medevac stretcher Tuesday, cargo Wednesday. Quick-release seats enable rapid role change between flights without tools or specialized maintenance","Removable seats are lighter in transit","Required for balance adjustment"],a:1,e:"EC135 versatility: the same airframe serves passenger transport, EMS, cargo, law enforcement, and other roles. Quickly removable seats (typically requiring only basic tools or hand-operated fittings) allow the operator to reconfigure between missions without scheduling maintenance downtime.",ref:"Ch.14 §3"},
{q:"What is the purpose of the optional flashlight clamping device at the crew doors?",o:["Secures the flashlight from vibration damage","Provides instant access to the flashlight for the crew during emergency egress — the light is at hand at the door exit point, where it is most needed in a night emergency evacuation","Provides a recharging point for the flashlight","Is an aesthetic mounting for crew convenience"],a:1,e:"Door-mounted flashlight: during night emergency egress, the crew member exiting through the door has immediate access to a light at the door. Floor-stored flashlights may be inaccessible if the helicopter is inverted or the cabin is flooded.",ref:"Ch.14 §1"},
{q:"What is the energy-absorbing mechanism in EC135 crew seat design?",o:["Gel-filled cushions only","Progressive tube collapse or shear deformation in the seat structure that converts kinetic energy to deformation energy, limiting peak vertical deceleration to the spinal tolerance limit","Spring suspension system","Hydraulic strut below the seat pan"],a:1,e:"Crashworthy seat design uses controlled structural collapse — metallic tubes or frangible elements that progressively buckle or shear at a calibrated load. The collapse stroke limits peak deceleration to below the human spinal injury threshold (typically ~14.5 G vertical limit per CS-27). The energy is absorbed mechanically rather than by the occupant's body.",ref:"Ch.14 §2"},
{q:"What is the location significance of placing the first-aid kit on the LH cargo door?",o:["LH door is always unlocked for emergency access","The cargo door location makes the kit accessible from outside (for rescuers) or immediately upon opening the door — accessible without entering the aircraft, important if the cabin is smoke-filled or the door must be opened from outside after a crash","LH door is the only accessible door in all crash attitudes","Weight and balance requires LH placement"],a:1,e:"LH cargo door kit placement: (1) Accessible to external rescuers without entering a potentially dangerous cabin, (2) Crew can access it while remaining partially outside, (3) Accessible from both sides of the door opening, (4) Easy visual inspection during preflight — immediately visible when door is opened.",ref:"Ch.14 §1"},
{q:"The Halon 1211 portable extinguisher is used for Class C (electrical) fires. What precaution applies when using it near avionics or cockpit equipment?",o:["No precaution — Halon is completely safe for all equipment","Halon 1211 leaves minimal residue but is electrically non-conductive and generally safe for electronics. However, in confined spaces the concentration can be high enough to displace oxygen — crew must exit or ventilate after use in the cockpit","Halon permanently damages avionics — do not use in cockpit","Halon must be diluted 50% with water for electrical fires"],a:1,e:"Halon 1211 in confined spaces: (1) At fire-extinguishing concentrations it displaces enough oxygen to reduce breathability, (2) Crew should minimize exposure time, (3) Ventilate the cockpit after discharge, (4) Halon is otherwise effective and non-conductive — suitable for electrical fires and does not damage avionics components.",ref:"Ch.14 §1"},
{q:"What is the difference between standard and EMS (Air Ambulance) cabin configuration?",o:["No difference — same configuration, different registration","EMS configuration removes passenger seats and installs medical equipment (stretcher/litter mounts, medical equipment rails, IV poles, defibrillator mounts) using the standard cabin attachment points","EMS requires a longer fuselage","EMS configuration requires a separate certificate of airworthiness"],a:1,e:"EMS conversion: standard passenger seats are removed from the flat cabin floor. EMS-specific equipment (stretcher mount, medical equipment rail system, monitoring equipment mounts, crew medical seat) are installed using existing cabin floor attachment points and approved equipment installation drawings. The flat floor design was specifically intended to facilitate this role conversion.",ref:"Ch.14 §3"},
{q:"What is the minimum check interval for the portable fire extinguisher?",o:["Weekly visual check","Pre-flight check of the pressure gauge (green zone) and visual condition of the extinguisher body, bracket, and safety pin — required before every flight","Annual hydrostatic test only","Only when the aircraft is at a maintenance facility"],a:1,e:"Pre-flight inspection includes: (1) Pressure gauge in green zone, (2) Safety pin in place and not activated, (3) Extinguisher body undamaged and no signs of corrosion or heat damage, (4) Mounted securely in its bracket. This is a daily/every-flight check — not periodic-only.",ref:"Ch.14 §1"},
{q:"Why is the EC135 interior paneling made of lightweight composite rather than aluminium or steel?",o:["Composite is mandatory per CS-27","Lightweight composite panels: (1) Reduce empty weight, increasing payload capacity, (2) Provide thermal insulation without adding significant weight, (3) Allow soundproofing materials to be integrated, (4) Resist moisture and corrosion, (5) Are easily trimmed and shaped for the cabin contours","Composite panels provide structural reinforcement","Metal panels would fail the flammability test"],a:1,e:"Interior panel weight directly reduces available payload — every kilogram of interior is one less kilogram of revenue load. Composite panels achieve the required stiffness, appearance, and durability at much lower density than metal. They also meet flammability requirements (FAR/CS cabin materials) while integrating acoustic and thermal properties.",ref:"Ch.14 §4"}
]
},

,

// ─────────────────────────────────────────
// CHAPTER 15 — Heating and Ventilation
// ─────────────────────────────────────────
{
m:[
{q:"How is the EC135 cabin heated on helicopters from SN 1000 onward?",o:["Electric resistance heaters","Engine bleed air through a mixing valve","A fuel-fired combustion heater","Hot MGB oil circulation"],a:1,e:"From SN 1000 onward, the EC135 uses engine bleed air mixed with cabin air via an electrically controlled mixing valve to produce conditioned air.",ref:"Ch.15 §2"},
{q:"What type of heating did EC135 aircraft before SN 1000 use?",o:["Electric convection heaters","Engine bleed air only","Combustion heater (fuel-fired)","MGB oil waste heat"],a:2,e:"EC135 aircraft before SN 1000 used a combustion heater — a small unit that burns helicopter fuel to generate cabin heat.",ref:"Ch.15 §1"},
{q:"What does the mixing valve do?",o:["Mixes hydraulic fluid from both systems","Blends hot engine bleed air with cooler cabin air to control temperature","Mixes fuel from both tanks","Blends fresh and recirculated air only"],a:1,e:"The electrically controlled mixing valve blends hot engine bleed air with cooler cabin air to produce the desired cabin temperature.",ref:"Ch.15 §2"},
{q:"What is the function of the air-switch unit?",o:["Switches between electrical buses","Routes conditioned air to either instrument panel nozzles or windscreen defog ducts","Controls the bleed air valve position","Monitors cabin CO₂ levels"],a:1,e:"The air-switch unit directs conditioned air either to the ventilation nozzles in the instrument panel or to the windscreen defog ducts.",ref:"Ch.15 §3"},
{q:"What does the cockpit ventilation blower (fan) do?",o:["Draws engine cooling air","Cools the avionics bay","Draws fresh outside air or recirculates cabin air","Pressurises the hydraulic reservoir"],a:2,e:"The cockpit ventilation blower draws fresh outside air from the intake on the middle access cover, or recirculates cabin air through the recirculation duct.",ref:"Ch.15 §3"},
{q:"What is the crew control for cabin temperature?",o:["A digital keypad","A rotary control on the heating panel — crew selectable","Fixed setting — not adjustable","Thermostat only (automatic)"],a:1,e:"The crew selects cabin temperature via a rotary control on the cockpit heating panel.",ref:"Ch.15 §2"},
{q:"What is the purpose of the windscreen defogging function?",o:["Cool the windscreen in hot weather","Direct warm conditioned air to the windscreen to prevent or remove fogging/icing inside","Wash the windscreen with fluid","Heat the windscreen glass electrically"],a:1,e:"Defog directs warm conditioned air to the windscreen ducts, preventing or removing internal windscreen fogging or icing.",ref:"Ch.15 §4"},
{q:"From which source is bleed air tapped for the heating system?",o:["MGB cooling airflow","Engine compressor stage","Fenestron® airflow","External ram air intake only"],a:1,e:"Bleed air is tapped from the engine compressor stage — a small quantity of compressed air is bled off for cabin heating.",ref:"Ch.15 §2"},
{q:"What ATA chapter covers the EC135 heating and ventilation system?",o:["ATA 12","ATA 21","ATA 26","ATA 30"],a:1,e:"The heating and ventilation system is covered under ATA 21 in the EC135 AMM.",ref:"Ch.15 §2"},
{q:"What is the flap valve in the ventilation system?",o:["Controls airflow to the fuel vents","Selects between fresh outside air and recirculated cabin air","Controls the bleed air flow rate","Opens and closes the engine cowling vents"],a:1,e:"The flap valve selects whether the ventilation blower draws from the outside air intake or from the recirculation duct (recirculated cabin air).",ref:"Ch.15 §3"},
{q:"When should windscreen defog be selected proactively?",o:["Only when fogging has already occurred","Early when fogging is anticipated, e.g. transitioning to cold air or high humidity conditions","Only in below-zero temperatures","Only during IFR flight"],a:1,e:"Defog should be selected early — before fogging occurs — especially when transitioning from warm cabin conditions to cold, humid external air where rapid fogging is expected.",ref:"Ch.15 §4"},
{q:"What happens to ventilation airflow when DEFOG is selected?",o:["Fresh air volume increases","The air-switch unit redirects airflow from the instrument panel nozzles to the windscreen ducts","The bleed air valve closes","The ventilation fan stops"],a:1,e:"When defog is selected, the air-switch unit redirects the warm conditioned air from the panel nozzles to the windscreen ducts, reducing panel ventilation.",ref:"Ch.15 §4"},
{q:"How are the heating and ventilation systems physically arranged?",o:["Fully integrated in one unit","Two separate systems interconnected in the forward bottom fuselage","Both systems are in the tail boom","Only one system — they share all components"],a:1,e:"The heating and ventilation systems are two separate systems that are interconnected in the forward bottom fuselage area.",ref:"Ch.15 §1"},
{q:"What temperature sensing components regulate heating output?",o:["Only the crew's rotary control — no sensors","Temperature sensor and switches that measure output air temperature and regulate the mixing valve","Engine temperature sensors only","Cabin occupant sensors"],a:1,e:"Temperature sensors and switches measure the output conditioned air temperature and regulate the mixing valve position via the control box to maintain the demanded temperature.",ref:"Ch.15 §2"},
{q:"What is the control box in the heating system?",o:["Houses the circuit breakers for the heating system","Processes the temperature demand from the crew's rotary control and regulates the mixing valve accordingly","Is the main ventilation air filter","Controls the engine bleed air valve only"],a:1,e:"The control box processes the temperature demand signal from the crew's rotary control and commands the mixing valve to blend bleed air and cabin air to achieve the desired temperature.",ref:"Ch.15 §2"}
],
h:[
{q:"Why does the bleed air system (SN 1000+) replace the combustion heater? What are the practical advantages?",o:["Bleed air is cheaper than the combustion heater fuel","Bleed air heating eliminates the combustion heater's fuel system, ignition system, and associated maintenance; reduces fire risk (no additional combustion source in the fuselage); uses waste energy from the engine; and improves reliability","Combustion heaters are not approved for twin-engine helicopters","Bleed air provides higher temperatures than combustion heaters"],a:1,e:"Advantages of bleed air over combustion heater: (1) No separate fuel supply needed, (2) No ignition components to maintain, (3) No combustion-related fire risk in the forward fuselage, (4) Uses energy already extracted from the engine (no additional fuel burn for heating), (5) Simpler system with fewer moving parts = higher reliability.",ref:"Ch.15 §1"},
{q:"What is the performance penalty of bleed air extraction from the engine?",o:["No penalty — bleed air is free energy","Extracting compressor bleed air reduces the engine's net power output because compressed air that would otherwise contribute to combustion and power generation is diverted. The FADEC compensates by increasing fuel flow to maintain demanded power, but overall engine efficiency is slightly reduced","Bleed air extraction only affects engine start capability","Bleed air extraction prevents OEI operation"],a:1,e:"Compressor bleed: the extracted air has already been compressed (using turbine work). Bleeding it away means that energy is not available to the combustor. The engine FADEC increases fuel flow to maintain the demanded power — resulting in slightly higher fuel consumption when cabin heat is selected. This is a factor in fuel planning for cold-weather operations.",ref:"Ch.15 §2"},
{q:"Why is the forward bottom fuselage the location for the interconnected heating/ventilation systems?",o:["Required by ATA 21 standard","Forward location minimises duct run length to the cockpit (primary heated/ventilated area), provides shortest bleed air routing from engine to mixing valve, and is easily accessible via the nose panel for maintenance","Forward location reduces weight at the nose","Required by CS-27 fire separation rules"],a:1,e:"Forward placement: (1) Shortest duct runs to the cockpit nozzles and windscreen ducts — minimises heat loss and duct weight, (2) Bleed air lines from engines run naturally to this location, (3) Accessible for maintenance without major disassembly, (4) Gravity drainage of condensation naturally goes forward and down for drainage.",ref:"Ch.15 §1"},
{q:"What happens if the bleed air mixing valve fails in the fully open (hot) position?",o:["The cabin receives no heat","Full hot bleed air is delivered to the cabin without mixing — potentially causing dangerously high cabin temperatures and burns to occupants. The crew must shut off bleed air and manage ventilation manually","The system automatically switches to the combustion heater","A CAUTION is generated and the valve automatically closes"],a:1,e:"Mixing valve stuck fully open: maximum temperature bleed air enters the cabin ducting. Duct temperatures can be high enough to cause burns if touched. Crew action: close the bleed air source, use ventilation fan with fresh outside air for cooling, monitor cabin temperature. This is a potentially hazardous failure requiring immediate crew response.",ref:"Ch.15 §2"},
{q:"Why is recirculation mode available in the ventilation system (in addition to fresh air)?",o:["Recirculation uses less electrical power","In very cold conditions, outside air is too cold even with heating — recirculating the already-warmed cabin air maintains temperature more efficiently. Also useful in dusty/smoky external conditions where fresh air intake would introduce contaminants","Recirculation is the normal mode — fresh air is for emergencies only","Recirculation reduces noise"],a:1,e:"Recirculation uses: (1) In severe cold — outside air requires maximum bleed air to heat. Recirculating already-warm cabin air reduces the heating demand. (2) In external contamination (smoke, dust, fumes near an airport or burning area) — prevents external contaminants from entering the cockpit. (3) Can also reduce external noise ingestion through the intake.",ref:"Ch.15 §3"},
{q:"What is the risk of selecting maximum heat (full bleed) at high altitude where OAT is very cold?",o:["No risk — maximum heat is always safe","At very high altitude, engine power is already reduced. Extracting maximum bleed air further reduces engine power availability, potentially limiting OEI performance margins or affecting cruise performance. The crew must balance cabin comfort against power reserves","Maximum heat improves engine efficiency at altitude","Maximum heat prevents carburetor icing"],a:1,e:"At altitude: (1) Engine power output is already reduced by lower density, (2) Maximum bleed air extraction further reduces the power available, (3) In OEI conditions, the surviving engine already at or near power limits — reducing it further with bleed air extraction could compromise the OEI climb performance. Monitor power margin when using maximum heat at altitude.",ref:"Ch.15 §2"},
{q:"When would the crew select the recirculation duct rather than fresh air intake?",o:["Always — recirculation is more efficient","When external air contains contaminants (smoke, exhaust fumes, sand, dust), when external temperatures are very cold and cabin is already warm, or when the fresh air intake is blocked","Recirculation is for descent only","Only when the bleed air system is off"],a:1,e:"Specific scenarios for recirculation: (1) Flying through or near smoke/fire ground areas, (2) Taxiing behind other aircraft in exhaust fumes, (3) Operating in dusty environments without IBF on the ventilation intake, (4) Very cold outside air where recirculation maintains cabin temperature with less bleed air demand.",ref:"Ch.15 §3"},
{q:"What is the consequence of windscreen fogging during a visual approach?",o:["Slight reduction in forward visibility — manageable","Rapid total loss of forward visibility at the critical phase of flight (low altitude, close to terrain/obstacles, high workload). If the approach is continued without visibility, terrain collision or obstacle strike is likely. The approach must be discontinued if fogging cannot be rapidly cleared","Fogging only affects the copilot's side","The HTAWS compensates for reduced crew visibility"],a:1,e:"Critical phase risk: during a VFR approach, the crew relies entirely on visual reference. Sudden total windscreen fogging at low altitude with terrain close ahead gives very little time to react. The correct response is: simultaneously select DEFOG, climb away from terrain (go-around), and recover visibility before re-attempting the approach.",ref:"Ch.15 §4"},
{q:"If both engines are shut down (e.g., during autorotation), what happens to the bleed air heating system?",o:["Heating continues from stored bleed air pressure","The bleed air source disappears when engines shut down — the heating system provides no heat. The crew relies on insulation and body heat only. This is a minor consideration during the brief autorotation/emergency landing phase","The combustion heater automatically activates","The ventilation fan provides residual heating"],a:1,e:"Engine bleed air is only available when engines are running. Engine shutdown = no bleed = no heat. During autorotation (brief duration), this has minimal operational effect. If engines are shut down for a prolonged period on the ground, crew must manage cold exposure. The ventilation fan can still run on battery if needed for cockpit air circulation.",ref:"Ch.15 §2"},
{q:"How does the temperature control loop function in the bleed air heating system?",o:["Pilot sets temperature and the valve stays at a fixed position","The crew sets a temperature demand. The control box compares actual duct temperature (from temperature sensor) with the demanded temperature. If actual < demanded, the mixing valve opens more toward bleed air. If actual > demanded, it blends more cabin air. This closed-loop regulation continuously maintains the demand temperature","Temperature is adjusted only during ground operations","The FADEC controls bleed air temperature directly"],a:1,e:"Closed-loop control: Demand (rotary control) → Control box compares demand vs. actual (temperature sensor) → Error signal → Mixing valve adjusts blend ratio → New duct temperature → Measured → Compare again. The loop continuously corrects for changes in outside temperature, bleed air temperature variation with engine power, or changes in heat demand.",ref:"Ch.15 §2"},
{q:"What maintenance consideration applies to the bleed air ducting in the EC135?",o:["No maintenance required — sealed system","Bleed air ducting must be inspected for cracks, delamination (if composite), and secure connections at all junctions — a bleed air leak inside the fuselage can cause fire (if near fuel lines), loss of cabin heating, or structural heat damage to surrounding components","Ducting is replaced at each 50-hour check","Only the mixing valve requires maintenance — ducts are permanent"],a:1,e:"Bleed air duct integrity is airworthiness-critical: (1) A hot bleed air leak inside the fuselage is a fire hazard near fuel lines or composite structure, (2) Leaks reduce cabin heating effectiveness, (3) Hot air can damage nearby components (wiring insulation, composite panels), (4) The AMM specifies inspection intervals and leak detection methods for all bleed air connections.",ref:"Ch.15 §2"},
{q:"What is the difference between 'heating' and 'ventilation' in the EC135 system context?",o:["There is no difference — they are the same system","Heating system: produces and delivers conditioned (warm) air using bleed air and mixing valve — primary temperature control. Ventilation system: circulates air (fresh or recirculated) for fresh air supply and comfort, independent of heating — operates using the ventilation blower","Heating is for winter; ventilation is for summer only","Ventilation only applies to the passenger cabin; heating to cockpit only"],a:1,e:"Two distinct functions: (1) HEATING — thermal control using bleed air blend, regulated by mixing valve and temperature sensor, output temperature-controlled. (2) VENTILATION — air movement for fresh air, CO₂ management, and comfort, using the blower and flap valve. They are interconnected (same ducts used) but functionally separate — ventilation can run without heating and vice versa.",ref:"Ch.15 §1"},
{q:"Why would the defog reduce instrument panel nozzle airflow while active?",o:["The AMC automatically reduces nozzle flow for safety","The air-switch unit directs the same airflow to either the panel nozzles OR the windscreen ducts — it is a switching unit, not an adding unit. The total airflow from the heating system is finite. Selecting defog redirects it from the panel to the windscreen","Instrument panel nozzles are closed during defog for avionics cooling","Defog increases total airflow so nozzles are not affected"],a:1,e:"The air-switch unit is a flow diverter — not a flow multiplier. Total conditioned airflow is fixed by the blower and bleed air system capacity. Selecting defog redirects this fixed airflow to the windscreen ducts, reducing what reaches the panel nozzles. Crew must choose between panel ventilation comfort and windscreen defog based on the dominant need.",ref:"Ch.15 §4"},
{q:"What is the significance of the bleed air heating being effective only while engines are running versus the combustion heater?",o:["No significance — both systems work identically","The combustion heater could operate on the ground with engines off (running on fuel from the main tank) for pre-warming the cabin. Bleed air heating requires engines running — no ground pre-warming capability without engines. This affects cold-weather operations where pre-warming the cabin before flight improves crew comfort and defogging","The combustion heater is more powerful","Bleed air is available for longer on the ground"],a:1,e:"Combustion heater operational advantage: pre-warm the cabin before engine start in extreme cold (useful for EMS, law enforcement standby, Arctic operations). Bleed air system requires engine start first — cabin heating begins only after engines are running and producing bleed air. Modern EC135 operators in cold climates may use ground heating equipment to compensate for this limitation.",ref:"Ch.15 §1"}
]
},

// ─────────────────────────────────────────
// CHAPTER 16 — Avionics Generalities
// ─────────────────────────────────────────
{
m:[
{q:"What transponder mode does the EC135 use?",o:["Mode A only","Mode C only","Mode S","Mode 3/A only"],a:2,e:"The EC135 uses a Mode S transponder, which supports selective addressing, altitude reporting (Mode C), and optional ADS-B out.",ref:"Ch.16 §5"},
{q:"On which frequencies does the EC135 ELT transmit in distress?",o:["243 MHz and 406 MHz","121.5 MHz and 406 MHz","121.5 MHz only","406 MHz only"],a:1,e:"The EC135 ELT transmits on 121.5 MHz (aviation guard frequency) and 406 MHz (COSPAS-SARSAT satellite detection).",ref:"Ch.16 §5"},
{q:"What does the Radar Altimeter measure?",o:["Barometric altitude above MSL","True altitude above sea level","Actual height above ground (AGL) using radar","GPS altitude above WGS-84 ellipsoid"],a:2,e:"The radar altimeter measures true height above the terrain directly below by timing radar pulses — not barometric pressure.",ref:"Ch.16 §4"},
{q:"What does DVCS 6100 stand for?",o:["Digital Voice Communication System 6100","Digital VHF Control System 6100","Dual Volume Cockpit System 6100","Direct Voice Call System 6100"],a:0,e:"DVCS 6100 = Digital Voice Communication System 6100 — the EC135 intercom system for crew-to-crew and crew-to-passenger communication.",ref:"Ch.16 §1"},
{q:"What navigation system provides bearing from a VHF ground station?",o:["ADF","GPS","VOR (VHF Omnidirectional Range)","DME"],a:2,e:"VOR (VHF Omnidirectional Range) provides magnetic bearing from a VHF ground navigation station, displayed on the NAVD and FND.",ref:"Ch.16 §3"},
{q:"What frequency range do the EC135 VHF COM radios cover?",o:["108–118 MHz","118–136.975 MHz","136–156 MHz","225–400 MHz"],a:1,e:"The VHF AM communication radios cover 118–136.975 MHz with 25 kHz channel spacing (8.33 kHz optional).",ref:"Ch.16 §2"},
{q:"How many VHF COM radios does the EC135 have?",o:["1","2","3","4"],a:1,e:"Two VHF AM COM radios provide primary and backup air-ground voice communication.",ref:"Ch.16 §2"},
{q:"What does ILS provide for approach guidance?",o:["Lateral guidance only (LOC)","Vertical guidance only (G/S)","Both lateral (LOC) and vertical (G/S) approach guidance","Only distance information (DME)"],a:2,e:"ILS provides both: LOC (Localizer) for lateral deviation guidance and G/S (Glide Slope) for vertical deviation guidance during precision approaches.",ref:"Ch.16 §3"},
{q:"What is DME?",o:["Direct Mode Entry","Distance Measuring Equipment","Digital Map Equipment","Directional Microwave Emitter"],a:1,e:"DME = Distance Measuring Equipment. It provides slant range distance from a ground DME beacon.",ref:"Ch.16 §1"},
{q:"Where are EC135 avionics units primarily located?",o:["Throughout the tail boom","On the avionics deck (nose), slant console, and centre console","Only in the overhead console","Under the cabin floor"],a:1,e:"EC135 avionics are located on the avionics deck (nose section), the slant console, and the centre console.",ref:"Ch.16 §1"},
{q:"What guard frequency is monitored by the EC135 VHF COM?",o:["118.0 MHz","121.5 MHz","123.45 MHz","156.8 MHz"],a:1,e:"121.5 MHz is the international aviation distress/guard frequency. The EC135 VHF COM can monitor guard frequency simultaneously.",ref:"Ch.16 §2"},
{q:"What does ADF stand for and what does it use?",o:["Automatic Direction Finder — uses NDB (Non-Directional Beacon)","Automatic Digital Frequency — uses GPS","Airborne Direction Finder — uses VOR","Advanced Data Feed — uses satellite"],a:0,e:"ADF = Automatic Direction Finder. It uses NDB (Non-Directional Beacon) ground stations that broadcast in the LF/MF frequency band.",ref:"Ch.16 §1"},
{q:"What does ADS-B stand for?",o:["Automatic Direction-finding Surveillance-Broadcast","Automatic Dependent Surveillance-Broadcast","Advanced Digital Surveillance Beacon","Airborne Data Synchronisation Broadcast"],a:1,e:"ADS-B = Automatic Dependent Surveillance-Broadcast — a surveillance technology where aircraft broadcast their position, altitude, and identity.",ref:"Ch.16 §5"},
{q:"What activates the ELT automatically?",o:["Low altitude below 500 ft","A G-switch activated by crash impact forces","Engine failure","Activation of the fire warning"],a:1,e:"The ELT is automatically activated by a G-switch that triggers upon detecting the high-G deceleration forces of a crash impact.",ref:"Ch.16 §5"},
{q:"What standard does the EC135 GPS use for navigation data display?",o:["Displayed on a dedicated GPS screen only","GPS data is integrated with FMS in Helionix® — position, track, and ground speed displayed on the NAVD","GPS displays on the ILS receiver only","GPS only feeds the transponder"],a:1,e:"GPS is integrated with the Helionix® FMS. GPS position, track, and ground speed are displayed on the NAVD (Navigation Display) and used for FMS-based navigation.",ref:"Ch.16 §4"}
],
h:[
{q:"What is the functional difference between Mode S and Mode C transponder capability?",o:["Mode S and Mode C are identical","Mode C adds pressure altitude encoding to Mode A identity squawk. Mode S adds selective addressing (ground station interrogates specific aircraft by ICAO address), data link capability, and is the foundation for ADS-B — Mode C cannot support these functions","Mode S reduces the transponder's range","Mode C is older and less accurate than Mode S"],a:1,e:"Mode C: identity + pressure altitude. Mode S: all of Mode C + ICAO unique 24-bit aircraft address (selective interrogation by ground radar), data link (uplink/downlink), and the platform for ADS-B out. Mode S enables the modern surveillance architecture — each aircraft can be individually interrogated, reducing radar reply congestion.",ref:"Ch.16 §5"},
{q:"Why does the EC135 ELT transmit on both 121.5 MHz and 406 MHz?",o:["Two frequencies provide redundancy","121.5 MHz provides immediate detection by overflying aircraft/ATC (within range); 406 MHz provides COSPAS-SARSAT satellite detection covering remote areas with no VHF coverage. Together they cover both short-range immediate alerting and long-range search and rescue notification","406 MHz is for primary signal; 121.5 MHz is for homing only","121.5 MHz is for civil aircraft; 406 MHz is for military only"],a:1,e:"Complementary roles: 121.5 MHz — overflying aircraft or ATC within VHF range (~150 nm) can receive and home immediately. 406 MHz — satellites detect and locate the signal globally within minutes, regardless of VHF coverage. Together: rapid initial alert locally + reliable global notification for SAR.",ref:"Ch.16 §5"},
{q:"What is the risk of an inadvertent ELT activation during ground testing?",o:["No risk — brief test transmissions are automatically filtered by COSPAS-SARSAT","A continuous 406 MHz signal will be detected by COSPAS-SARSAT satellites within minutes, generating a real SAR alert. ATC and SAR authorities respond as for a genuine distress signal — wasting significant resources. The operator must immediately notify ATC and the responsible SAR authority. Fines and penalties may apply","Test transmissions last only 1 second and are ignored","Only 121.5 MHz requires reporting — 406 MHz tests are authorised"],a:1,e:"COSPAS-SARSAT satellites cannot distinguish a brief accidental transmission from a genuine distress signal. Any 406 MHz activation triggers a SAR response. Correct test procedure: brief test using the TEST switch (one second maximum), ideally at the top of the hour and notified to ATC in advance. Any unintended activation must be immediately reported to ATC.",ref:"Ch.16 §5"},
{q:"How does DGPS improve on standard GPS accuracy and what EC135 operation benefits from it?",o:["DGPS doubles the GPS satellite count","DGPS uses ground reference stations that know their exact position; they measure GPS errors in real-time and broadcast corrections. Accuracy improves from ~3–5 m to <1 m. Benefits EC135 precision approaches (RNP/GNSS approaches) that require accuracy better than standard GPS can provide","DGPS provides altitude accuracy only","DGPS is the same as standard GPS — just a different abbreviation"],a:1,e:"DGPS (Differential GPS): ground station at a known location measures GPS error continuously and broadcasts corrections. Aircraft GPS receiver applies corrections, dramatically improving position accuracy. This enables: precision GNSS approaches (RNAV/RNP with LPV or LNAV/VNAV minimums), offshore operations where precise hover position is critical, and law enforcement tracking applications.",ref:"Ch.16 §4"},
{q:"How does VOR bearing differ from ADF bearing in terms of reference?",o:["No difference — both provide magnetic bearing","VOR provides magnetic bearing FROM the station (radial) regardless of aircraft heading — it is a fixed reference. ADF provides the RELATIVE bearing of the NDB station from the aircraft's nose — changes with aircraft heading","VOR uses True North; ADF uses Magnetic North","ADF provides bearing from the station; VOR provides bearing to the station"],a:1,e:"VOR radial: the magnetic bearing FROM the station (e.g., 270° radial = aircraft is to the west of the station, regardless of aircraft heading). ADF Relative Bearing: angle from aircraft nose to the station — must add magnetic heading to get magnetic bearing to station. VOR is therefore much simpler to interpret for navigation without mental arithmetic.",ref:"Ch.16 §3"},
{q:"What advantage does the slant console location provide for communication/navigation management?",o:["Slant console location reduces weight","The slant console is in the centre of the cockpit between pilot and copilot — accessible by either crew member for frequency selection, mode changes, and navigation input without requiring one pilot to reach across the other","Slant console is required by EASA for dual-crew helicopters","Slant console reduces cable run lengths"],a:1,e:"Shared access: the slant console is positioned geometrically between both seats. Either pilot can reach frequency selectors, transponder, navigation controls, and radio management without compromising their primary flight instruments scan or requiring awkward cross-cockpit reach. This is important for crew workload sharing and CRM.",ref:"Ch.16 §1"},
{q:"What is the purpose of marker beacons in the EC135 avionics suite?",o:["Provide distance from the destination airport","Provide position fixes at specific points on an ILS approach — outer marker (~4–7 nm), middle marker (~0.5 nm), and inner marker (at threshold) — indicated by audio tones and visual lights on the instrument panel","Are used instead of DME in the EC135","Provide weather information along the route"],a:1,e:"Marker beacons receive signals from ground markers at specific points on an ILS approach. Tones and lights distinguish outer (400 Hz / blue), middle (1300 Hz / amber), and inner (3000 Hz / white) markers. They provide position confirmation along the approach without requiring a DME measurement.",ref:"Ch.16 §1"},
{q:"If the radar altimeter is not functioning, which AFCS modes are affected?",o:["No modes are affected","CRHT (Cruise Height/terrain following) and approach modes that use radar height as a control variable are affected — they cannot engage or maintain radar height reference. Approach modes needing Decision Height reference also lose an input","Only the FND altitude display is affected","The radar altimeter only affects transponder altitude reporting"],a:1,e:"Radar altimeter-dependent AFCS modes: CRHT (Cruise Height hold — uses RadAlt to maintain height above terrain), and some approach modes that use RadAlt for Decision Height alerting or height-above-threshold reference. Loss of RadAlt in IMC significantly degrades approach capability, particularly for operations requiring low Decision Heights.",ref:"Ch.16 §4"},
{q:"What is the difference between LOC (Localizer) and VOR in terms of frequency and signal type?",o:["LOC and VOR are identical — just different names","LOC uses frequencies 108–111.95 MHz (even tenths) with a course deviation signal. VOR uses 108–117.95 MHz (odd tenths above 108 MHz) with an omnidirectional bearing signal. A single VHF NAV receiver handles both — frequency selection determines whether LOC or VOR is decoded","LOC uses UHF; VOR uses VHF","LOC provides bearing; VOR provides course deviation"],a:1,e:"Both are in the VHF range. Receiver auto-detects the signal type from the frequency: even-tenth decimals above 108 MHz = ILS LOC, odd-tenth decimals above 108 MHz = VOR. LOC provides a single-course deviation signal aligned with the runway. VOR provides 360 radials from the station. One combined VHF NAV receiver handles both.",ref:"Ch.16 §3"},
{q:"Why does Mode S transponder use a unique 24-bit ICAO address for each aircraft?",o:["To encrypt the transponder signal","The 24-bit address (over 16 million unique codes) allows ATC automation to link all transponder returns unambiguously to a single specific aircraft — enabling flight plan correlation, conflict alerting (ACAS/TCAS), and ADS-B tracking. Mode A squawk codes are only 4096 possibilities and reused globally","To prevent transponder interference between nearby aircraft","The 24-bit code determines the pilot's licence number"],a:1,e:"ICAO 24-bit address: globally unique to one aircraft (assigned by the State of registry). Allows: (1) Unambiguous ATC surveillance tracking without squawk code conflicts, (2) ACAS/TCAS peer-to-peer interrogation of specific aircraft, (3) ADS-B position broadcasts tagged to one specific aircraft, (4) Automatic flight plan correlation in ATC automation systems.",ref:"Ch.16 §5"},
{q:"In the EC135 VHF COM system, what is the 8.33 kHz channel spacing option used for?",o:["Military communications only","European airspace above FL195 mandates 8.33 kHz spacing to accommodate the higher traffic density in upper airspace — providing approximately 3× more channels than 25 kHz spacing in the same frequency band","8.33 kHz is for helicopter-specific frequencies only","Reduces electrical noise in the radios"],a:1,e:"8.33 kHz spacing: Europe (EASA) mandated 8.33 kHz above FL195 (later extended to FL085 and below in some regions) to triple the number of available VHF COM channels. This addresses spectrum congestion from increased traffic. EC135 operating in European airspace requires an 8.33 kHz capable radio.",ref:"Ch.16 §2"},
{q:"What operational limitation applies to ADF/NDB navigation compared to VOR?",o:["ADF has shorter range than VOR","NDB signals are affected by: thunderstorm static (needle swings to storm), coastal refraction (bearing error near coastlines), night effect (signal bouncing off ionosphere), and terrain effects. VOR is less susceptible to these errors. ADF is therefore less precise and should be treated as supplementary navigation","ADF cannot display on the NAVD","ADF requires special pilot certification"],a:1,e:"ADF limitations: (1) Thunderstorm interference — needle attracted to nearby electrical storms (dangerous near convective weather), (2) Coastal effect — refraction of MF signals at coastlines causes bearing errors, (3) Night effect — atmospheric refraction causes bearing errors at night, (4) Mountains — terrain reflections. VOR (VHF) is much less susceptible to these errors.",ref:"Ch.16 §3"},
{q:"What is the purpose of the Helionix® interface to the avionics bus (ARINC 429)?",o:["Only for display purposes","ARINC 429 is the standard avionics digital data bus. All navigation sensors (VOR, ILS, GPS, ADF, DME) transmit their processed data over ARINC 429 to the AMCs. The AMC integrates these inputs for FND/NAVD display and provides AFCS with navigation guidance signals","ARINC 429 is only used for weather radar","ARINC 429 provides the transponder data link"],a:1,e:"ARINC 429 is the backbone digital bus: each avionics box transmits its data (bearing, course deviation, distance, position) to the AMC via ARINC 429. The AMC integrates all navigation data for display on MFDs and for AFCS navigation mode (VOR tracking, LOC/GS coupling, FMS navigation). This standardised bus allows different equipment suppliers' boxes to communicate.",ref:"Ch.16 §1"},
{q:"How does the EC135 GPS integrate with the AFCS for navigation?",o:["GPS provides position to pilot display only — no AFCS connection","GPS position and track data flows to the Helionix® FMS via ARINC 429. The FMS computes cross-track error and desired track. These outputs are sent to the AFCS, which uses them for NAV (FMS navigation), TRK (track hold), FPA (flight path angle), and GTC (GPS-guided approach to hover) modes","GPS only controls the NAVD display — AFCS uses VOR only","GPS is independent of the AFCS — must be coupled manually"],a:1,e:"GPS → Helionix® FMS → cross-track deviation + track reference → AFCS AMC → SEMA trim actuators drive aircraft along FMS route. This integration enables IFR navigation without ground-based navaids: RNAV routes, GPS approaches, and GTC helicopter GPS approaches. The quality of navigation depends on GPS signal integrity monitoring within the FMS.",ref:"Ch.16 §4"}
]
},

// ─────────────────────────────────────────
// CHAPTER 17 — Electrical System
// ─────────────────────────────────────────
{
m:[
{q:"What is the voltage of the EC135 DC electrical system?",o:["14 V DC","24 V DC","28 V DC","48 V DC"],a:2,e:"The EC135 uses a fully redundant 28 V DC electrical system — the standard for modern helicopters and military aircraft.",ref:"Ch.17 §1"},
{q:"What dual function do EC135 starter/generators serve?",o:["Generator and battery charger","Starter during engine start then Generator after","Hydraulic pump and generator","Generator and inverter"],a:1,e:"EC135 Starter/Generators operate as starters during engine start (drawing battery current), then automatically switch to generator mode once the engine reaches self-sustaining speed.",ref:"Ch.17 §1"},
{q:"What does EPSU stand for?",o:["External Power Supply Unit","Emergency Power Supply Unit","Electrical Protection System Unit","Engine Power Sensor Unit"],a:1,e:"EPSU = Emergency Power Supply Unit — the standby battery that powers the Emergency Bus if all main power sources fail.",ref:"Ch.17 §3"},
{q:"What is the purpose of the Bus Tie contactor?",o:["Isolates the two buses in all conditions","Allows a single operating generator to power both Bus 1 and Bus 2 sides","Provides ground fault protection","Connects batteries to the Emergency Bus"],a:1,e:"The Bus Tie contactor electrically joins Bus 1 and Bus 2 together, allowing a single remaining generator to supply both sides of the electrical system.",ref:"Ch.17 §4"},
{q:"What type of batteries does the EC135 use?",o:["Lead-acid","Lithium-ion","NiCd (Nickel-Cadmium)","Lithium-polymer"],a:2,e:"The EC135 uses NiCd (Nickel-Cadmium) batteries — the main battery type for helicopter and aviation applications due to reliable performance across wide temperature ranges.",ref:"Ch.17 §1"},
{q:"What are SHED buses used for?",o:["Supply essential flight systems","Power AMC computers","Supply non-essential loads that are automatically disconnected in abnormal conditions","Supply only high-current consumers"],a:2,e:"SHED buses supply non-essential loads (e.g., cabin lighting, entertainment) that are automatically shed (disconnected) when the electrical system is in a degraded state.",ref:"Ch.17 §2"},
{q:"What is the rated current of each EC135 starter/generator?",o:["100 A","200 A","300 A","400 A"],a:2,e:"Each EC135 Starter/Generator is rated at approximately 300 A in generator mode.",ref:"Ch.17 §1"},
{q:"What is the BMB?",o:["Bus Master Battery","Battery Master Box — monitors battery temperature and discharge","Backup Motor Bus","Battery Management Buffer"],a:1,e:"BMB = Battery Master Box. It monitors the NiCd battery temperature and discharge state, providing thermal protection and state-of-charge information.",ref:"Ch.17 §3"},
{q:"What connects to the Emergency Bus?",o:["All aircraft systems","Only the EPSU standby battery provides Emergency Bus power when all main sources fail","Only the main battery","Only one generator"],a:1,e:"The Emergency Bus is powered by the EPSU standby battery — it provides minimum essential systems when all generators and main batteries are depleted or disconnected.",ref:"Ch.17 §3"},
{q:"What does external GPU provide?",o:["Engine start air","Ground Power Unit — 28V DC power for aircraft systems without using onboard battery or generators","Hydraulic pressure for ground checks","Pneumatic power for bleed tests"],a:1,e:"A GPU (Ground Power Unit) provides 28 V DC power via the external power receptacle, allowing ground operation of aircraft systems without using the onboard battery or requiring engine starts.",ref:"Ch.17 §4"},
{q:"What is the optional AC power system on the EC135?",o:["A dedicated AC generator on the MGB","An inverter that produces 115 V AC 400 Hz from the DC system","A fuel cell for AC generation","An external AC transformer"],a:1,e:"An optional inverter converts 28 V DC to 115 V AC at 400 Hz for equipment that requires AC power (e.g., some weather radar or navigation equipment).",ref:"Ch.17 §4"},
{q:"What is the AMC Bus?",o:["The main power bus for all systems","Dedicated supply bus for the Helionix® AMC computers","Alternative Main Circuit bus","Auxiliary Motor Control bus"],a:1,e:"The AMC Bus is a dedicated supply bus for the Helionix® Aircraft Management Computers — ensuring the avionics system has priority power supply.",ref:"Ch.17 §2"},
{q:"How many generators does the EC135 have?",o:["1","2","3","4"],a:1,e:"The EC135 has 2 Starter/Generators — one per engine — providing fully redundant generation.",ref:"Ch.17 §1"},
{q:"What is the purpose of High Load Buses?",o:["Supply emergency systems only","Supply high-current consumers such as heating systems","Supply the AMC computers","Supply only the batteries"],a:1,e:"High Load Buses supply high-current consumers such as the anti-icing heating elements, windshield wiper, and other high-current loads.",ref:"Ch.17 §2"},
{q:"How many main NiCd batteries does the EC135 have?",o:["1","2","3","4"],a:1,e:"The EC135 has 2 main NiCd batteries providing starting power and backup generation capability.",ref:"Ch.17 §1"}
],
h:[
{q:"Why does the EC135 use NiCd batteries rather than lead-acid batteries?",o:["NiCd is lighter and cheaper","NiCd advantages: (1) Better performance across wide temperature range (-40°C to +70°C), (2) Higher charge/discharge cycle life, (3) More consistent capacity at high discharge rates (engine start), (4) Lower internal resistance = better high-current delivery for starter/generator. Lead-acid degrades more rapidly in aviation temperature extremes","NiCd provides higher voltage","NiCd does not require maintenance"],a:1,e:"Aviation NiCd batteries: high-current delivery capability (important for starter loads), wide temperature performance, long cycle life, and consistent capacity. The compromise is thermal runaway risk (must be monitored by BMB) and the requirement for controlled discharge/charge cycles. Lead-acid is cheaper but less suitable for high-demand aviation applications.",ref:"Ch.17 §1"},
{q:"What is the risk of NiCd battery thermal runaway and how does the BMB protect against it?",o:["NiCd batteries cannot have thermal runaway","Thermal runaway: excessive current → heat → faster chemical reaction → more current → more heat → chain reaction potentially causing fire. BMB monitors battery temperature continuously; if temperature rises abnormally, it triggers a CAUTION (or BATTERY OVERHEAT warning), alerting crew to disconnect the battery before thermal runaway develops","BMB only monitors voltage — not temperature","Thermal runaway is prevented by the circuit breakers alone"],a:1,e:"NiCd thermal runaway occurs when internal short circuits or overcharging cause an uncontrolled exothermic reaction. BMB temperature monitoring is the primary protection: if battery temperature rises above the threshold during charging or operation, the crew is alerted and can isolate the battery before thermal runaway — which could cause fire in the electrical bay.",ref:"Ch.17 §3"},
{q:"In a dual-generator failure scenario, what is the sequence of electrical system degradation?",o:["Immediate and total power loss","Generators fail → batteries power Main buses → as batteries deplete, SHED buses are disconnected → further depletion triggers loss of Main buses → EPSU provides Emergency Bus only until it depletes","Generators fail → EPSU activates immediately → battery stays on standby","Generators fail → system continues normally on batteries for 4 hours"],a:1,e:"Degradation sequence: (1) Both generators fail → batteries take over Main bus loads, (2) As battery voltage drops, SHED loads may be shed automatically, (3) Continued battery depletion → Main bus voltage drops below threshold → Main buses disconnect, (4) EPSU activates → Emergency Bus only → minimum essential systems until EPSU depletes. Crew must identify and act on each stage to extend duration.",ref:"Ch.17 §2"},
{q:"What is the significance of the Bus Tie contactor in a single-generator failure scenario?",o:["Bus Tie has no function in single generator failure","Bus Tie closes to connect Bus 1 to Bus 2 — the remaining single generator now supplies both bus sides through the tie. Without Bus Tie, the bus on the failed generator side would be unpowered, leaving half the aircraft's systems without power despite having one functional generator","Bus Tie disconnects the failed generator","Bus Tie only connects the batteries"],a:1,e:"Single generator failure → Bus Tie closes: the working generator's bus connects to the unpowered bus, restoring power to all dual-bus systems from one source. SHED loads may be automatically shed to reduce total load on the single generator. Crew confirms Bus Tie is closed and monitors single generator load.",ref:"Ch.17 §4"},
{q:"Why are there separate ESS (Essential) buses distinct from Main buses?",o:["Essential buses provide higher voltage","If the main generator fails and the bus tie is insufficient, or a main bus fault occurs, Essential bus architecture ensures flight-critical systems remain powered from a separate protected source — even if the main bus has a fault (short circuit) that would cause its protective device to disconnect it","Essential buses have higher current capacity","ESS buses are for the crew; Main buses are for passengers"],a:1,e:"Essential bus separation provides fault isolation: a short circuit on a Main bus would trip its protection, disconnecting Main bus loads. Separately fed Essential buses remain powered from the same or alternate source, ensuring flight-critical systems (AFCS, primary avionics, fire detection) remain operative even with a Main bus fault.",ref:"Ch.17 §2"},
{q:"How does the Starter/Generator automatically transition from starter to generator mode?",o:["The crew manually selects GEN mode after each start","During start: battery current flows through the S/G to turn the engine. When engine speed reaches self-sustaining RPM, the starter function is no longer needed. An automatic voltage-sensing relay detects when the S/G output voltage exceeds the battery voltage (meaning the engine is spinning it fast enough to generate) and automatically switches the contactor from START to GEN circuit","The FADEC commands the transition","Transition requires both engines running"],a:1,e:"Automatic transition: (1) Battery powers starter function until engine reaches self-sustaining speed, (2) As engine accelerates, S/G output voltage rises, (3) At a set voltage threshold (above battery voltage), an automatic relay disconnects the start circuit and connects the generator circuit, (4) The generator now provides power to the buses and charges the battery — no crew action required.",ref:"Ch.17 §1"},
{q:"What is the purpose of having two separate electrical buses (Bus 1 and Bus 2)?",o:["Two buses allow twice the current capacity","Dual bus architecture: a fault (short circuit, fire) on Bus 1 causes Bus 1 protective device to trip, isolating Bus 1. Bus 2 continues to power its connected loads normally — providing half the systems on Bus 2 while Bus 1 fault is isolated. Without dual buses, a single bus fault would cause total electrical failure","Bus 1 is for pilot systems; Bus 2 is for copilot systems only","Bus 1 and 2 are always connected — they are effectively one bus"],a:1,e:"Dual-bus redundancy: (1) Physical separation of wiring and distribution, (2) Fault isolation — a fault or fire on one bus doesn't cascade to the other, (3) Each bus has its own protection (circuit breakers, contactors), (4) Critical systems are duplicated with one on each bus (e.g., AHRS 1 on Bus 1, AHRS 2 on Bus 2). This is fundamental avionics/electrical redundancy architecture.",ref:"Ch.17 §2"},
{q:"What happens when the STANDBY BATT (EPSU) switch is selected ON in a normal electrical situation?",o:["It charges the EPSU from the main bus","EPSU takes over all electrical supply","It arms the EPSU so it will automatically supply the Emergency Bus if main power falls below a set threshold — it does not disconnect the main power immediately","It disconnects all SHED loads"],a:2,e:"EPSU switch ON = armed mode. In normal operation with generators running, the EPSU sits in standby, monitoring bus voltage. If main bus voltage collapses below the threshold (generators failed, buses depleted), the EPSU automatically connects to the Emergency Bus. It does not actively power anything in normal operation — it is a self-activating backup.",ref:"Ch.17 §3"},
{q:"Why does the EC135 have a dedicated AMC Bus rather than powering the AMC computers from the Main or Essential buses?",o:["Cost reduction — fewer bus types needed","A dedicated AMC Bus ensures the Helionix® computers always receive clean, stable power with priority protection — isolated from load variations and transients on the Main and Essential buses. A spike or voltage fluctuation on the main bus (from large loads switching) cannot corrupt AMC operation","AMC Bus provides AC power to the AMC computers","The AMC Bus is a regulatory requirement"],a:1,e:"Avionics power quality: computers are sensitive to voltage spikes and transients from switching loads (generators engaging, high-current loads activating). A dedicated AMC Bus with its own regulation and filtering ensures clean, stable 28V DC for the Helionix® IMA. This is critical for software integrity and correct sensor processing — a corrupted AMC could cause incorrect flight data or AFCS commands.",ref:"Ch.17 §2"},
{q:"What is the risk of connecting a faulty or over-voltage GPU to the EC135?",o:["No risk — the GPU receptacle has automatic protection","An over-voltage GPU (output > 28 V DC + tolerance) can: damage avionics equipment, corrupt memory in AMC computers, damage battery charging circuits, or cause NiCd battery thermal runaway from overcurrent charging. The GPU must be checked for correct voltage and polarity BEFORE connection","GPU can be any voltage — aircraft regulators compensate","Only voltage below 24 V creates risk"],a:1,e:"GPU verification: always confirm GPU voltage is within 28 V DC ± tolerance before connecting. The aircraft's own electrical system protects against minor transients, but sustained over-voltage bypasses these protections and reaches sensitive avionics directly. GPU polarity must also be confirmed — reverse polarity causes immediate and severe damage to solid-state components.",ref:"Ch.17 §4"},
{q:"In a complete electrical failure with EPSU active, what specific systems remain available?",o:["All systems continue normally","Only the minimum essential flight systems: typically one AHRS (attitude reference), one AMC (reduced capability), fire warning system, emergency lighting, one COM radio, and essential engine control — the minimum required to safely descend and land","Only the fire warning system","Engine FADEC continues but all other systems fail"],a:1,e:"Emergency Bus philosophy: provide the minimum required for safe flight to landing. Typically: (1) Attitude reference (IESI or one AHRS), (2) Fire detection and warning, (3) Engine control (FADEC on alternator power for ARRIUS, or battery-backed for PW), (4) One COM radio, (5) Essential instrument (altimeter, IAS). The crew must shed all non-essential loads immediately to extend EPSU duration.",ref:"Ch.17 §3"},
{q:"What is the function of circuit breakers in the EC135 electrical system compared to fuses?",o:["They are identical in function","Circuit breakers (CBs) are resettable overcurrent protection devices. When tripped, the crew can reset them if appropriate. Fuses (one-time use) cannot be reset. CBs also provide manual switch function — deliberately pulling a CB isolates a circuit without a switch. In aircraft, CBs are preferred because: (1) Resettable for transient faults, (2) Pull-able for deliberate isolation, (3) Visible trip status","Fuses are faster to blow — CBs are slower","Circuit breakers are only in the overhead console; fuses are elsewhere"],a:1,e:"CB advantages: resettable after transient overload (without accessing remote fuse holder), visible trip indication (button pops out), manually pullable to isolate a misbehaving system (e.g., pulling avionics CB in smoke situation), no need to carry spare fuses. Aircraft CBs are carefully rated — do NOT reset a tripped CB more than once without investigation, as a persistent fault can cause fire.",ref:"Ch.17 §2"},
{q:"How does the battery charging circuit work when the generator is running?",o:["Generator charges the battery via a direct connection — no regulation","Generator output (regulated 28 V DC) is applied to the battery bus. Since NiCd battery terminal voltage is slightly below the regulated generator output, current flows from generator to battery — charging it. A battery charge current limiter prevents excessive charge current that would cause overheating (BMB monitors)","Batteries are charged only on the ground via GPU","Charging is manual — crew selects charge mode"],a:1,e:"Battery charging: regulated 28V DC bus > battery terminal voltage → natural current flow from generator to battery. The BMB monitors charge current and temperature. If temperature rises excessively (overcharging), the BMB alerts crew. The battery acts as a voltage stabiliser — absorbing transients and providing instantaneous high-current capability for loads like radio PTT keying.",ref:"Ch.17 §3"},
{q:"Why is 28 V DC the standard for helicopter electrical systems rather than lower voltages?",o:["28 V was chosen arbitrarily","28 V DC originated from WWII military standardisation (2× 12V lead-acid batteries). At 28 V, wire gauge can be smaller than at 12 V for the same power (P=IV — half the current = quarter the resistive loss = lighter wiring). This became the international military and civil helicopter standard","28 V is the only voltage supported by NiCd chemistry","Higher voltage requires fewer safety measures"],a:1,e:"28 V practical reasons: (1) For a given power, higher voltage = lower current = smaller wiring gauge = lighter harness (critical for aircraft weight), (2) Military standardisation (WWII onwards) enabled interoperable ground equipment, (3) NiCd and lead-acid battery voltages combine naturally to 24-28 V nominal, (4) Solid-state electronics are easily powered from 28 V. Higher voltages (270 V DC in some military) reduce weight further but require more safety precautions.",ref:"Ch.17 §1"}
]
},

// ─────────────────────────────────────────
// CHAPTER 18 — Inspections
// ─────────────────────────────────────────
{
m:[
{q:"Which inspection method uses dye to detect surface cracks?",o:["Magnetic particle inspection","Penetrant crack inspection","Ultrasonic inspection","Eddy current inspection"],a:1,e:"Penetrant crack inspection uses dye penetrant that seeps into surface-breaking cracks, then developer draws it out for visible detection under UV or white light.",ref:"Ch.18 §1"},
{q:"Who can perform the EC135 preflight check?",o:["Only a licensed engineer","Only the aircraft captain","The pilot or a licensed mechanic","Any flight crew member or ground crew"],a:2,e:"The preflight check can be performed by the pilot (PIC) or a licensed mechanic. Items marked ★ must be checked before EACH flight.",ref:"Ch.18 §2"},
{q:"What document governs EC135 scheduled inspections?",o:["Flight Manual (AFM)","AMM Chapter 05","EASA CS-27","ATA 104 Standard"],a:1,e:"Scheduled inspections are governed by AMM (Aircraft Maintenance Manual) Chapter 05, which defines all check intervals, tasks, and tolerances.",ref:"Ch.18 §2"},
{q:"What is the purpose of a functional test?",o:["Check external appearance of components","Verify correct operation of systems/subsystems","Detect material cracks","Measure component dimensions"],a:1,e:"A functional test verifies that a unit, system, or subsystem operates correctly — for example, an engine ground run or hydraulic system pressure test.",ref:"Ch.18 §1"},
{q:"What is the Continuous Maintenance Program (CMP)?",o:["A program to monitor engine health continuously","Splitting major checks into smaller packages spread over time to reduce downtime","An online training record system","Automatic FADEC self-test monitoring"],a:1,e:"The CMP divides the 300/600-hour checks into smaller task packages spread over shorter intervals, keeping the aircraft flying while maintenance is performed incrementally.",ref:"Ch.18 §3"},
{q:"What periodic inspection interval follows directly after daily checks for the EC135?",o:["25-hour check","50-hour check","100-hour check","150-hour check"],a:1,e:"The 50-hour check is the first periodic inspection interval after the daily/A-check.",ref:"Ch.18 §2"},
{q:"What must be recorded in the aircraft log book after any inspection?",o:["Only defects found","Date, airframe total hours, inspector signature, licence number, defects found, and rectification","Only the inspector's name","Date and type of check only"],a:1,e:"All inspections must be recorded with: date and time, airframe total hours, inspector's signature and licence number, defects found, and rectification actions taken.",ref:"Ch.18 §3"},
{q:"What are the four types of inspections used on the EC135?",o:["Check A, Check B, Check C, Check D","Visual, Condition, Functional test, Inspection for cracks","Preflight, Daily, 50-hour, Annual","Internal, External, Major, Minor"],a:1,e:"The EC135 inspection system defines four types: Visual, Condition, Functional Test, and Inspection for Cracks.",ref:"Ch.18 §1"},
{q:"What does a visual inspection involve?",o:["Removal of all panels and parts for detailed check","External condition check without removing parts — identifies obvious damage, leaks, deformation, missing hardware","Full disassembly and measurement","X-ray or NDT only"],a:1,e:"A visual inspection is an external condition check without removing parts. It identifies obvious damage, leaks, deformation, corrosion, and missing hardware.",ref:"Ch.18 §1"},
{q:"What distinguishes a condition inspection from a visual inspection?",o:["Condition inspection is shorter","Condition inspection is an extended visual that may require removal of parts and use of measuring instruments — checks for corrosion, wear, and secure installation in more detail","They are identical","Condition inspection requires a licensed engineer only"],a:1,e:"A condition inspection goes beyond visual: it may require removing access panels or parts to inspect internal surfaces, and may use measuring instruments to quantify wear or dimensional deviations.",ref:"Ch.18 §1"},
{q:"What are the three methods for crack inspection on the EC135?",o:["Visual, Radiographic, and Magnetic particle","Visual, Penetrant dye, and Magnetic particle","Ultrasonic, Eddy current, and Penetrant","Visual, Ultrasonic, and Radiographic"],a:1,e:"The EC135 inspection system uses three crack detection methods: visual (bare eye/magnifying glass), penetrant crack inspection (dye penetrant), and magnetic particle inspection.",ref:"Ch.18 §1"},
{q:"What calendar-based inspection covers the EC135?",o:["6-month inspection","Annual inspection","18-month inspection","2-year inspection"],a:1,e:"An annual inspection provides a comprehensive calendar-based check of the EC135, supplementing the flight-hour-based checks.",ref:"Ch.18 §2"},
{q:"Who must perform EC135 maintenance?",o:["Trained pilots during their preflight inspection","Any qualified aircraft technician","Licensed engineers in accordance with the approved AMM and applicable Airworthiness Directives","Only Airbus-authorised service centres"],a:2,e:"All maintenance must be performed by a licensed engineer in accordance with the approved AMM and any applicable Airworthiness Directives (ADs).",ref:"Ch.18 §3"},
{q:"What does the ★ symbol next to an item in the EC135 Flight Manual preflight check indicate?",o:["Optional check","Requires a licensed engineer","Must be checked before EACH flight (not just the first of the day)","Airworthiness Directive compliance item"],a:2,e:"Items marked ★ in the preflight check must be performed before EVERY flight during the day, not just the first one.",ref:"Ch.18 §2"},
{q:"How many flight-hour based major check intervals does the EC135 have?",o:["50hr only","50hr and 300hr","50hr, 300hr, and 600hr","25hr, 50hr, 100hr, 300hr"],a:2,e:"The EC135 has periodic inspection intervals at 50 hours, 300 hours, and 600 hours, plus the annual calendar-based inspection.",ref:"Ch.18 §2"}
],
h:[
{q:"What is the principle behind magnetic particle crack inspection, and when is it used on the EC135?",o:["Magnetic fields destroy cracks — it is a repair method","Ferromagnetic components are magnetised; iron particles applied to the surface concentrate at field discontinuities (cracks). Used on EC135 steel and ferromagnetic components: landing gear fittings, drive shaft flanges, and other steel structural items. Does NOT work on aluminium or composite","Magnetic particles are glued into cracks for repair","Used to measure component hardness"],a:1,e:"Magnetic particle inspection (MPI): (1) Component is magnetised, (2) Fine iron particles (wet or dry) are applied, (3) At a crack, the magnetic field leaks out at the surface, attracting and holding particles at the crack line, (4) Under UV or white light, cracks are visible as particle accumulation lines. Limited to ferromagnetic materials — aluminium and composites use penetrant or ultrasonic instead.",ref:"Ch.18 §1"},
{q:"What is the difference between an Airworthiness Directive (AD) and a regular AMM maintenance task?",o:["They are the same thing","ADs are MANDATORY legally-binding airworthiness requirements issued by the regulatory authority (EASA/FAA) in response to identified unsafe conditions. Non-compliance grounds the aircraft. Regular AMM tasks are manufacturer-recommended maintenance for continued serviceability — non-compliance affects airworthiness but through operator decision, not regulatory mandate","Regular AMM tasks are more important than ADs","ADs apply only to engines; AMM covers the airframe"],a:1,e:"Critical distinction: (1) AD = regulatory requirement, legally mandated, specific compliance timeline, non-compliance = aircraft unairworthy by law. (2) AMM task = manufacturer recommendation based on engineering analysis, operator has some discretion (MEL-governed). ADs often impose additional or more frequent inspection requirements beyond standard AMM schedules when a specific unsafe condition is identified in service.",ref:"Ch.18 §3"},
{q:"Why might a penetrant crack inspection give a false positive (indicate a crack where none exists)?",o:["Penetrant testing never gives false positives","Surface contamination (oil, grease), corrosion pitting, tool marks, forging laps, or porosity in castings can retain penetrant and produce indications that mimic cracks. Proper surface preparation (cleaning, degreasing) before penetrant application is critical to avoid misleading false positive indications","False positives only occur on composite materials","Penetrant indicators always represent real cracks"],a:1,e:"False positive sources: (1) Oil/grease in surface discontinuities retains penetrant after wiping, (2) Corrosion pits retain penetrant — look like tight cracks, (3) Manufacturing features (forging laps, cold shuts, porosity) are not flight-critical defects but may show as penetrant indications. Experienced inspectors distinguish true cracks (sharp-edged, linear, defined endpoints) from false indications through shape, depth, and repeatability.",ref:"Ch.18 §1"},
{q:"What is the legal consequence of performing maintenance on an EC135 without a licensed engineer signing the maintenance release?",o:["A warning letter from the authority","The aircraft is not airworthy — it cannot legally fly. Any flight would be an illegal operation. The operator is liable for civil penalties, and insurance may be void. If an incident occurs, criminal liability for the person who authorised the flight is possible","Only a documentation deficiency — flyable pending paperwork","Requires a test flight to confirm airworthiness"],a:1,e:"Without a valid maintenance release from a licensed engineer: (1) The aircraft's Certificate of Airworthiness is suspended, (2) Any subsequent flight is an illegal operation under EASA Part M (or equivalent), (3) Insurance is void, (4) If an accident occurs, the operator/PIC may face criminal charges for operating an unairworthy aircraft. This applies even for apparently simple tasks.",ref:"Ch.18 §3"},
{q:"How does the CMP (Continuous Maintenance Program) maintain airworthiness while reducing aircraft downtime?",o:["CMP defers maintenance indefinitely","CMP divides a major check (e.g., 600-hour) into multiple smaller task packages, each completed at shorter intervals (e.g., every 100 hours over 6 intervals). All tasks are completed before the 600-hour total is reached — the aircraft never goes out of service for a long check, but all required maintenance is still completed within the certified interval","CMP allows some tasks to be skipped entirely","CMP replaces all scheduled maintenance with condition monitoring"],a:1,e:"CMP example: a 300-hour check has 100 task packages. CMP distributes them: 33 tasks at each 100-hour interval. By 300 hours, all tasks are complete — same as a traditional 300-hour check. No single long out-of-service event. The aircraft completes shorter 100-hour checks, each with a portion of 300-hour tasks included. AMM approval required for CMP implementation.",ref:"Ch.18 §3"},
{q:"What is the significance of the ★ preflight items that require checking before EACH flight?",o:["They are optional advisory items","These items are safety-critical conditions that can CHANGE between flights during the same day (e.g., fuel quantity, oil level, tie-down removal, control lock removal, system functional state). Checking only before the first flight could miss a condition that changed during a turnaround (refueling error, oil leak during previous flight, door not secured after passenger loading)","★ items are for the first flight after maintenance only","★ items are checked by the licensed engineer, not the pilot"],a:1,e:"Between-flight changes that ★ items catch: (1) Oil leaked during previous flight → low oil level, (2) Control lock inadvertently left on from ground handling, (3) Fuel quantity different from expected after refueling, (4) Passenger door not fully secured after loading/unloading, (5) New defect or fluid leak from previous flight. A first-flight-only check would miss these.",ref:"Ch.18 §2"},
{q:"What happens if a defect is found during a 50-hour inspection that cannot be immediately rectified?",o:["The aircraft continues on a test flight to assess the defect","The defect is recorded in the technical log. Continued airworthiness depends on whether the defect is covered by the MEL (Minimum Equipment List) with approved dispatch conditions and time limits. If not MEL-approved, the aircraft is grounded until the defect is rectified by a licensed engineer","The pilot can accept the defect at their discretion","The defect is deferred to the next 50-hour inspection"],a:1,e:"Defect management: (1) Record in tech log, (2) Check MEL for dispatch authorisation — MEL defines conditions under which the aircraft can fly with specific inoperative items (with possible operational restrictions and repair time limits), (3) If not covered by MEL or dispatch conditions not met: aircraft grounded, (4) Rectification by licensed engineer, new maintenance release required before next flight.",ref:"Ch.18 §2"},
{q:"What is the purpose of recording airframe total hours in the maintenance log?",o:["For billing purposes only","Airframe total hours (also called Total Time in Service — TTIS) tracks cumulative component usage against life limits. Life-limited components (e.g., MGB housing, rotor head fittings, landing gear crosstubes) have mandatory replacement at defined total hours — regardless of apparent condition. Accurate hour recording is essential for life-limited component management","Only engine hours matter — airframe hours are advisory","For insurance purposes only"],a:1,e:"Life-limited parts (LLPs): components with known fatigue life. The manufacturer certifies them to a maximum number of hours (or cycles). Beyond this limit, hidden fatigue cracks may exist even if the part looks perfect. Removing and replacing at the life limit is mandatory. Inaccurate TTIS records mean LLPs may be operated beyond their certified life — an immediately serious airworthiness issue.",ref:"Ch.18 §3"},
{q:"Why is the annual calendar-based inspection used in addition to flight-hour checks?",o:["Annual inspection covers more items than 600-hour checks","Some degradation mechanisms are time-based rather than usage-based: rubber seal deterioration, chemical corrosion, lubricant degradation, battery capacity reduction, and sealant/adhesive degradation occur on calendar time regardless of flight hours. A helicopter with very few annual hours may still need seal replacement, battery check, and corrosion inspection","Annual inspection is only for high-utilisation aircraft","Annual inspection replaces 600-hour checks"],a:1,e:"Calendar-based degradation: (1) Rubber seals age and harden regardless of usage — can cause hydraulic/fuel leaks after a set time, (2) Corrosion advances with moisture exposure in storage/low-use, (3) Battery capacity reduces with calendar time (not just cycles), (4) Adhesives and sealants have shelf life and in-service life, (5) Lubricant chemical breakdown over time. A low-hours helicopter stored for 11 months may need more calendar-based maintenance than a high-hours aircraft flown daily.",ref:"Ch.18 §2"},
{q:"What specific training or qualification must an inspector have to perform penetrant crack inspection on EC135 components?",o:["Any licensed aircraft engineer can perform penetrant inspection","NDT (Non-Destructive Testing) Level 1 or 2 certification (typically to EN 4179 / NAS 410) in the penetrant method. The inspector must be qualified for the specific material type and component category. Not all licensed engineers are qualified for all NDT methods — the qualification is separate from the base engineering licence","Penetrant inspection is a pilot preflight item requiring no special qualification","Only Airbus factory inspectors may perform penetrant inspection"],a:1,e:"NDT qualifications are separate from the basic licence: (1) Level 1 — can perform inspection under supervision, (2) Level 2 — can perform, evaluate, and report independently, (3) Level 3 — can develop procedures and qualify Level 1/2 personnel. Standards: EN 4179 (European) or NAS 410 (American). Without proper NDT qualification, an inspector's findings cannot be used as an airworthiness release basis.",ref:"Ch.18 §1"},
{q:"If the aircraft log book is lost, what is the airworthiness status of the EC135?",o:["The aircraft can continue flying — records can be reconstructed","The aircraft cannot fly until its total time in service, component hours, maintenance history, and last maintenance release can be reconstructed to the satisfaction of the competent authority (EASA/CAA). This is a complex, costly process. Without a verified maintenance history, LLPs may be at unknown life status — the aircraft is grounded","Only engine records are needed — airframe log is advisory","Fly for 10 hours then establish new log records"],a:1,e:"Lost records consequences: (1) LLP status unknown — possibly at or past life limits, (2) Last maintenance release unknown — cannot prove airworthiness, (3) AD compliance status unknown, (4) Component histories unknown — possible unrecorded damage history. Reconstruction requires: engine manufacturer records, previous operator records, physical inspection of components, and regulatory authority approval. Until cleared, the aircraft is unairworthy.",ref:"Ch.18 §3"},
{q:"What is the meaning of 'condition monitoring' as a maintenance philosophy, and does it apply to all EC135 components?",o:["Condition monitoring means no scheduled maintenance is required","Condition monitoring: the component is monitored in service (vibration analysis, oil spectrometry, borescope inspection) and replaced when deteriorating towards failure, rather than at a fixed interval. Does NOT apply to Life-Limited Parts (LLPs) — these have mandatory hard time limits regardless of condition. EC135 uses a mix: hard-time LLPs + on-condition for many consumable and non-structural items","All EC135 components use condition monitoring","Condition monitoring only applies to engines"],a:1,e:"EC135 maintenance uses multiple philosophies: (1) Hard-time: mandatory replacement at defined hours/cycles for LLPs and time-limited components, (2) On-condition: inspection at scheduled intervals, continue if condition is within limits, replace if deteriorated, (3) Condition monitoring (for some systems): continuous or scheduled health monitoring. The critical safety components (rotor head, MGB fittings, landing gear) use hard-time replacement regardless of apparent condition.",ref:"Ch.18 §2"},
{q:"What is the inspector's responsibility if they find a defect that is NOT listed in the AMM as requiring repair?",o:["If not in the AMM, ignore the defect","If a defect is found that is not covered by existing AMM repair data, the inspector must: report it to the operator's quality system, contact Airbus Helicopters for a repair assessment or engineering order, and not release the aircraft until an approved repair scheme is defined. Undocumented damage cannot be self-assessed as acceptable","The pilot makes the airworthiness decision","Any defect not in the AMM can be accepted at the engineer's discretion"],a:1,e:"Novel or undocumented defects require Manufacturer (Airbus Helicopters) input: they have the structural analysis capability and design authority to assess whether the defect is acceptable, repairable, and if so, what the approved repair procedure is. The engineer's role is to identify, document, and report — not to self-certify a repair for damage outside the AMM.",ref:"Ch.18 §1"}
]
},

// ─────────────────────────────────────────
// CHAPTER 19 — Autopilot (AFCS)
// ─────────────────────────────────────────
{
m:[
{q:"What is the difference between SAS and AFCS?",o:["SAS is the autopilot; AFCS is the stability system","SAS provides basic rate-damping; AFCS adds upper modes like ALT, HDG, IAS holds","AFCS uses EHA actuators; SAS uses SEMA trim actuators","SAS is pilot-engaged; AFCS is always active"],a:1,e:"SAS provides basic rate-damping (always active). AFCS adds upper-mode automation (ALT hold, HDG, IAS, approaches) via the SEMAs on top of the SAS.",ref:"Ch.19 §1"},
{q:"What type of actuators do AFCS trim (upper-mode) functions use?",o:["EHA (Electro-Hydraulic Actuators)","Mechano-Hydraulic Actuators (MHA)","SEMA (Smart Electro-Mechanical Actuators)","Direct hydraulic servo actuators"],a:2,e:"AFCS upper modes (ALT, HDG, etc.) use SEMAs (Smart Electro-Mechanical Actuators) — electric trim actuators operating in parallel with the pilot inputs.",ref:"Ch.19 §3"},
{q:"What mode automatically captures and holds a pre-selected altitude?",o:["ALT (Altitude Hold)","V/S (Vertical Speed)","ALT.A (Altitude Acquire)","CRHT (Cruise Height)"],a:2,e:"ALT.A (Altitude Acquire) commands a climb or descent to a pre-selected altitude then automatically transitions to ALT hold when reached.",ref:"Ch.19 §4"},
{q:"What does CRHT mode maintain?",o:["Barometric altitude above MSL","GPS altitude","Radar altimeter height above terrain","Cabin pressure altitude"],a:2,e:"CRHT (Cruise Height) uses the radar altimeter to maintain a constant height above the terrain — useful for low-level operations.",ref:"Ch.19 §4"},
{q:"What is GTC HOVER mode used for?",o:["Automatic engine shutdown in hover","GPS-guided approach to and maintenance of a stabilised hover","Hovering in strong crosswinds manually","Automatic power management in hover"],a:1,e:"GTC HOVER (Ground Trajectory Command Hover) uses GPS to guide the aircraft along a computed trajectory to arrive at and hold a stabilised hover over a GPS point.",ref:"Ch.19 §5"},
{q:"What are the two computers that run the AFCS algorithms?",o:["ECB and DTD","Two AMCs (Aircraft Management Computers)","Two FADECs","One AMC and one ECB"],a:1,e:"The AFCS algorithms run in the two AMCs (Aircraft Management Computers) — part of the Helionix® IMA.",ref:"Ch.19 §1"},
{q:"What is the ECB in the AFCS architecture?",o:["Emergency Control Box","Engine Control Bus","Engine Control Box — interface between AMC and actuators","Electronic Circuit Breaker"],a:2,e:"ECB = Engine Control Box. It is the interface unit between the AMC (which runs the AFCS algorithms) and the physical SEMA and EHA actuators.",ref:"Ch.19 §1"},
{q:"What is the primary attitude sensor for the AFCS?",o:["ADU 3200","Radar altimeter","AHRS 1 (primary) with AHRS 2 as backup","GPS receiver"],a:2,e:"AHRS 1 is the primary attitude and heading reference for the AFCS. AHRS 2 provides redundancy.",ref:"Ch.19 §2"},
{q:"What does the APCP provide?",o:["Automatic Power Control Panel — controls engine power","Autopilot Control Panel — the crew interface for engaging AFCS modes","Air Pressure Compensation Panel","Automatic Pitch Control Panel"],a:1,e:"APCP = Autopilot Control Panel. It is the crew interface for selecting and engaging AFCS modes (ATT, ALT, HDG, IAS, etc.).",ref:"Ch.19 §4"},
{q:"What is ATT mode?",o:["Automatic Takeoff mode","Attitude Hold — maintains pitch and roll attitude when cyclic is released","Altitude Target mode","Auto Trim Trim mode"],a:1,e:"ATT = Attitude Hold. When engaged, the AFCS maintains the pitch and roll attitude that existed at the moment of engagement.",ref:"Ch.19 §4"},
{q:"What sensor does the AFCS use for IAS hold mode?",o:["Radar altimeter","GPS ground speed","ADU 3200 (Air Data Unit) for Indicated Airspeed","Pitot pressure direct input only"],a:2,e:"The ADU 3200 (Air Data Unit) provides Indicated Airspeed data to the AFCS for IAS hold and capture modes.",ref:"Ch.19 §2"},
{q:"What is the GA (Go-Around) mode?",o:["Ground Alert mode — sends distress signal","Go-Around — AFCS commands a specific attitude and power for go-around from an approach","Generator Arm mode","Gyro Alignment mode"],a:1,e:"GA = Go-Around mode. The AFCS commands the appropriate nose-up attitude and power setting for a go-around from an instrument approach.",ref:"Ch.19 §4"},
{q:"What is RNP in the EC135 AFCS context?",o:["Required Navigation Performance — precision approach mode using satellite navigation","Radio Navigation Panel","Radar Navigation Protocol","Reduced No Power mode"],a:0,e:"RNP = Required Navigation Performance mode — a precision RNAV approach mode that uses GPS/FMS navigation and AFCS coupling for approaches with specific accuracy requirements.",ref:"Ch.19 §5"},
{q:"What is the V/S mode?",o:["VOR Slope mode","Vertical Speed — maintains a selected rate of climb or descent","VHF Standby mode","Variable Speed mode"],a:1,e:"V/S = Vertical Speed mode. The AFCS maintains the selected climb or descent rate (feet per minute) until another mode engages or the mode is disengaged.",ref:"Ch.19 §4"},
{q:"What happens to the AFCS upper modes if a SEMA on one axis fails?",o:["Total AFCS failure — all modes disengage","That axis loses AFCS authority but SAS (EHA) continues. The pilot retains full manual control","AFCS switches to the other SEMA","The ECB takes over that axis"],a:1,e:"A SEMA failure means the AFCS cannot trim that control axis. Upper modes on that axis disengage, but SAS (EHA) continues rate-damping and the pilot retains full manual authority.",ref:"Ch.19 §3"}
],
h:[
{q:"What is the engineering reason EHAs are used for SAS while SEMAs are used for AFCS upper modes?",o:["SEMAs are more powerful than EHAs","SAS requires HIGH BANDWIDTH (fast, small corrections many times per second to damp rate changes) — only hydraulic actuators can respond fast enough. AFCS upper modes require HIGH AUTHORITY with lower bandwidth (slow, sustained trim position changes) — electric actuators are ideal for this. EHA speed/hydraulic force for SAS; SEMA precision/electric for trim","Cost difference only","EHAs fail less frequently than SEMAs"],a:1,e:"Bandwidth vs. authority: (1) SAS rate damping: pilot inputs a movement → helicopter starts to roll → SAS must correct within milliseconds. Only hydraulics can apply the force fast enough (100+ Hz bandwidth). (2) AFCS upper modes: ALT hold applies a slow, sustained trim correction to maintain altitude — no need for high-speed response. Electric SEMAs can hold a precise position for extended time with low power consumption.",ref:"Ch.19 §3"},
{q:"How does the AFCS ATT mode respond when the pilot applies a cyclic input?",o:["ATT mode rejects all pilot inputs — must be disengaged to manoeuvre","The pilot's cyclic input overrides the ATT mode SEMA (because pilot mechanical force > SEMA authority). When the pilot releases the cyclic, ATT mode captures the NEW attitude and holds it — not the original attitude. This 'beep trim' behaviour allows intuitive attitude changes without mode disengagement","ATT mode is automatically disengaged by any cyclic input","ATT mode slowly returns to the original attitude after pilot input"],a:1,e:"ATT mode beep-trim: pilot applies cyclic → overrides SEMA → aircraft moves to new attitude → pilot releases cyclic → ATT mode captures new attitude and holds. This allows manoeuvring without disengaging ATT — the mode continuously re-arms to the latest attitude. Trim switches can also reposition the ATT datum without manual cyclic input.",ref:"Ch.19 §4"},
{q:"What is the role of the ADU 3200 in AFCS operations beyond IAS hold?",o:["Only for IAS hold mode","ADU 3200 provides: IAS (for IAS hold/capture), altitude (for ALT hold/acquire), vertical speed (for V/S mode and ALT.A transition), and OAT. All altitude-based and speed-based AFCS modes depend on ADU data — an ADU failure degrades or removes multiple AFCS modes simultaneously","ADU provides only altitude data","ADU provides only GPS altitude"],a:1,e:"ADU 3200 provides: (1) IAS → IAS hold mode, (2) Barometric altitude → ALT hold/ALT.A, (3) Vertical speed (baro rate) → V/S mode and ALT.A transition logic, (4) OAT → density altitude for performance calculations. ADU failure affects ALL modes requiring airspeed or altitude reference — a significant AFCS capability reduction.",ref:"Ch.19 §2"},
{q:"During a LOC/GS ILS approach with AFCS coupled, what is the crew's primary responsibility?",o:["Hands off — the AFCS flies the complete approach autonomously","Monitoring: verify AFCS is tracking LOC and GS correctly, confirm the aircraft follows the expected approach geometry, be ready to take manual control if AFCS deviates or disengages, maintain radio and ATC communication, call decision height, and execute missed approach or landing as appropriate. The AFCS assists — the pilot is still PIC and responsible","Only manage power — AFCS handles everything else","Only monitor altitude — AFCS manages lateral tracking"],a:1,e:"AFCS-coupled approach crew duties: (1) Confirm LOC capture (needle centering + AFCS mode annunciation), (2) Confirm GS capture at the appropriate intercept point, (3) Monitor approach geometry vs. expected (VASI/PAPI, radar altimeter trend), (4) Monitor AFCS mode status on MFD, (5) Call DH and make land/go-around decision, (6) Manage power (AFCS may not control collective in all modes), (7) Be instantly ready to take over if AFCS disengages.",ref:"Ch.19 §5"},
{q:"What is the difference between VOR mode and NAV mode in the AFCS?",o:["VOR tracks ground-based VOR radials; NAV uses FMS/GPS for en-route navigation — the sensor differs but both provide lateral track guidance to the AFCS","They are identical — different names for the same mode","NAV mode is only for ILS; VOR is for VOR approaches only","VOR is a vertical mode; NAV is a lateral mode"],a:0,e:"VOR mode: AFCS couples to the VOR course deviation signal from the VOR receiver — tracks a specific VOR radial. NAV mode: AFCS couples to the FMS cross-track deviation — follows an FMS/GPS-defined route regardless of navaid type. VOR = ground-based navaid coupling; NAV = FMS/GPS-based routing.",ref:"Ch.19 §5"},
{q:"What safety mechanism prevents the AFCS from attempting a manoeuvre that exceeds the aircraft's structural limits?",o:["The AFCS has no structural protection — it relies on pilot monitoring","AFCS authority limits (maximum SEMA travel limits) prevent any single AFCS input from commanding extreme control positions. Additionally, the AFCS algorithms have built-in rate limits and attitude limits. The AFCS cannot command bank angles or pitch attitudes beyond the defined limits — if these would be needed to maintain a mode, the mode disengages instead","The AFCS structural protection is provided by the FADEC","Rotor speed limits prevent structural overstress automatically"],a:1,e:"AFCS protection: (1) SEMA authority limits — maximum trim deflection prevents extreme control positions, (2) Attitude limits — AFCS algorithms include maximum bank and pitch attitude limits (typically 30° bank, defined pitch range), (3) Rate limits — maximum rate of control input to prevent sudden attitude changes, (4) Mode disengagement if reference signal is lost or invalid. These limits are defined in the AFCS design certification.",ref:"Ch.19 §1"},
{q:"How does the FPA (Flight Path Angle) mode differ from ILS G/S capture?",o:["They are identical — both use glide slope signal","FPA maintains a constant geometric descent angle (e.g., -3°) referenced to the aircraft's inertial/GPS trajectory — requires no ground-based glide slope transmitter. ILS G/S captures and tracks the ILS radio glide slope beam (2.5°–3.5° from the transmitter). FPA is used for GPS/GNSS approaches where ILS is not available","FPA is for fixed-wing only; G/S is for helicopters","FPA requires a glide slope transmitter; G/S does not"],a:1,e:"FPA: GPS/inertial-referenced fixed descent angle — independent of ground navaids, used for RNAV/GPS approaches. ILS G/S: radio beam coupled — accuracy depends on ILS signal quality and approach category. FPA provides consistent angle regardless of wind or distance; ILS G/S accuracy degrades with distance from the antenna. FPA enables approaches at airfields without ILS.",ref:"Ch.19 §5"},
{q:"What is the specific risk of CRHT (Cruise Height) mode operation in hilly or mountainous terrain?",o:["No additional risk — CRHT adapts to terrain profile","CRHT maintains a fixed height above the terrain DIRECTLY BELOW the aircraft using the radar altimeter. It does NOT provide terrain avoidance: approaching a valley wall from a distance will not trigger a descent — the radar is looking straight down, not forward. The crew must maintain visual terrain clearance; CRHT provides AGL height stability, not collision avoidance","CRHT uses HTAWS to avoid terrain automatically","CRHT only works over flat terrain"],a:1,e:"CRHT critical limitation: radar altimeter points straight down. If flying toward a rising terrain feature (hill, escarpment) at 100 ft AGL, CRHT maintains 100 ft above the terrain directly below — not in front. The rising terrain will be encountered at the same AGL height until it is directly below the aircraft. CRHT provides no forward terrain protection — continuous visual terrain scan and HTAWS remain essential.",ref:"Ch.19 §4"},
{q:"What AFCS pre-flight test is required before IFR flight?",o:["No pre-flight test is required","AFCS self-test initiated from the APCP or VMS SYST page verifies SEMA function on all axes, EHA response, AHRS data validity, ADU data, and mode engagement logic. Any failure detected grounds the aircraft for IFR operation — full AFCS capability is required for IFR","Only the AHRS alignment check is needed","The pre-flight test is optional for experienced crews"],a:1,e:"AFCS IFR pre-flight test: mandatory. Tests: (1) SEMA integrity on each axis (pitch, roll, collective, yaw), (2) EHA function, (3) Sensor validity (AHRS, ADU, RadAlt), (4) Mode logic. Any AFCS failure detected = AFCS unserviceable for IFR. The test takes approximately 2–3 minutes and must be completed before each IFR flight.",ref:"Ch.19 §1"},
{q:"How does the AFCS manage the transition from ALT.A to ALT hold at the target altitude?",o:["The pilot manually selects ALT mode when the altitude is reached","The AMC continuously monitors barometric altitude vs. the pre-selected target. As the aircraft approaches the target altitude within a defined capture window, the AMC commands a smooth deceleration of the climb/descent rate (using V/S control) to arrive at the target altitude with near-zero vertical speed, then seamlessly transitions to ALT hold — no pilot action required","ALT.A activates ALT automatically only if the aircraft is exactly at the target altitude","FADEC reduces power automatically at the target altitude to initiate the level-off"],a:1,e:"ALT.A capture algorithm: (1) Climbing/descending at demanded V/S toward target altitude, (2) At a computed distance before target (based on current V/S and inertia), AMC begins reducing V/S smoothly, (3) Aircraft approaches target altitude with decreasing V/S, (4) At target altitude, V/S ≈ 0 → seamless transition to ALT hold, (5) No altitude overshoot. The capture distance is computed each update cycle to account for changing conditions.",ref:"Ch.19 §4"},
{q:"What is the consequence of AHRS 1 failure on AFCS capability?",o:["No consequence — AHRS 2 seamlessly takes over with no mode change","AHRS 1 is primary — failure causes AFCS to switch to AHRS 2. A CAUTION is generated. If AHRS 2 data matches AHRS 1 prior data (consistency check passed), most AFCS modes continue on AHRS 2. If both AHRS have failed or are inconsistent: all AFCS attitude-based modes disengage — only modes not requiring attitude reference (e.g., ALT baro hold if altitude data is from ADU alone) may continue","AHRS 1 failure causes immediate total AFCS failure","AFCS continues without any indication of AHRS 1 failure"],a:1,e:"Dual AHRS provides operational continuity: (1) AHRS 1 failure → CAUTION, automatic switch to AHRS 2, (2) AFCS evaluates AHRS 2 data quality — if valid, modes continue, (3) If both AHRS failed/unreliable: attitude-based modes (ATT, HDG, LOC, G/S, etc.) disengage — cannot hold attitude without a reference. The IESI provides standby attitude for manual flight reference.",ref:"Ch.19 §2"},
{q:"What is the AFCS engagement philosophy regarding pilot override authority?",o:["Once engaged, the pilot cannot override the AFCS without disengaging it","The AFCS is always subordinate to the pilot. Any pilot input on the controls overrides the AFCS for that axis (SEMAs have limited authority that pilot force exceeds). The pilot never needs to 'fight' the AFCS — they simply apply the desired input and the AFCS follows. Dedicated AFCS disconnect switches on the cyclic and collective also provide instant disengagement","The AFCS cannot be overridden — it must be disengaged via the APCP only","AFCS override requires both pilot and copilot action simultaneously"],a:1,e:"Pilot authority principle: (1) SEMAs have limited travel authority — pilot force always wins, (2) Beep trim allows attitude repositioning without disengagement, (3) Quick Release Button (QRB) on cyclic provides instant AFCS upper-mode disconnect, (4) Force limiter in some modes prevents the AFCS from working against the pilot if they apply a correction. AFCS is a pilot aid — never an override.",ref:"Ch.19 §3"},
{q:"How does the TRK (Track) mode function differently from HDG (Heading) mode?",o:["They are identical — TRK and HDG are the same mode","HDG maintains a magnetic heading — the aircraft points in the selected direction regardless of wind (wind causes drift = track ≠ heading). TRK maintains the GPS ground track — AFCS corrects for wind automatically, keeping the aircraft over the selected GPS track line. TRK mode provides actual over-ground navigation; HDG mode provides directional flying without drift correction","TRK is for fixed-wing; HDG is for helicopter only","HDG uses GPS; TRK uses VOR"],a:1,e:"Critical distinction for navigation: (1) HDG mode: aircraft nose points at the selected magnetic heading — in a crosswind, the aircraft drifts sideways off the intended track. (2) TRK mode: aircraft's GPS ground track matches the selected track — the AFCS automatically applies a wind correction angle to maintain the actual track over ground. TRK is superior for precise navigation; HDG is used when heading (not track) is the ATC instruction.",ref:"Ch.19 §5"},
{q:"What AFCS mode architecture change occurs when flying an ILS approach from intermediate to final approach?",o:["Only LOC is active throughout — GS engages manually on final","LOC mode is typically engaged first for lateral guidance on the intermediate approach. When the aircraft intercepts the ILS glide slope (GS mode arms), GS mode activates upon intercept, engaging both LOC (lateral) and GS (vertical) simultaneously — providing full precision approach coupling. The crew monitors both mode annunciations on the MFD and confirms both are active before the decision height","LOC and GS engage simultaneously at the FAF","GS mode must be manually engaged by pressing the GS button at each step-down fix"],a:1,e:"ILS approach AFCS mode sequence: (1) Intercept heading toward LOC — HDG or TRK, (2) LOC armed → LOC captures on intercept → LOC active, (3) GS armed while established on LOC, (4) GS intercept from below → GS captures → dual-channel precision approach (LOC+GS active), (5) Continue coupled approach monitoring LOC and GS deviations on FND, (6) At DH: pilot makes land or go-around decision.",ref:"Ch.19 §5"}
]
}

]; // end QBANK
